-- Poems batch 206
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('41f59c92-6d74-48d1-bc68-90345614e484','壽史丞相','程公許','宋','宋诗','song-poetry','','[]','君不見唐朝郭元振，退朝愉色奉溫凊。',162,'全唐诗/poet.song.194000.json','["君不見唐朝郭元振，退朝愉色奉溫凊。", "又不見國初王文康，黑頭拜相歸捧觴。", "台衮崇嚴親壽考，歷數古今良亦少。", "而况二老偕耆頤，如二公者那易有。", "四窗爽氣舒雲霞，相業之盛專一家。", "父子弟昆踵科級，到公名業尤榮華。", "蔡州擒吳抑何壯，開幕江淮護諸將。", "手提黄鉞却欃槍，即軍中冊右丞相。", "我乘馳驅亦勞止，衮衣趣覲天顔喜。", "垂紳列弁競趨迎，恩遇之隆昔無比。"]'),
('df605374-8db6-4a6d-8960-6d562f0b11b5','書懷','程公許','宋','宋诗','song-poetry','','[]','字民能使民和悅，儒術信與吏道別。',96,'全唐诗/poet.song.194000.json','["字民能使民和悅，儒術信與吏道別。", "十年妖祲滓太清，有耳厭聽鼙鼓鳴。", "創殘之餘忍椎剝，逃生要不如無生。", "願絜乾綱奠坤軸，罷兵寬賦家給足。", "聖躬示朴吏廉平，歲歲蠶登牛産犢。", "宦情我自春雲薄，何日西歸田舍樂。"]'),
('da5dede6-e129-4439-8e35-f6cbf764908a','送游提刑祕閣赴召三首  其一','程公許','宋','宋诗','song-poetry','','[]','舊聞游監簿，姱節紹熙朝。',48,'全唐诗/poet.song.194000.json','["舊聞游監簿，姱節紹熙朝。", "有子登臺省，危言動冕旒。", "不容求外補，親政復旌招。", "四海澄清志，無寧久使軺。"]'),
('116523db-7941-4a82-a932-518445b28c00','送游提刑祕閣赴召三首  其二','程公許','宋','宋诗','song-poetry','','[]','日馭中天運，冰山失勢多。',48,'全唐诗/poet.song.194000.json','["日馭中天運，冰山失勢多。", "可能羣枉杜，端藉衆賢和。", "公去應前席，人言合上坡。", "調停前轍誤，國事竟如何。"]'),
('6ef1f913-8bd2-4b03-a80d-d731c00ecaac','送游提刑祕閣赴召三首  其三','程公許','宋','宋诗','song-poetry','','[]','外敵日侵伐，滋爲元氣傷。',48,'全唐诗/poet.song.194000.json','["外敵日侵伐，滋爲元氣傷。", "憂心耿不寐，洗耳待封章。", "弱植如羈羽，知音念五羊。", "因書及疏賤，决起尚榆枋。"]'),
('001b6337-6dfa-439c-923a-a5e6c236b7a5','送成都倅黎德升赴召崔侍郎薦士召者五人三首  其一','程公許','宋','宋诗','song-poetry','','[]','憶侍西征幕，叢談夜達晨。',48,'全唐诗/poet.song.194000.json','["憶侍西征幕，叢談夜達晨。", "別來青鬢換，喜見紫泥新。", "宸極拱朝幘，曉星看蜀珍。", "一朝樓五鳳，積憤洗峨岷。"]'),
('4c836ad1-e230-445f-b150-30e1d2eb6f59','送成都倅黎德升赴召崔侍郎薦士召者五人三首  其二','程公許','宋','宋诗','song-poetry','','[]','塵暗朔風急，雨淫晨景昏。',48,'全唐诗/poet.song.194000.json','["塵暗朔風急，雨淫晨景昏。", "憂心長似擣，欲語吐還吞。", "持底舒天步，云何塞亂源。", "熱官餳裏鴆，名節貴璵璠。"]'),
('76f26706-7e8a-4933-ac35-93a637ccf32d','送成都倅黎德升赴召崔侍郎薦士召者五人三首  其三','程公許','宋','宋诗','song-poetry','','[]','已往嗟奚及，方來當若何。',48,'全唐诗/poet.song.194000.json','["已往嗟奚及，方來當若何。", "幸無疏藥石，庶可起沈疴。", "讎僞半盧扁，滌腸須華佗。", "康時付公等，隨分且絃歌。"]'),
('4b7f644a-1ee5-4d23-984e-975765c48ae5','送別魏校書借參預李先生韻  其一','程公許','宋','宋诗','song-poetry','','[]','斯文天未椓，世復有斯人。',48,'全唐诗/poet.song.194000.json','["斯文天未椓，世復有斯人。", "縹帙磨鉛舊，泥封染墨新。", "詞華班馬富，道術魯鄒醇。", "滿腹經綸願，逢時氣益振。"]'),
('eff2fe64-3e34-46e9-9ae7-982f3615fd4b','送別魏校書借參預李先生韻  其二','程公許','宋','宋诗','song-poetry','','[]','雙闕一回首，滯留今十連。',48,'全唐诗/poet.song.194000.json','["雙闕一回首，滯留今十連。", "河圖元國鎮，泗石待宮縣。", "南紀浪翻雪，北風塵暗天。", "經營倚天定，九軌達山川。"]'),
('8931e366-16ad-4e25-b4b8-f5d382f331c9','送別魏校書借參預李先生韻  其三','程公許','宋','宋诗','song-poetry','','[]','搔首暮雲碧，懷人酒淺斟。',48,'全唐诗/poet.song.194000.json','["搔首暮雲碧，懷人酒淺斟。", "萬鍾心不動，九鼎力能任。", "夜雨青綾直，春風紫禁深。", "愛君須引類，一念帝來臨。"]'),
('5ff880ca-0ee4-440c-8d87-721abde498bc','送別長翁制幹赴審察  其一','程公許','宋','宋诗','song-poetry','','[]','戎幕接談笑，薦函聯姓名。',48,'全唐诗/poet.song.194000.json','["戎幕接談笑，薦函聯姓名。", "自憐風退鷁，快見浪翻鯨。", "知己方圖任，聯鑣夐有榮。", "明堂足材具，社櫟復何營。"]'),
('05d52a5b-4a59-4578-9cca-43400b7bec53','送別長翁制幹赴審察  其二','程公許','宋','宋诗','song-poetry','','[]','屯雲開宇宙，八表斂風塵。',48,'全唐诗/poet.song.194000.json','["屯雲開宇宙，八表斂風塵。", "獵德恢天網，充庭詫蜀珍。", "一編元祐學，雙闕武林春。", "赤汗青絲鞚，修途款問津。"]'),
('a2c16a79-4bcf-43f2-8c18-54ac53742d0f','送別長翁制幹赴審察  其三','程公許','宋','宋诗','song-poetry','','[]','機欲審而發，瑟調音自諧。',48,'全唐诗/poet.song.194000.json','["機欲審而發，瑟調音自諧。", "况思萬全計，可畏一毫差。", "回斡須羣彥，輪囷疊寸懷。", "樵漁暫相狎，鴛鷺豈其儕。"]'),
('b0c15d74-9010-483a-bd8f-a99f981f3990','到闕政府以辟郡未下隔對','程公許','宋','宋诗','song-poetry','','[]','練紙密銜袖，宮門報隔班。',48,'全唐诗/poet.song.194000.json','["練紙密銜袖，宮門報隔班。", "衷腸鬰未吐，殿檻可容攀。", "巨用須桴棟，旁搜及蒯菅。", "對揚當有日，傾盡不須刪。"]'),
('79b2c3b6-3cbd-425d-8c83-a41680106d99','和龔彥質韻送別趙稅院','程公許','宋','宋诗','song-poetry','','[]','譏征傍南海，何遽別同盟。',48,'全唐诗/poet.song.194000.json','["譏征傍南海，何遽別同盟。", "漫仕不妨學，能詩新有聲。", "烟濤千里隔，書劍一航輕。", "榘範求諸近，菊坡冰雪清。"]'),
('db0aef94-7d86-41b9-8c97-6e0efa04e7c1','別家仲行得成都尉西歸','程公許','宋','宋诗','song-poetry','','[]','遠役得佳伴，天涯還摻袪。',48,'全唐诗/poet.song.194000.json','["遠役得佳伴，天涯還摻袪。", "憂端今轉甚，漫仕意何如。", "落筆敏無敵，軒髯豪不除。", "市橋春好在，勿共酒杯疏。"]'),
('6c9e83a3-8f98-4fad-8475-43d94492f87e','華陽尉授代喜成二首  其一','程公許','宋','宋诗','song-poetry','','[]','唱第八年久，折腰三考書。',48,'全唐诗/poet.song.194000.json','["唱第八年久，折腰三考書。", "上官容我拙，樸學與時疏。", "冷落隨陽鴈，蹣跚上竹魚。", "平生經世志，窮達豈關渠。"]'),
('1b1abb60-6bc0-4dc4-88a6-2700d9ecd7c0','華陽尉授代喜成二首  其二','程公許','宋','宋诗','song-poetry','','[]','冉冉歲云暮，齊邱促戍忙。',48,'全唐诗/poet.song.194000.json','["冉冉歲云暮，齊邱促戍忙。", "倦憑南郭几，靜寄贊公房。", "夢想蠶絲軟，涎流蟻杓香。", "循陔歸潔養，一笑樂哄堂。"]'),
('3be3c8af-e2c9-4a09-b5a3-f5f75f0d6fb2','用光弟携兒送至南定','程公許','宋','宋诗','song-poetry','','[]','親友遠追送，後先還故鄉。',48,'全唐诗/poet.song.194000.json','["親友遠追送，後先還故鄉。", "殷勤仲光父，嫪戀及江陽。", "執手哽無語，修名那易量。", "歸來訓子姪，椿桂會聯芳。"]'),
('bda8cfdb-b038-4b33-abca-e25532e83243','挾文薛君自賦五首克己讀書安貧擇交訓子爲題戒其子婿王叔儼萬里索和  其一','程公許','宋','宋诗','song-poetry','','[]','爲人非外鑠，己與物同之。',48,'全唐诗/poet.song.194000.json','["爲人非外鑠，己與物同之。", "私欲陰霾蔽，良心日月虧。", "若能無窒礙，底用苦思惟。", "天理渾然處，吾生自有涯。"]'),
('47d6e8b2-b49f-425a-aa86-b91146dcbd28','挾文薛君自賦五首克己讀書安貧擇交訓子爲題戒其子婿王叔儼萬里索和  其二','程公許','宋','宋诗','song-poetry','','[]','靜得山林趣，閒知日月長。',48,'全唐诗/poet.song.194000.json','["靜得山林趣，閒知日月長。", "清風披竹素，小雨潤芸香。", "外飾謝文繡，饑餐須稻粱。", "人生有同嗜，只此絕難忘。"]'),
('6832bea9-e047-4f6c-930b-5049bc5d7457','挾文薛君自賦五首克己讀書安貧擇交訓子爲題戒其子婿王叔儼萬里索和  其三','程公許','宋','宋诗','song-poetry','','[]','賦予有常分，非關智力求。',48,'全唐诗/poet.song.194000.json','["賦予有常分，非關智力求。", "違行能自信，顯晦復何憂。", "瓢飲賢顔子，瓜疇隠邵侯。", "胸中吉祥宅，何處不天游。"]'),
('07c23ddf-97b8-4040-8b12-33731305048e','挾文薛君自賦五首克己讀書安貧擇交訓子爲題戒其子婿王叔儼萬里索和  其四','程公許','宋','宋诗','song-poetry','','[]','士能知尚友，豈必盡同時。',48,'全唐诗/poet.song.194000.json','["士能知尚友，豈必盡同時。", "雜鮑蘭胥化，亡羊路或岐。", "醴甘知易絕，絲素亦奚悲。", "可以交難擇，而忘伐木詩。"]'),
('d0697baf-6621-422e-8b39-6959b01be73c','挾文薛君自賦五首克己讀書安貧擇交訓子爲題戒其子婿王叔儼萬里索和  其五','程公許','宋','宋诗','song-poetry','','[]','萬事烟雲過，須留尾段看。',48,'全唐诗/poet.song.194000.json','["萬事烟雲過，須留尾段看。", "芝蘭庭砌茂，風雨夜燈寒。", "楚澤荷紉綠，燕山桂染丹。", "詩書門戶壯，何待侈重欒。"]'),
('b8b6e1ba-e71e-42d9-901f-0450295b1399','壽李悅齋五首和送三榮使君韻  其一','程公許','宋','宋诗','song-poetry','','[]','南薰諧玉軫，舜殿載賡歌。',48,'全唐诗/poet.song.194000.json','["南薰諧玉軫，舜殿載賡歌。", "天憫蒼生苦，人如安石何。", "無心書咄咄，有術辦多多。", "肯學癯山澤，楸枰詫爛柯。"]'),
('274c8c61-fa5d-4fbc-870d-a6bdf2682cf5','壽李悅齋五首和送三榮使君韻  其二','程公許','宋','宋诗','song-poetry','','[]','宇縣風塵暗，軍需色目繁。',48,'全唐诗/poet.song.194000.json','["宇縣風塵暗，軍需色目繁。", "時機寧我待，心事向誰論。", "羶聚螘爭慕，泉深驥渴奔。", "非公能借箸，猛虱恐徒捫。"]'),
('8e2df247-00e7-4fe0-88d3-757005e48b76','壽李悅齋五首和送三榮使君韻  其三','程公許','宋','宋诗','song-poetry','','[]','國鎮重雙璧，寵光均一時。',48,'全唐诗/poet.song.194000.json','["國鎮重雙璧，寵光均一時。", "姱修甘俗忤，忠憤倚天知。", "聞道徵環急，難忘側席思。", "分明調鼎味，梅熟雨垂垂。"]'),
('8d0bb459-fc6a-4a6a-a747-0c0a2e94d3f8','壽李悅齋五首和送三榮使君韻  其四','程公許','宋','宋诗','song-poetry','','[]','衡泌春無盡，湖天風快哉。',48,'全唐诗/poet.song.194000.json','["衡泌春無盡，湖天風快哉。", "書堂三壽語，仙籍幾生來。", "一髮扶周鼎，千金築隗臺。", "人心索調護，根本更須培。"]'),
('61984b6a-c48c-4197-b58d-44b36b5b2e72','壽李悅齋五首和送三榮使君韻  其五','程公許','宋','宋诗','song-poetry','','[]','磊磊松椿幹，淵淵金石聲。',48,'全唐诗/poet.song.194000.json','["磊磊松椿幹，淵淵金石聲。", "功名寧貰我，富貴本無情。", "陛對三千牘，胸奇百萬兵。", "扶持天意在，容我請長纓。"]'),
('39a85273-2803-4d09-b54c-79a1f198bc0d','送道傳姪旅中赴省','程公許','宋','宋诗','song-poetry','','[]','上國友多士，三年期一鳴。',48,'全唐诗/poet.song.194000.json','["上國友多士，三年期一鳴。", "藝須專必勝，祿逮養爲榮。", "門戶久灰冷，雲霄如砥平。", "五豪同著便，一爲起家聲。"]'),
('c4b31d39-7de3-4ccb-96bb-856342fbba60','參選成都親友追送月夕飲江上','程公許','宋','宋诗','song-poetry','','[]','久聚未知樂，蹔離能許愁。',48,'全唐诗/poet.song.194000.json','["久聚未知樂，蹔離能許愁。", "清江一輪月，後夜兩般秋。", "語倦且呼酒，寒侵頻索裘。", "鼎湖龍去遠，憂憤涕滂流。"]'),
('dda54c37-ce1d-4edd-8f6e-7e56334155f1','留別李貫之大著二首  其一','程公許','宋','宋诗','song-poetry','','[]','車馬紅塵裏，閲人誰似君。',48,'全唐诗/poet.song.194000.json','["車馬紅塵裏，閲人誰似君。", "洚流傾世論，砥柱倚斯文。", "籍甚詩書譽，超然利欲醺。", "相從期歲晚，蘭佩襲芳熏。"]'),
('e4adc5fe-3aac-4402-9940-cf3af170ad17','留別李貫之大著二首  其二','程公許','宋','宋诗','song-poetry','','[]','二老俱黄髮，遥憐望倚門。',48,'全唐诗/poet.song.194000.json','["二老俱黄髮，遥憐望倚門。", "淒涼遊子意，慚愧主人恩。", "酒舫湖光灧，書燈夜雨昏。", "三山渺雲海，何日聽重論。"]'),
('315489cd-5be4-44be-9b0b-7e7b7778f586','楓橋寺侍悅齋先生誨語三日而別','程公許','宋','宋诗','song-poetry','','[]','唐人舊題處，那復有江楓。',48,'全唐诗/poet.song.194000.json','["唐人舊題處，那復有江楓。", "寺近闔閭國，門當岝崿峰。", "清風三宿戀，紫氣一尊同。", "恨與心知別，烟波千萬重。"]'),
('2de811ac-c290-40fc-9c44-d3576b2ea7a0','雨中送客觀魚閣','程公許','宋','宋诗','song-poetry','','[]','送客觀魚閣，山光水色中。',48,'全唐诗/poet.song.194000.json','["送客觀魚閣，山光水色中。", "最憐秋慘澹，况復雨溟濛。", "坐久覺衣薄，杯行到手空。", "恨無佳句子，喚醒少陵翁。"]'),
('f5a813c5-211f-43ea-9ac7-4ac977be1b6f','風雨過南溪','程公許','宋','宋诗','song-poetry','','[]','小艇泝洄穩，短蓬興寢勞。',48,'全唐诗/poet.song.194000.json','["小艇泝洄穩，短蓬興寢勞。", "斷崖榕倒影，亂石水翻濤。", "過雨山如沐，終風晚更饕。", "愁須詩自遣，吟罷轉蕭騷。"]'),
('3bd3ad1b-8668-4038-b8d8-18bd93d52ac0','三江曉渡','程公許','宋','宋诗','song-poetry','','[]','喚渡三江岸，停車兩眼明。',48,'全唐诗/poet.song.194000.json','["喚渡三江岸，停車兩眼明。", "烟涵秋日澹，露洗曉寒輕。", "山色晴逾爽，波流怒未平。", "詩翁舊游處，有句不堪呈。"]'),
('7a6662c3-5f28-43f4-b659-989c25d7b670','陪憲節飯石堂書院渡江游雙泉墅即席和韻','程公許','宋','宋诗','song-poetry','','[]','箯輿杭野渡，竹逕繞平疇。',48,'全唐诗/poet.song.194000.json','["箯輿杭野渡，竹逕繞平疇。", "紅蓼前宵漲，黄花幾日秋。", "談鋒蜚屑玉，巖竇答鳴球。", "山水饒心賞，能忘恤緯憂。"]'),
('20ec3396-9e15-4a98-9db5-1eccb5b2aaa0','仲春八日自成都起程度劍閣','程公許','宋','宋诗','song-poetry','','[]','蕭寺深居穩，春深殊未知。',48,'全唐诗/poet.song.194000.json','["蕭寺深居穩，春深殊未知。", "偶然成遠役，猶幸及芳時。", "麥浪含風軟，花光眩日遲。", "客行無復恨，隨處可尋詩。"]'),
('1f639939-5f3c-4408-ba39-0defc24182b6','秉炬游麻仙玉華洞','程公許','宋','宋诗','song-poetry','','[]','雲峰環翠幄，洞戶閟瓊臺。',48,'全唐诗/poet.song.194000.json','["雲峰環翠幄，洞戶閟瓊臺。", "勝處難名狀，飛仙此往來。", "近應通玉局，遠或接蓬萊。", "安得一伸臂，乘風遍九垓。"]'),
('b2c4a01d-ba44-423c-99d7-2fbb16f2ef28','送劉時可縣丞奉母游岷山','程公許','宋','宋诗','song-poetry','','[]','西爽抗層霄，南牆日見招。',48,'全唐诗/poet.song.194000.json','["西爽抗層霄，南牆日見招。", "乘春扶鶴馭，披霧過龍橋。", "香火祈親壽，烟霞遠俗囂。", "歸來索吟稿，起我意逍遥。"]'),
('e36fb4ec-69b9-42b9-a6a8-713fdebb8aa8','過中巖渡月出峨眉山上','程公許','宋','宋诗','song-poetry','','[]','返照中巖渡，峨眉分外清。',48,'全唐诗/poet.song.194000.json','["返照中巖渡，峨眉分外清。", "一彎新吐月，共我兩忘形。", "露下沙逾白，宵寒酒易醒。", "荻花風索索，擁被不堪聽。"]'),
('120b8380-73bd-49fa-a05c-76e2d4194d9b','山中戲雲端子','程公許','宋','宋诗','song-poetry','','[]','追路歸山後，開關喚客眠。',48,'全唐诗/poet.song.194000.json','["追路歸山後，開關喚客眠。", "那知言在耳，已作醉逃禪。", "急雪濃篩瓦，中宵冷透氈。", "清愁分不盡，惜別意淒然。"]'),
('0ec0811c-1e8b-4d75-8898-bd8c0cdc8a67','題丹景山','程公許','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','原廟標丹景，神游想岱宗。',48,'全唐诗/poet.song.194000.json','["原廟標丹景，神游想岱宗。", "寶龕嚴石像，紺殿鎖雲峰。", "浪說侵疆復，何當檢玉封。", "天門東北望，漠漠曉烟濃。"]'),
('43e30116-1e3a-476f-8a9f-22e6095c40be','題信州半月巖','程公許','宋','宋诗','song-poetry','','[]','巖際半輪月，神工幻怪奇。',48,'全唐诗/poet.song.194000.json','["巖際半輪月，神工幻怪奇。", "本來無顯晦，何自有盈虧。", "嵐霧凝蟾彩，藤蘿影桂枝。", "能令萬里客，爲爾憶峨眉。"]'),
('5d9ebe41-9a15-4842-940e-8e5354e9ee01','炷香至德山','程公許','宋','宋诗','song-poetry','','[]','異時聞至德，滴水洗沈冤。',48,'全唐诗/poet.song.194000.json','["異時聞至德，滴水洗沈冤。", "空寂等三世，悟迷同一源。", "松杉膏宿雨，樓閣麗朝暾。", "猶恨高峰頂，藤蘿未得捫。"]'),
('97195805-4a61-486e-a41c-4939c8995970','自船莊過化城留宿翌旦炷香宣石橋卯塔','程公許','宋','宋诗','song-poetry','','[]','路欲轉前嶺，僧邀宿化城。',51,'全唐诗/poet.song.194000.json','["路欲轉前嶺，僧邀宿化城。", "飯抄青{飠卂}軟，茶瀹乳花輕。", "嵐雨侵衣潤，松風入夜清。", "瓣香宣老塔，坐待日華生。"]'),
('196baa31-2e98-4299-8eb9-ac12a3dc5b00','侍飲寶子山遊忠武侯祠','程公許','宋','宋诗','song-poetry','','[]','一郡最高處，元戎領客遊。',48,'全唐诗/poet.song.194000.json','["一郡最高處，元戎領客遊。", "雲根棲萬井，城角带雙流。", "日薄樓臺暝，風悲鼓角秋。", "卧龍千古恨，烟靄隔神州。"]'),
('9919c69e-f37a-4f9a-b539-28a07bcec7d3','題馬溪寺二首  其一','程公許','宋','宋诗','song-poetry','','[]','久客愁多雨，清遊喜驟晴。',48,'全唐诗/poet.song.194000.json','["久客愁多雨，清遊喜驟晴。", "雲藍猶獨踞，玉嶺忽雙撐。", "洞口龍方卧，山腰虎尚獰。", "方池竟何在，一水至今清。"]'),
('0b6d1a5d-2666-4ee8-a936-1dea1bbb8db9','題馬溪寺二首  其二','程公許','宋','宋诗','song-poetry','','[]','先子舊遊此，余時方五齡。',48,'全唐诗/poet.song.194000.json','["先子舊遊此，余時方五齡。", "風神見圖像，雲體想儀刑。", "衰髮年年白，遥山面面青。", "不須論舊事，欲說喚誰聽。"]'),
('eed5c0ba-a499-4b27-a5a6-0a82394fd3bb','留題馬溪寺二首即用前韻  其一','程公許','宋','宋诗','song-poetry','','[]','玉筍競秋爽，翠屏張曉晴。',48,'全唐诗/poet.song.194000.json','["玉筍競秋爽，翠屏張曉晴。", "天開金地勝，鼎峙紫霄撐。", "見說禪心靜，能調異物獰。", "十方薌水海，何處不澄清。"]'),
('b0832f04-620c-492d-b754-d840ca59c1bf','留題馬溪寺二首即用前韻  其二','程公許','宋','宋诗','song-poetry','','[]','翠珉瞻手澤，六十有餘齡。',48,'全唐诗/poet.song.194000.json','["翠珉瞻手澤，六十有餘齡。", "囊錦傳宗旨，錐沙更典刑。", "髮緣憂世白，眼獨爲山青。", "蕙帳摇歸夢，秋猿正可聽。"]'),
('978f40b6-025f-4dcc-a467-3fcd2ad86f35','香積寺午齋','程公許','宋','宋诗','song-poetry','','[]','峻陟龍門路，來參雞骨師。',48,'全唐诗/poet.song.194000.json','["峻陟龍門路，來參雞骨師。", "樓臺春雨霽，魚鼓午齋時。", "倦憩僧留話，荒尋僕憚隨。", "一筇支野步，且以暮爲期。"]'),
('0f4eb1ef-3b17-42c2-85de-a602f3c21965','挽桃源使君虞公二首  其一','程公許','宋','宋诗','song-poetry','','[]','疇昔交諸季，曾聞說長公。',48,'全唐诗/poet.song.194000.json','["疇昔交諸季，曾聞說長公。", "聖涯探窔奧，詞藻亦精工。", "偶幸趨徵詔，方當順下風。", "飈斿無處問，延佇鬢飛蓬。"]'),
('66714c87-99be-4e12-abc0-a58d51335788','挽桃源使君虞公二首  其二','程公許','宋','宋诗','song-poetry','','[]','解印桃源後，卜居梅溆幽。',48,'全唐诗/poet.song.194000.json','["解印桃源後，卜居梅溆幽。", "秉心難偶俗，樂道自忘憂。", "故國八千里，妖氛六十州。", "公魂如不泯，時作玉芝游。"]'),
('26e4b83c-5394-422f-97c2-05652b480c7c','挽前眉州使君廖子長二首  其一','程公許','宋','宋诗','song-poetry','','[]','二老金蘭好，諸昆筆硯交。',48,'全唐诗/poet.song.194000.json','["二老金蘭好，諸昆筆硯交。", "坐隅親問字，投分漆如膠。", "决眥雲間步，驚心水上泡。", "屋梁耿殘月，含涕祖西郊。"]'),
('1553a129-a5ce-44c7-b519-1b1df15f8625','挽前眉州使君廖子長二首  其二','程公許','宋','宋诗','song-poetry','','[]','卧羆花石戍，夢蝶古渝津。',48,'全唐诗/poet.song.194000.json','["卧羆花石戍，夢蝶古渝津。", "秀子嗣榮祿，諸郎皆聘珍。", "笄珈陪墓窆，霧雨暗車塵。", "今代誰班范，牽連漢傳循。"]'),
('29eae292-d430-4bbf-9cbc-6ad4dec04e07','挽永康守成寺簿同年二首  其一','程公許','宋','宋诗','song-poetry','','[]','模楷親前哲，丰姿自軼羣。',48,'全唐诗/poet.song.194000.json','["模楷親前哲，丰姿自軼羣。", "回翔垂白髮，凌厲即青雲。", "幕府列功簿，詩書清塞氛。", "寶仙催命駕，拱木漫新墳。"]'),
('2c95e574-2bfd-4347-a7b8-e448241c9f32','挽永康守成寺簿同年二首  其二','程公許','宋','宋诗','song-poetry','','[]','友愛根天性，今人古與俱。',48,'全唐诗/poet.song.194000.json','["友愛根天性，今人古與俱。", "棣華雖殄瘁，玉樹更扶疏。", "經濟終齎恨，循良誰讀書。", "慈恩共心賞，霜月淚霑裾。"]'),
('cf833b81-4640-492e-aebc-39623736812b','挽潼帥許侍郎成子三首  其一','程公許','宋','宋诗','song-poetry','','[]','天地英靈氣，風雲感會期。',48,'全唐诗/poet.song.194000.json','["天地英靈氣，風雲感會期。", "龍頭推蜀産，骨鯁自天知。", "雨露榮三接，江湖滯一麾。", "甲兵何日洗，遠慮憶蓍龜。"]'),
('cb2d5ee2-20cf-434e-9477-dcbc03b2908a','挽潼帥許侍郎成子三首  其二','程公許','宋','宋诗','song-poetry','','[]','正色趨文石，危言竦列紳。',48,'全唐诗/poet.song.194000.json','["正色趨文石，危言竦列紳。", "直前香案曉，批敕瑣闈春。", "天要明堂柱，人間匠石斤。", "汲公寧妄發，軒冕付平津。"]'),
('43d2dec1-8cfe-4657-8e60-a156803a58f8','挽潼帥許侍郎成子三首  其三','程公許','宋','宋诗','song-poetry','','[]','雪慘龍沙節，春濃豹尾班。',48,'全唐诗/poet.song.194000.json','["雪慘龍沙節，春濃豹尾班。", "難銷方寸赤，不待二毛斑。", "力盡三醫謁，憂深九虎攀。", "丁寧尸諫語，端不愧家山。"]'),
('68500868-3cf1-4ef4-ae0e-db4c01b0c537','元正書懷','程公許','宋','宋诗','song-poetry','','[]','甲子循環六十年，手披新歷意茫然。',64,'全唐诗/poet.song.194000.json','["甲子循環六十年，手披新歷意茫然。", "了知自性覺玄妙，寧與世間寒暑遷。", "寡過得如蘧瑗化，諾惺要了瑞巖禪。", "故園未卜西歸日，遇好溪山且數椽。"]'),
('4e270c14-f326-40d7-9819-755b9aefe1dd','立春','程公許','宋','宋诗','song-poetry','','[]','月墮霜空發上亭，土牛今日却鞭春。',64,'全唐诗/poet.song.194000.json','["月墮霜空發上亭，土牛今日却鞭春。", "六花度臘慳呈瑞，二麥何時飽食新。", "四序斡旋均一氣，萬殊元化託洪鈞。", "已煩元帥調新律，早願三邊靜戰塵。"]'),
('d18c7f1a-b0f4-4588-a60a-ba18e95e2009','正月二十日雪','程公許','宋','宋诗','song-poetry','','[]','東皇弭節未多時，忽作漫空六出飛。',64,'全唐诗/poet.song.194000.json','["東皇弭節未多時，忽作漫空六出飛。", "商略田功興嗣歲，翕張天巧惜陰機。", "麥才覆土欣蘇醒，梅久烘晴稍發揮。", "蕭寺掩關終日卧，忍寒不著獸紅圍。"]'),
('f816a9aa-f09b-4eba-88b7-c02385233179','正月念三日以南床劾論去國憩浄慈客館蘇稅院惠二詩和韻  其一','程公許','宋','宋诗','song-poetry','','[]','意不求全那得毀，本來知足豈須多。',64,'全唐诗/poet.song.194000.json','["意不求全那得毀，本來知足豈須多。", "世途何處非乘險，古井如今已不波。", "緣督更須師漆吏，乞墦可使愧鄒軻。", "君看野馬難羈束，寧羨天街想玉珂。"]'),
('5f035893-cb6e-4025-b3a3-7326a31857a1','正月念三日以南床劾論去國憩浄慈客館蘇稅院惠二詩和韻  其二','程公許','宋','宋诗','song-poetry','','[]','寄包古剎客過門，煨芋殘爐晚未溫。',64,'全唐诗/poet.song.194000.json','["寄包古剎客過門，煨芋殘爐晚未溫。", "萬里風塵迷遠望，三峰文獻接諸孫。", "湖山春動饒佳趣，杖履時來共至言。", "一笑老仙堤柳畔，人間誰怨復誰恩。"]'),
('543ee8b6-f90c-4ce1-91d7-65ff265e9b78','仲春再雪與禪衲夜話','程公許','宋','宋诗','song-poetry','','[]','蓬萊不肯著癡仙，放去湖山一任顛。',64,'全唐诗/poet.song.194000.json','["蓬萊不肯著癡仙，放去湖山一任顛。", "術不競時甘斂退，僧知同趣喜留連。", "春深半地雪盈尺，雲破遥林月一弦。", "撥盡灰寒吟未穩，不如欹枕愜昏眠。"]'),
('ee5ca011-17bd-4e81-8959-0f1d7daff165','寒食','程公許','宋','宋诗','song-poetry','','[]','賣餳簫咽紙鳶飛，愁思驚隨節物來。',64,'全唐诗/poet.song.194000.json','["賣餳簫咽紙鳶飛，愁思驚隨節物來。", "誓墓可能同逸少，操音誰復憫鍾儀。", "松楸此日空瞻望，桃李當年奉宴嬉。", "投老與公同一恨，淒風撩亂我心哀。"]'),
('6066eba3-6d9b-4a09-b359-6f0d4af74ad1','清明日郡圃遊觀者如織余以趙園之約至夕乃還若水賦詩後四日偶因小疾謁告清坐始得奉答','程公許','宋','宋诗','song-poetry','','[]','老怯尊前倒玉山，清晨有約夕曛還。',64,'全唐诗/poet.song.194000.json','["老怯尊前倒玉山，清晨有約夕曛還。", "似知是日笙簫沸，趁賞羣芳綺纈班。", "細閲餘妍能幾許，喜因小疾得端閒。", "持觴不釂春應笑，若欠題詩亦厚顔。"]'),
('7d81a09f-ba8e-4ae1-9853-9201e37bb71a','三衢道士鄭自得即天慶寮舍種梅疏池爲小亭扁曰橫清有詔住南岳道觀復以此扁其亭解官事言歸袖詩相訪爲次韻','程公許','宋','宋诗','song-poetry','','[]','高人久已悟空花，養就丹田日月華。',64,'全唐诗/poet.song.194000.json','["高人久已悟空花，養就丹田日月華。", "方丈有誰來晤語，橫枝相對慮無邪。", "雲開衡岳重回首，雪滿柯山遲到家。", "乞得歸閒來叩戶，摘將青子薦流霞。"]'),
('e5c4d6ac-8880-4a2b-a194-bf3708073863','和虞使君賦山茶花二首  其一','程公許','宋','宋诗','song-poetry','','[]','眼明絕艷照凋年，傲雪凌霜分外妍。',64,'全唐诗/poet.song.194000.json','["眼明絕艷照凋年，傲雪凌霜分外妍。", "鶴頂染砂那得似，犀棱削角自蒼然。", "若爲白瑞三冬裏，獨抱丹心一節堅。", "歲晚須公與商略，儘渠春晝萬紅嫣。"]'),
('a7d7c04b-18c0-47f2-8975-2cfddfd3723e','和虞使君賦山茶花二首  其二','程公許','宋','宋诗','song-poetry','','[]','梅花蘸影碧江潯，似怪高人金玉音。',64,'全唐诗/poet.song.194000.json','["梅花蘸影碧江潯，似怪高人金玉音。", "詠絮可憐清寡伴，冠霞來與共論心。", "定知句迫瓊瑶響，莫惜杯浮琥珀深。", "姑射清寒西子醉，一時嫵媚索高吟。"]'),
('fb4a037b-fb13-4a76-824b-5cf2d70e28e0','道傳山丹一本兩花舉以見遺夜窗翻書偶見劉潛夫嘗賦云偶然避雨過民舍一本山丹恰盛開種久樹身樛似蓋澆頻花面大如杯怪疑朱草非時出驚問紅雲甚處來可惜書生無事力千金移入畫欄栽因借韻同賦一首','程公許','宋','宋诗','song-poetry','','[]','種類山茶花較大，一根恰有兩枝開。',64,'全唐诗/poet.song.194000.json','["種類山茶花較大，一根恰有兩枝開。", "鉛砂煉熟大還鼎，琥珀琢成雙勸杯。", "威鳳想從丹穴下，飛仙近自赤城來。", "便船惟會加培養，寄伴階庭芍藥栽。"]'),
('857f9fff-1b1d-414f-b9a4-71066bec0433','仲秋池塘荷蓋方密有四五朵花','程公許','宋','宋诗','song-poetry','','[]','公暇羽衣憑水檻，漸多翠蓋倚紅粧。',64,'全唐诗/poet.song.194000.json','["公暇羽衣憑水檻，漸多翠蓋倚紅粧。", "想應三伏怯袢熱，待到仲秋吐艷香。", "藻澗魚跳晴景眩，樹陰蟬嘒晚風凉。", "意行偶與欣佳會，門外催科正自忙。"]'),
('0eff664c-23c2-4d8d-820e-834cd103d31b','擬玉谿體賦醴泉墅海棠二首  其一','程公許','宋','宋诗','song-poetry','','[]','東皇張飲錦周遭，華艷偏宜望處高。',64,'全唐诗/poet.song.194000.json','["東皇張飲錦周遭，華艷偏宜望處高。", "結綺樓深迷玉樹，銷金帳暖醉羊羔。", "先驅瑞節眩穠李，近侍舞衫環蒨桃。", "乞得巫雲來芘護，蜚廉作橫未應饕。"]'),
('e675859c-6c8b-4293-a06d-9fc8c81cbf7d','擬玉谿體賦醴泉墅海棠二首  其二','程公許','宋','宋诗','song-poetry','','[]','濯錦波光繞百遭，夜寒秉燭更須高。',64,'全唐诗/poet.song.194000.json','["濯錦波光繞百遭，夜寒秉燭更須高。", "恨無麗藻供摛翰，聊復重裘索俊羔。", "長笑董仙癡守杏，可憐曼倩坐偷桃。", "若教入侍紅雲殿，應悔從前俗慮饕。"]'),
('34ea44d1-17e3-4665-941d-3ac89012ebd5','昌元郡圃看海棠紅苞爛然未有開者問訊以詩','程公許','宋','宋诗','song-poetry','','[]','畫本爭如覿面奇，含苞香露已霏霏。',64,'全唐诗/poet.song.194000.json','["畫本爭如覿面奇，含苞香露已霏霏。", "阿嬌早合貯金屋，南子似羞褰錦帷。", "花信定因寒較晚，賞心何事巧相違。", "壁題恨欠江城句，綵筆誰能爲發揮。"]'),
('ef98600c-68d4-457d-a3b3-784a9f8e7773','崇女擷菜煮羹','程公許','宋','宋诗','song-poetry','','[]','穉女春間繞舍嬉，手挑野菜滿籃歸。',64,'全唐诗/poet.song.194000.json','["穉女春間繞舍嬉，手挑野菜滿籃歸。", "細𣂏碧澗和根煮，旋掬香粳芼糝稀。", "久識道腴知雋永，更從禪悅悟精微。", "投床忽作還鄉夢，雪暖西山筍蕨肥。"]'),
('06a3706b-d520-47e6-8f71-4dc4f69fddf5','督堰至岷下借館南浦張叔全家臨別惠以潤石香几一峰挺拔于白雲杳靄間殊有遠意小詩謝之','程公許','宋','宋诗','song-poetry','','[]','飛幰輕輿御暖風，款門何事日憧憧。',64,'全唐诗/poet.song.194000.json','["飛幰輕輿御暖風，款門何事日憧憧。", "芳榮滿檻丹青麗，穠秀當軒紫翠重。", "石几拜嘉才徑尺，雲天無際挺孤峰。", "更煩指似麻壇路，萬壑千巖借一筇。"]'),
('9c64d025-8976-41df-99ef-cc38f6e5300d','同家德清侍尚書楊寶學山行先過上巖訪家諧季','程公許','宋','宋诗','song-poetry','','[]','鶴書杳杳上巖雲，錦里安車忽暮曛。',64,'全唐诗/poet.song.194000.json','["鶴書杳杳上巖雲，錦里安車忽暮曛。", "二陸久當爲世瑞，一夔留與護香芸。", "中春澗壑晴如暝，亭午松蘿氣自薰。", "倚檻欲歌招隠賦，客塵痼我不成文。"]'),
('bb1834e6-f030-409a-9976-94f62e03581c','北新橋借孫氏宅內有井甘寒又有柳陰度夏爲宜','程公許','宋','宋诗','song-poetry','','[]','幸有安居暫寄包，拙如鳩不費營巢。',64,'全唐诗/poet.song.194000.json','["幸有安居暫寄包，拙如鳩不費營巢。", "日長有井供茶課，客至移床蔭樹梢。", "無事莫將吟思攪，儘閒且把舊書抄。", "心知守道惟玄默，不用援毫賦解嘲。"]'),
('96fd65c1-3a6b-408a-889c-001fa93928f5','樊丈子思以予兄弟三年端居招飲山房爲破愁寂賦詩以謝','程公許','宋','宋诗','song-poetry','','[]','銜恤三年意緒凋，嘉招爲我破無憀。',64,'全唐诗/poet.song.194000.json','["銜恤三年意緒凋，嘉招爲我破無憀。", "露秋爽借談鋒利，霜月寒侵酒力消。", "心事寂無機事擾，詩情何似道情饒。", "平生我亦輕簪紱，安得長年共一瓢。"]'),
('d729ce93-4031-4eb2-a346-4793a335c1d2','再賦','程公許','宋','宋诗','song-poetry','','[]','物華過眼半黄凋，萬竅號風夜慄憀。',64,'全唐诗/poet.song.194000.json','["物華過眼半黄凋，萬竅號風夜慄憀。", "一寸古心難石轉，三生妄念易冰消。", "鉛黄汗筆千年夢，白黑文枰幾路饒。", "勘破古今無一事，省煩更好去風瓢。"]'),
('649210e5-9fd4-4556-9f49-4216360065d7','借東溪巷錢莊寓居','程公許','宋','宋诗','song-poetry','','[]','蕩蕩青天隔九門，携孥飄泊此江村。',64,'全唐诗/poet.song.194000.json','["蕩蕩青天隔九門，携孥飄泊此江村。", "漁蓑且當青綾被，賜酒何如老瓦盆。", "萬軸書籤須細閲，九還火候要重溫。", "少陵有句須參透，政藉幽居拙養尊。"]'),
('f1bc7f69-cc3f-450b-b8ba-700af48f6efb','同振之德久分韻賦坐石東坡得坡字','程公許','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千年間氣落岷峨，驚世聲名鎮不磨。',64,'全唐诗/poet.song.194000.json','["千年間氣落岷峨，驚世聲名鎮不磨。", "吟詠西湖雖有案，經年儋耳却無波。", "細看據石橫藜坐，想見騎龍跨海過。", "山谷老人猶剩語，是非元不到東坡。"]'),
('2ee6aaa2-3623-429d-ad01-31ee5e5278ec','移住西門之溪上','程公許','宋','宋诗','song-poetry','','[]','罷官來就湖州住，爲愛雙流貫一城。',64,'全唐诗/poet.song.194000.json','["罷官來就湖州住，爲愛雙流貫一城。", "僦屋本非嫌僻靜，開窗正要納空明。", "魚蝦幸可隨宜買，饘粥何妨逐漸營。", "况有雙梅供索笑，昭琴底處有虧成。"]'),
('5330c488-208f-4c16-9ccd-eeb297782dc9','雨晴後同兄姪遊開元寺一覽亭飲道傅書院  其一','程公許','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','勝賞幾爲雨罷休，霽光俄湧屋山頭。',64,'全唐诗/poet.song.194000.json','["勝賞幾爲雨罷休，霽光俄湧屋山頭。", "松根烟暖留飛屐，蓼岸波寒緩泝舟。", "霧斂長江青眼對，雪消遠岫翠眉浮。", "郊原浩蕩春無價，漫索枯腸唱且酬。"]'),
('58708e37-2884-4706-a6e7-ca9306e2955b','雨晴後同兄姪遊開元寺一覽亭飲道傅書院  其二','程公許','宋','宋诗','song-poetry','','[]','山色撩人共一杯，夜堂淺酌不須催。',64,'全唐诗/poet.song.194000.json','["山色撩人共一杯，夜堂淺酌不須催。", "醉吟兀兀驚頹玉，睡思齁齁易轉雷。", "蠟炬烘殘三寸焰，水流潤浥一爐灰。", "西游歸趁桃紅暖，相約清尊陸續開。"]'),
('9b4910e9-bb7b-46c9-bb22-2ac94dbf4691','三高亭二首  其一','程公許','宋','宋诗','song-poetry','','[]','一棹松江朔雪饕，椒漿曾此酹三高。',64,'全唐诗/poet.song.194000.json','["一棹松江朔雪饕，椒漿曾此酹三高。", "遠遊借與薰風便，偉觀還如昔日遭。", "喚起玉龍噓霧雨，饒教綵蜺戰雲濤。", "平生最愛登高賦，盍爲豐碑續擬騷。"]'),
('666b04f6-a0a2-4b7e-a050-3cf1e05c0bae','三高亭二首  其二','程公許','宋','宋诗','song-poetry','','[]','水仙要我小遲留，探借五湖風雨秋。',64,'全唐诗/poet.song.194000.json','["水仙要我小遲留，探借五湖風雨秋。", "三萬頃波融一鑑，八千里客只孤舟。", "望迷漁荻荒寒境，思挾琴高汗漫游。", "模寫自知才未稱，天隨有集更精搜。"]'),
('4e10ea26-8696-4b5f-ace3-e1e6dcd5d4d2','避暑鏘璆亭','程公許','宋','宋诗','song-poetry','','[]','老怯新秋暑鬰蒸，晚風水檻一披襟。',64,'全唐诗/poet.song.194000.json','["老怯新秋暑鬰蒸，晚風水檻一披襟。", "試教通閘喧雷鼓，何似穿崖響玉琴。", "默坐自能醒渴夢，微吟時與和清音。", "專城大似專丘壑，不待山行記蔚深。"]'),
('619ca192-0ef2-4b30-920a-13cd98a8dde2','重陽後一日陪憲節登清音亭飲見易亭即席和韻','程公許','宋','宋诗','song-poetry','','[]','一封諫疏徹銀臺，感憤題詩醉墨堆。',64,'全唐诗/poet.song.194000.json','["一封諫疏徹銀臺，感憤題詩醉墨堆。", "喚醒菊邊秋寂寞，爛游松下逕縈回。", "參軍逸韻頻欹帽，詩老多情不放杯。", "勝日追隨容湛輩，從容歸騎不須催。"]'),
('a73c2167-86fa-4505-b40c-77329410ceb6','煇父道父携酒相伴飲飛赴寺四望亭','程公許','宋','宋诗','song-poetry','','[]','四望奇觀廣莫同，瘦藤拄入畫圖中。',64,'全唐诗/poet.song.194000.json','["四望奇觀廣莫同，瘦藤拄入畫圖中。", "晴烟杳靄景無盡，醉眼糢糊鳶墮空。", "邑蕞也曾基相業，井眢誰復現神通。", "漫勞二妙相追逐，勝處宜搜未易工。"]'),
('04b64614-e893-49da-abe6-44ac04fc0b8b','移居北新橋彥質惠詩和答  其一','程公許','宋','宋诗','song-poetry','','[]','束書欲去意遲遲，從此寧無一會期。',64,'全唐诗/poet.song.194000.json','["束書欲去意遲遲，從此寧無一會期。", "客路相逢如宿契，人生難得是閒時。", "虛廊過午陪行食，浄院中宵共說詩。", "此樂何時仍共賞，底須簪佩侍彤墀。"]'),
('6a3e1629-e3d8-4809-b435-3538a1d7f7cc','移居北新橋彥質惠詩和答  其二','程公許','宋','宋诗','song-poetry','','[]','繡段輕投報苦遲，隔關那復共襟期。',64,'全唐诗/poet.song.194000.json','["繡段輕投報苦遲，隔關那復共襟期。", "艱虞敢自求安宅，懶慢欣知不入時。", "王粲登樓初有賦，杜陵屏跡可無詩。", "邊聲又逐秋風勁，誰有良籌動玉墀。"]'),
('793e8267-7459-46cd-847d-90e7169ff56c','計煇父訪予上皇山中拉歸龍溪款話一夕和前韻相贈仍爲賡賦','程公許','宋','宋诗','song-poetry','','[]','憶曾款竹憩神輿，賡賦傳抄倦小胥。',64,'全唐诗/poet.song.194000.json','["憶曾款竹憩神輿，賡賦傳抄倦小胥。", "偶復緣雲尋勝踐，忽驚響屐慰逃虛。", "卜鄰也擬營環堵，飽飯何當共趁墟。", "浮世升沈何足計，得如一室靜翻書。"]'),
('726beffa-00a6-4b0d-8118-e9e58dbfe293','子春再約避暑和樊子思韻','程公許','宋','宋诗','song-poetry','','[]','憂端引起鬢絲長，喜報梁州復故疆。',64,'全唐诗/poet.song.194000.json','["憂端引起鬢絲長，喜報梁州復故疆。", "相約楊園舒野步，頻呼竹葉沃剛腸。", "颼颼翠篠風生檻，灧灧紅蕖水滿塘。", "剩殖芳榮好看客，春風勿吝費除堂。"]'),
('70250a51-2b23-4c89-897e-ebbbafa13ff9','張伯修令君賦詩同韻稱慶','程公許','宋','宋诗','song-poetry','','[]','玉節何如素節高，歸來喜氣溢東臯。',64,'全唐诗/poet.song.194000.json','["玉節何如素節高，歸來喜氣溢東臯。", "存耕元自有餘地，嘉植何曾生不毛。", "采石勳名須世濟，陵陽今昔幾人豪。", "含飴一笑春無價，授簡梁園可憚勞。"]'),
('88d1ab75-a9bd-40fa-b56c-4705efd3bb2d','七曲和魏校書韻','程公許','宋','宋诗','song-poetry','','[]','神理之公參造化，簡書千古豈虛傳。',64,'全唐诗/poet.song.194000.json','["神理之公參造化，簡書千古豈虛傳。", "權衡無意物輕重，水鏡何心人醜妍。", "天爵一身元不欠，人生萬事且隨緣。", "椒漿跪奠無餘禱，擬續離騷愧斐然。"]'),
('2398a8d9-afee-49ae-bb3c-fa1ac0777c9d','揆初之日承父用晦以余前歲登玉華樓翫月借宋青山詩韻賦詩稱壽仍和答之并示甥姪','程公許','宋','宋诗','song-poetry','','[]','防意由來似守城，澗潢潔祀及良辰。',64,'全唐诗/poet.song.194000.json','["防意由來似守城，澗潢潔祀及良辰。", "命名猶念記閭史，學道粗知存谷神。", "欲誦蓼莪心楚愴，愧投木李句清新。", "何當共覓長生訣，去逐商顔四老人。"]'),
('a501cc08-6605-4f7b-a0b8-cdd29d74d118','和答括蒼龔彥質','程公許','宋','宋诗','song-poetry','','[]','不慣參禪不學仙，不婚不宦忽華顛。',64,'全唐诗/poet.song.194000.json','["不慣參禪不學仙，不婚不宦忽華顛。", "前身疑是林和靖，好句多於謝惠連。", "投贈頗堪華錦繡，擇交當勝佩韋弦。", "鷄蟲得失何時了，洗耳松風共醉眠。"]'),
('4d535952-2beb-4cf9-a586-ae189fb789de','和樓大參韻贊史伯謙少弼二同年掛冠  其一','程公許','宋','宋诗','song-poetry','','[]','俚耳驚聞古曲彈，地行元不慕仙官。',64,'全唐诗/poet.song.194000.json','["俚耳驚聞古曲彈，地行元不慕仙官。", "方看鳳穴將雛上，已悟羊腸涉世難。", "蟻夢未酣誰喚醒，鱼遊自樂與誰觀。", "不妨散策三巖路，聽徹松風度百灘。"]'),
('212680d1-d139-4f2c-9886-1f4ddc7c475b','和樓大參韻贊史伯謙少弼二同年掛冠  其二','程公許','宋','宋诗','song-poetry','','[]','琴自無絃不用彈，歲寒姱節傲蒼官。',64,'全唐诗/poet.song.194000.json','["琴自無絃不用彈，歲寒姱節傲蒼官。", "青衫吏隠非吾願，綵服兒啼畏色難。", "三徑歸尋元約在，萬緣回向自心觀。", "何時款竹雲莊去，洗耳香山八節灘。"]'),
('724c4e23-9cf0-4d91-82f4-585ac51b1cfe','小詩謝霅川使君幫祠庭薄俸','程公許','宋','宋诗','song-poetry','','[]','地行不必羨飛仙，驤首青雲恐疾顛。',64,'全唐诗/poet.song.194000.json','["地行不必羨飛仙，驤首青雲恐疾顛。", "但得一廛耕谷口，底須萬騎戰祁連。", "齋房盡日清如水，吾道從來直似絃。", "頼有故人供祿米，飽餐贏得枕書眠。"]'),
('595cda08-67b4-401a-a073-d9cba326a912','正旦上壽紫宸微臣以祀太一初獻不預賜茶酒退就殿門少歇俟追班拜正旦賀表','程公許','宋','宋诗','song-poetry','','[]','去歲楓橋度歲除，寒燈一盞自抄書。',64,'全唐诗/poet.song.194000.json','["去歲楓橋度歲除，寒燈一盞自抄書。", "誰知東觀歸繙史，仍許西垣綴佩琚。", "四闢不憂獰虎豹，九成猶恐眩鶢鶋。", "彤墀百拜陳金鑑，只願中興似國初。"]'),
('a1685688-e040-414c-9c6b-71da617c2099','元日即事四首  其一','程公許','宋','宋诗','song-poetry','','[]','鳳銜丹詔紀初元，餘恨難忘杞國天。',64,'全唐诗/poet.song.194000.json','["鳳銜丹詔紀初元，餘恨難忘杞國天。", "賢路會當三接晝，宅家可卜中興年。", "出車未可忘多難，覃耜尤須祝大田。", "千古逃吳稱至德，有周篤慶更綿延。"]'),
('6116d983-16ea-4286-80b8-9632f285fd37','元日即事四首  其二','程公許','宋','宋诗','song-poetry','','[]','端居俄換歲華三，荼苦於吾若薺甘。',64,'全唐诗/poet.song.194000.json','["端居俄換歲華三，荼苦於吾若薺甘。", "照影菱花驚雪白，强顔柏葉借春酣。", "人間擾擾多岐路，聖世悠悠欠指南。", "一穟黄雲晴晝永，叩門誰辨與同參。"]'),
('960d141d-e283-423d-9815-de9149111977','元日即事四首  其三','程公許','宋','宋诗','song-poetry','','[]','憧憧行李不曾休，消遣年華古渡頭。',64,'全唐诗/poet.song.194000.json','["憧憧行李不曾休，消遣年華古渡頭。", "得似青衿專挾冊，浪隨黄帽熟操舟。", "歸裝趁得椒花頌，洗盞連呼柏葉浮。", "容易一年春又換，賞心可欠七年酬。"]'),
('a00eaafb-151e-40e5-aa47-52e00874f714','元日即事四首  其四','程公許','宋','宋诗','song-poetry','','[]','屠蘇最後釂銀杯，歲月侵尋老景催。',64,'全唐诗/poet.song.194000.json','["屠蘇最後釂銀杯，歲月侵尋老景催。", "離坎新工幾銖火，乾坤生意一聲雷。", "君親未報鬢驚雪，名業倘來心欲灰。", "一笑山頭冰萬仞，曉晴還見翠屏開。"]'),
('7118d667-5cb8-47eb-b8c2-fa55fef3b8c0','元正和洪司令紀事二首  其一','程公許','宋','宋诗','song-poetry','','[]','寸心炯炯水朝東，雲繞通明一朶紅。',64,'全唐诗/poet.song.194000.json','["寸心炯炯水朝東，雲繞通明一朶紅。", "螭籀薦祥天眷顧，鷄竿銜赦日沖融。", "遥知萬國趨堯彩，可使前旒隔舜瞳。", "京闕陵園須汛掃，聖心原不慕邊功。"]'),
('10889fc1-1f29-4a24-b9c7-986352b7c87d','元正和洪司令紀事二首  其二','程公許','宋','宋诗','song-poetry','','[]','兔魄烏輪西復東，流光那肯駐顔紅。',64,'全唐诗/poet.song.194000.json','["兔魄烏輪西復東，流光那肯駐顔紅。", "禮羅君不見溫造，志廣吾寧如孔融。", "難策材駑攀逸武，相期親壽轉方瞳。", "飛騰景暮何須問，聖處慙無一髮功。"]'),
('46d91e10-b72e-458e-82b9-25e1070ba2eb','再和前韻','程公許','宋','宋诗','song-poetry','','[]','條風吹轉斗杓東，護日祥雲一段紅。',64,'全唐诗/poet.song.194000.json','["條風吹轉斗杓東，護日祥雲一段紅。", "聖主慶成神璽重，老親喜動壽杯融。", "塵沙自染雙蓬鬢，歲月難磨兩碧瞳。", "斗印垂腰吾分耳，早看兒輩策新功。"]'),
('90363cc9-785f-43e7-a89a-e5f0f8e93fbb','和彥威紀事二首  其一','程公許','宋','宋诗','song-poetry','','[]','久戍兵殘將亦驕，幸時轇轕與民仇。',64,'全唐诗/poet.song.194000.json','["久戍兵殘將亦驕，幸時轇轕與民仇。", "邊關撤警久階厲，甲胄棄殘尤誤謀。", "淮浦方期三就緒，王官忍賦四宜休。", "江城永夜欹寒枕，數盡殘更有幾籌。"]'),
('2c35ced8-839a-48d1-ad7a-691c47444fa4','和彥威紀事二首  其二','程公許','宋','宋诗','song-poetry','','[]','民勞無訴卒長征，安得天河洗甲兵。',64,'全唐诗/poet.song.194000.json','["民勞無訴卒長征，安得天河洗甲兵。", "虎出柙誰當任責，鳥傷弓後可無驚。", "峽山風雪清尊共，楚澤雲濤去棹輕。", "憂國寧忘絲髮補，忍隨時態慕鮮榮。"]'),
('1f31060a-315e-4c25-bf42-2e4c4424a988','聞山東捷報','程公許','宋','宋诗','song-poetry','','[]','幾年豢虎費隄虞，一旦芟夷快决疽。',64,'全唐诗/poet.song.194000.json','["幾年豢虎費隄虞，一旦芟夷快决疽。", "黼扆可曾輕赫怒，金甌幸未失枝梧。", "戎車喜奏膚公捷，獨柳寧煩傴僂誅。", "更願清朝懲往轍，剩須汲直折姦覦。"]'),
('8369fced-9562-4160-91e9-9cf34bfbfbe4','連日得關表捷報聞敵騎無復留境上者志喜成詩','程公許','宋','宋诗','song-poetry','','[]','十里旌幢轉曉風，行營日報捷書同。',64,'全唐诗/poet.song.194000.json','["十里旌幢轉曉風，行營日報捷書同。", "悠悠何補青油畫，栩栩驚回畫角雄。", "壯士有懷時拔劍，仁人無策弛張弓。", "天機翕闢一翻手，看取桃林騎火紅。"]'),
('f7802ddf-2122-4ada-95ed-62268b1323a8','題卷子會','程公許','宋','宋诗','song-poetry','','[]','龍飛景運詔賓興，將相之階自此升。',64,'全唐诗/poet.song.194000.json','["龍飛景運詔賓興，將相之階自此升。", "毛穎銛鋒須快戰，楮生衷甲作先登。", "精思可使文加點，抄寫能令價倍增。", "努力殺青男子事，功名未盡剡溪藤。"]'),
('f72d12d8-c151-40c0-b185-0482f9a935a2','送彥威姪赴類省試','程公許','宋','宋诗','song-poetry','','[]','吾兄仙去幾何年，情未能忘一綫傳。',64,'全唐诗/poet.song.194000.json','["吾兄仙去幾何年，情未能忘一綫傳。", "相見幽明參勇决，正須行藝兩渾全。", "世科從此傳燈廣，親黨同時奏凱旋。", "孝友令恭天所祐，修途萬里穩加鞭。"]'),
('bd77aaed-9a6b-40cf-ac2a-05f6f7bf9d1c','送句甥持敬赴省試','程公許','宋','宋诗','song-poetry','','[]','外祖憐孫肇錫名，瓊林宴匝兩周星。',64,'全唐诗/poet.song.194000.json','["外祖憐孫肇錫名，瓊林宴匝兩周星。", "果能冠歲露頭角，須信故家猶典刑。", "笑問兩昆眉底白，喜覘二老鬢猶青。", "遄飛借與秋風便，側耳英聲駭震霆。"]'),
('28a41d58-c462-4574-81b8-e928e0f49c02','送家朝南徵君二首  其一','程公許','宋','宋诗','song-poetry','','[]','萬里岷峨入貢琛，怒風摶上九霄鵬。',64,'全唐诗/poet.song.194000.json','["萬里岷峨入貢琛，怒風摶上九霄鵬。", "人才於國猶元氣，天步如今甚薄冰。", "家父憂心宜有誦，嗣王求助可無懲。", "男兒不朽須名節，黄木之灣又一燈。"]'),
('070f770a-f32e-468e-8a00-7ce6288063a1','送家朝南徵君二首  其二','程公許','宋','宋诗','song-poetry','','[]','獵獵霜風不滿旗，留連尊酒話襟期。',64,'全唐诗/poet.song.194000.json','["獵獵霜風不滿旗，留連尊酒話襟期。", "紛紜世上無窮事，慘淡江頭欲別時。", "未必交枰無活著，只憂起死欠神醫。", "疎頑我亦宣州客，傾耳囊封慰所思。"]'),
('54456561-5a5f-450f-9247-d080cdef4c71','鹿鳴宴貢士','程公許','宋','宋诗','song-poetry','','[]','蜀莊故里好揚鄰，不盡斯文萬古存。',64,'全唐诗/poet.song.194000.json','["蜀莊故里好揚鄰，不盡斯文萬古存。", "漢詔十行銜彩鳳，禹門三級躍潛鱗。", "傾心射策恩方渥，努力摧堅語忌陳。", "一第摘髭容易耳，直須名業任千鈞。"]'),
('726604e6-daee-44dd-b5d1-abd254f67ed9','聞喜宴恭和御製賜進士詩','程公許','宋','宋诗','song-poetry','','[]','九五天臨德有元，自應皇化軼羲軒。',64,'全唐诗/poet.song.194000.json','["九五天臨德有元，自應皇化軼羲軒。", "囊封何日無忠諫，延策今年許盡言。", "端藉多材戡世難，盡銷殺氣作春溫。", "萬間華屋非難就，杗桷應須妙選掄。"]'),
('07525dc2-a351-41bf-889d-a42385dc41ec','甲午歲除即事二首初被聘召之命末章感遇述懷  其一','程公許','宋','宋诗','song-poetry','','[]','行年半百又加三，隔一宵還一歲添。',64,'全唐诗/poet.song.194000.json','["行年半百又加三，隔一宵還一歲添。", "邱壑甚慙心賞誤，軒裳可與道情兼。", "醱醅酒熟頻𣂏玉，耐冷燈青密下簾。", "絕愛緗梅開較晚，雪晴要我日巡簷。"]'),
('36c066af-2885-4bd7-a696-e2ee84dbccfc','甲午歲除即事二首初被聘召之命末章感遇述懷  其二','程公許','宋','宋诗','song-poetry','','[]','乞州如斗苦難諧，遣戍蓬婆也自佳。',64,'全唐诗/poet.song.194000.json','["乞州如斗苦難諧，遣戍蓬婆也自佳。", "嚴詔自天疑過誤，虛心造物與安排。", "轒轀猶未空三輔，鼙鼓何當靜兩淮。", "經世無才羞汲引，寸丹咫尺是堯階。"]'),
('dce48aca-b74f-42d9-a747-78afa56d321e','閲邸報上臨朝召用二三耆德志喜有賦過眉山呈悅齋','程公許','宋','宋诗','song-poetry','','[]','人間二十八年事，天運盈虛一剎那。',64,'全唐诗/poet.song.194000.json','["人間二十八年事，天運盈虛一剎那。", "金塢漫憂無處著，冰山想復誤人多。", "問唐偃月消磨幾，奈魯靈光岌嶪何。", "黄道方看升日轂，洗兵馬更挽天河。"]'),
('7872cefd-fd95-4629-8f5c-0528e119fd76','參選銓曹','程公許','宋','宋诗','song-poetry','','[]','竽瑟明知繆所操，才疏分不與時遭。',64,'全唐诗/poet.song.194000.json','["竽瑟明知繆所操，才疏分不與時遭。", "扶犁輕失田家計，斂版來趨吏部曹。", "邂逅功名嫌預借，馳驅州縣敢辭勞。", "憂時空有崢嶸憤，九鑰天關守護牢。"]'),
('178a69de-6f73-4372-a7f6-b9e924370bf1','分直玉堂有懷','程公許','宋','宋诗','song-poetry','','[]','儤直稍寬庚伏暑，傳宣來自玉皇家。',64,'全唐诗/poet.song.194000.json','["儤直稍寬庚伏暑，傳宣來自玉皇家。", "冰盤滿掬三危露，金榼頻𣂏九醖霞。", "衙鼓驟驚行抱牘，索鈴猶誤吏催麻。", "叵堪厨釀甜如蜜，漫倚橋欄看水花。"]'),
('58ad48a6-8645-44f9-81a2-c1cd2d874273','和史子修投贈二首韻時被命至玉堂  其一','程公許','宋','宋诗','song-poetry','','[]','儒習平生祇自酸，可能學古到商盤。',64,'全唐诗/poet.song.194000.json','["儒習平生祇自酸，可能學古到商盤。", "風塵世路知難拗，潢潦詞源恐易乾。", "已愧登瀛聯俊彥，那堪上水費嘲彈。", "饕榮愧乏經時策，安得軍中有范韓。"]'),
('ebcb280a-7148-499e-997d-7498d06628d2','和史子修投贈二首韻時被命至玉堂  其二','程公許','宋','宋诗','song-poetry','','[]','歷盡羊腸足力酸，湖山正好暫遊盤。',64,'全唐诗/poet.song.194000.json','["歷盡羊腸足力酸，湖山正好暫遊盤。", "羈愁等是如鴻集，鄉信難忘問鵲乾。", "瓦屋三間非易借，蒯緱長鋏莫多彈。", "玉川那用輕參尹，沽酒誰爲赤令韓。"]'),
('12944464-022c-4997-b350-4b8a81f96795','直舍紀事二首  其一','程公許','宋','宋诗','song-poetry','','[]','獨冷官曹可得禁，近來冷過玉壺冰。',64,'全唐诗/poet.song.194000.json','["獨冷官曹可得禁，近來冷過玉壺冰。", "無錢沽酒休煩送，有馬知誰許借乘。", "罷謁最宜吟慘淡，愛閒贏得睡懵騰。", "鸞凰自合翔千仞，誰遣人間罣弋矰。"]'),
('c9c8a328-379b-4750-9369-cfdfa4f8302c','直舍紀事二首  其二','程公許','宋','宋诗','song-poetry','','[]','豈不懷歸畏簡書，人生何處不蘧廬。',64,'全唐诗/poet.song.194000.json','["豈不懷歸畏簡書，人生何處不蘧廬。", "靜看世態冥心久，貪問生涯畫計疏。", "休作勞神狙賦芧，可同貪啄鳥馴除。", "飯疏有味親長健，此樂千金莫換渠。"]'),
('4fbae9af-9eee-4a39-af9d-57a199f7e044','歸班之明日以六參入趁起居','程公許','宋','宋诗','song-poetry','','[]','湖海飄摇誤召環，春風入綴紫宸班。',64,'全唐诗/poet.song.194000.json','["湖海飄摇誤召環，春風入綴紫宸班。", "恭聞聘幣及巖穴，不以多材遺蒯菅。", "靜念升沉皆命分，喜因蹈舞拜天顔。", "承明莫作官曹看，汗簡須憑直筆刪。"]'),
('cdf19297-1682-4302-a4fb-3bdb0e080832','題高廟宸翰','程公許','宋','宋诗','song-poetry','','[]','古錦囊開兩軸書，宸奎騰采動山墟。',64,'全唐诗/poet.song.194000.json','["古錦囊開兩軸書，宸奎騰采動山墟。", "能令使者分王命，想見中興似國初。", "九鼎可爲宗社重，萬年誰謂草茅疏。", "襲藏何但傳家寶，汗簡他年或作諸。"]'),
('3b7415a5-c35a-4c52-8662-87065b8c24b9','以西省齋事被差孟夏景靈宮朝饔跪進茶酒齋宿道山','程公許','宋','宋诗','song-poetry','','[]','承明三入笑陳人，藥砌翻紅又一春。',64,'全唐诗/poet.song.194000.json','["承明三入笑陳人，藥砌翻紅又一春。", "英轂並馳慙領袖，斐章何自稱絲綸。", "駿奔數幸天顔近，駑拙難勝寵渥頻。", "月蠹腐紅無以報，囊封敢不罄披陳。"]'),
('ec2138ac-b1ac-4f0a-a901-58c85d03e619','上茶使鄒監丞秘閣','程公許','宋','宋诗','song-poetry','','[]','年時觸熱曳長裾，重拜劉公一紙書。',64,'全唐诗/poet.song.194000.json','["年時觸熱曳長裾，重拜劉公一紙書。", "駑駟何堪蒙錦繡，木瓜無復報瓊琚。", "還因持檄親犀節，恐趁追鋒侍玉除。", "九萬扶摇鵬運闊，可能倦翮借吹噓。"]'),
('32627ef7-1865-451e-a42a-b8b6e9b7322f','西省齋宿陪侍左史曹舍人話舊以除當字賦詩下教和答  其一','程公許','宋','宋诗','song-poetry','','[]','一行奎畫寵新除，左陛濡毫要直書。',64,'全唐诗/poet.song.194000.json','["一行奎畫寵新除，左陛濡毫要直書。", "何幸鵷班連省闥，誤令鼠璞雜瓊琚。", "雲窗霧閣非官府，璧月珠星近帝居。", "二十年前舊騷律，琢磨今乃過黄初。"]'),
('fc542c3d-8736-4a5e-a198-3a1cc74fcdd8','西省齋宿陪侍左史曹舍人話舊以除當字賦詩下教和答  其二','程公許','宋','宋诗','song-poetry','','[]','潑面緇塵不易當，佩蘭誰與共祗芳。',64,'全唐诗/poet.song.194000.json','["潑面緇塵不易當，佩蘭誰與共祗芳。", "迂頑羞問翻階藥，邂逅容分夾案香。", "且可埋頭繙竹素，底須繫肘詫銀黄。", "看公自致青雲上，老我何妨誚斗量。"]'),
('c9efccc7-aa82-44a4-bd73-e0a9970c9343','寄呈座主李左史三首  其一','程公許','宋','宋诗','song-poetry','','[]','絲絇趁曉紫宸朝，憫俗超然賦遠遊。',64,'全唐诗/poet.song.194000.json','["絲絇趁曉紫宸朝，憫俗超然賦遠遊。", "富貴儻來心止水，隠思不耐鬢先秋。", "誰知皓首太玄草，獨對青山大白浮。", "只恐萬牛勤挽致，未須封戶橘千頭。"]'),
('b9e59fde-2570-45d1-b97c-77d2c3eaf2a0','寄呈座主李左史三首  其二','程公許','宋','宋诗','song-poetry','','[]','九萬雲程不作遥，暫教六月息鵬遊。',64,'全唐诗/poet.song.194000.json','["九萬雲程不作遥，暫教六月息鵬遊。", "騷情吟徹湖天曉，義膽寒生石劍秋。", "想見床頭談屑墮，時澆椀面乳花浮。", "雲山不隔師牆戀，憑仗緘書乞點頭。"]'),
('f2a999db-0de2-4948-b9d4-84c91b4268b7','寄呈座主李左史三首  其三','程公許','宋','宋诗','song-poetry','','[]','世紛棖觸不勝憂，尚憶薰風故國遊。',64,'全唐诗/poet.song.194000.json','["世紛棖觸不勝憂，尚憶薰風故國遊。", "惝怳夢回身八翼，凄凉別久日三秋。", "願馳玉軑天津阻，擬問星槎海浪浮。", "千載指南先覺在，行迷未遠却回頭。"]'),
('e76b7773-4cdf-4cd8-bf8a-09dffb68fc12','壽楊浩齋二首  其一','程公許','宋','宋诗','song-poetry','','[]','駕鶴飛來白玉京，疏髯秀色自仙真。',64,'全唐诗/poet.song.194000.json','["駕鶴飛來白玉京，疏髯秀色自仙真。", "要看轉物天機密，更念居閒學力新。", "孔孟以來扶墜緒，羲黄向上屬誰人。", "雅知仁靜宜黄耈，仙谷烟霞不盡春。"]'),
('b7cd7157-43fc-42da-b7bc-bc2759249d09','壽楊浩齋二首  其二','程公許','宋','宋诗','song-poetry','','[]','澒洞風塵漲九垓，萬牛何事首空回。',64,'全唐诗/poet.song.194000.json','["澒洞風塵漲九垓，萬牛何事首空回。", "隠思未易甲兵洗，商略須先根本培。", "望望璽封頒紫閣，駸駸鼎味熟黄梅。", "頌言豈爲摳衣舊，黄道方期日月開。"]'),
('dcb99eee-1090-4c16-a6d9-a576bca2ba3d','立秋後陰雨踰旬新拜禮寺司直之除寓大卿廳一窗清邃','程公許','宋','宋诗','song-poetry','','[]','伏熱翻成十日陰，鬰蒸還復似梅霖。',64,'全唐诗/poet.song.194000.json','["伏熱翻成十日陰，鬰蒸還復似梅霖。", "常疑兵結蚩尤祲，猶喜刑清貫索沈。", "借得一窗堆簡冊，浪憑三尺替山林。", "方池不斷簷花滴，欹枕中宵響玉琴。"]'),
('e3a9a39b-5f39-46e5-8c55-2ed61ab4774b','夏旱奉詔餘杭疏决歸上封事','程公許','宋','宋诗','song-poetry','','[]','桑林忱禱極焦勞，奉詔寬刑輟省曹。',64,'全唐诗/poet.song.194000.json','["桑林忱禱極焦勞，奉詔寬刑輟省曹。", "玉食不怡先損己，璇穹何忍尚屯膏。", "運河今乃通車轍，眢井誰能舉桔槹。", "飽食太倉心自愧，封章不隔九天高。"]'),
('8629ef21-1b95-4309-8c74-3dabd7e55e49','久旱禱雨羅仙有應使君再賦索和','程公許','宋','宋诗','song-poetry','','[]','未饒風伯怒吹雲，且爲仙翁薦寶熏。',64,'全唐诗/poet.song.194000.json','["未饒風伯怒吹雲，且爲仙翁薦寶熏。", "光奪鍾山耕父室，令傳古道阿香墳。", "流膏泫泫溝塍溢，喜氣酣酣麴糵醺。", "太守同憂亦同樂，兵厨餘瀝不難分。"]'),
('ecabe5c7-4416-4341-b41b-4461840d7dcb','禱雨有應和郡廣文希白韻','程公許','宋','宋诗','song-poetry','','[]','金氣胚渾火尚流，亢陽漸已裂龜疇。',64,'全唐诗/poet.song.194000.json','["金氣胚渾火尚流，亢陽漸已裂龜疇。", "沛然一雨酬精禱，暫與羣黎緩隠憂。", "千里耕桑猶樂土，三邊鼙鼓又防秋。", "白頭底是寬閒日，款段令人羨少游。"]'),
('a9a5d934-4a68-4889-8f52-48406bf818d1','郡以閔雨勞民曹顔若春有禱於仰山塔誠念感格甘澤隨應辱教佳製借韻以謝','程公許','宋','宋诗','song-poetry','','[]','鵲尾爐香半未灰，古潭瞥地撼風雷。',64,'全唐诗/poet.song.194000.json','["鵲尾爐香半未灰，古潭瞥地撼風雷。", "單車陟降固勞止，萬壑喧豗亦壯哉。", "高廩正須端策驗，應門已報送詩來。", "憂時更願人才富，重與南山詠有臺。"]'),
('54f39dc4-03a4-41e3-afdf-8f2b84a36054','題射洪顯惠廟','程公許','宋','宋诗','song-poetry','','[]','靈皇夙嗜祗江山，卜宅烟霞縹緲間。',64,'全唐诗/poet.song.194000.json','["靈皇夙嗜祗江山，卜宅烟霞縹緲間。", "带水浄涵青黤黮，畫屏中嵌玉孱顔。", "耽耽洞府自宮闕，裊裊天風來佩環。", "一炷爐烟通肸蠁，願開晴景遍人間。"]'),
('41902fef-f3f2-484c-bca4-071fde001a8b','再遊鳳凰山寺  其一','程公許','宋','宋诗','song-poetry','','[]','人生出處豈前謀，歲一星周再此遊。',64,'全唐诗/poet.song.194000.json','["人生出處豈前謀，歲一星周再此遊。", "世故鼎來憂似海，壯心空在鬢先秋。", "戎車擁路抽身去，僧鉢分香勸我留。", "擾擾戰爭何日定，從前變滅幾浮漚。"]'),
('c0d3fa3a-04a7-4ca9-b334-e86fb26c9102','再遊鳳凰山寺  其二','程公許','宋','宋诗','song-poetry','','[]','西康州隔暮雲邊，風去不來今幾年。',64,'全唐诗/poet.song.194000.json','["西康州隔暮雲邊，風去不來今幾年。", "神睠此山良有以，客行何恨獨潸然。", "瑞圖那復來阿閣，王澤何當復下泉。", "定慧光中祈印證，等慈心與佛齊肩。"]'),
('1d12f054-660e-4759-babb-a43202e4c823','已嘗早稻晚禾得雨亦驟長出城按行阡陌歷諸寺而還成七言二章  其一','程公許','宋','宋诗','song-poetry','','[]','歡謠千里慶西成，小隊傳呼略按行。',64,'全唐诗/poet.song.194000.json','["歡謠千里慶西成，小隊傳呼略按行。", "雨足陳根重穎栗，眼明多稼盡坻京。", "靈君禪悅屏燔炙，樂歲人和喧送迎。", "老守何功享成事，祇憑一念輯和平。"]'),
('e145b58d-4da0-4e08-ad71-b74731e41af1','已嘗早稻晚禾得雨亦驟長出城按行阡陌歷諸寺而還成七言二章  其二','程公許','宋','宋诗','song-poetry','','[]','稻壠楓林錦纈文，秋郊樂事壓芳春。',64,'全唐诗/poet.song.194000.json','["稻壠楓林錦纈文，秋郊樂事壓芳春。", "爲山谷訪竹尊者，介衛公尋石丈人。", "午暑緩觴休北寺，夕曛趣駕度東津。", "勝遊偶際文書暇，一笑溪山面目親。"]'),
('8267e317-db7e-437c-bd22-64afbda174a8','中秋節侍楊尚書待月南樓','程公許','宋','宋诗','song-poetry','','[]','羽扇風清夙靄收，元戎邀月上南樓。',64,'全唐诗/poet.song.194000.json','["羽扇風清夙靄收，元戎邀月上南樓。", "卷回天外連宵雨，借與人間一夕秋。", "六合掃清知有待，微雲點綴故宜休。", "闌干直北頻搔首，何限關山笛裏愁。"]'),
('519a45d0-e418-4104-ba27-11523c0d9cda','久雨快晴侍楊尚書燕鎮遠樓','程公許','宋','宋诗','song-poetry','','[]','瘴雨彌旬快作晴，小山香馥晚風清。',64,'全唐诗/poet.song.194000.json','["瘴雨彌旬快作晴，小山香馥晚風清。", "高秋幕府閒書檄，落日江山擁旆旌。", "形勢自應專一面，關河猶未息交枰。", "雅知牧御須才望，盍早還朝洗甲兵。"]'),
('37f861cd-3c71-4163-b515-d73c9b88f246','和前送吳季永工侍韻二首寄宣城使君吳尚書叔永時季永尚留宣城郡齋  其一','程公許','宋','宋诗','song-poetry','','[]','對床有約二蘇公，湖海何曾出處同。',64,'全唐诗/poet.song.194000.json','["對床有約二蘇公，湖海何曾出處同。", "得似公家情繾綣，相看歲晚樂沖融。", "宛陵信是佳山水，公館翛然若翠蓬。", "吏散不妨談陸續，是非馬耳射東風。"]'),
('8ed1bc63-947b-4e2b-a9ab-4da3cbc781fb','和前送吳季永工侍韻二首寄宣城使君吳尚書叔永時季永尚留宣城郡齋  其二','程公許','宋','宋诗','song-poetry','','[]','詞林巨擘久心降，萬斛龍文隻手扛。',64,'全唐诗/poet.song.194000.json','["詞林巨擘久心降，萬斛龍文隻手扛。", "革履似因求見數，朱衣蹔隔引前雙。", "明當歸闢翹材館，想未能忘濯錦江。", "剩向雲間籠白鶴，他年携伴讀書窗。"]'),
('0888e2ba-e570-4204-92ef-dd6639c87ac7','嘉平八日禱雪崇福觀集霰隨車至晚大雪凡三日廣文邵丈志喜賦詩勉和元韻','程公許','宋','宋诗','song-poetry','','[]','集霰纔隨紫馬回，散花天已御風來。',64,'全唐诗/poet.song.194000.json','["集霰纔隨紫馬回，散花天已御風來。", "塵寰瞥地開仙境，和氣融春入酒杯。", "寒沍潛消人物癘，清吟肯傍簿書堆。", "南枝陡覺精神別，探借東皇信息催。"]'),
('1691e186-bb09-4c64-86bb-a82c30ab9fb6','除夕立春送姪女歸句氏娣家兄弟甥姪皆會席上','程公許','宋','宋诗','song-poetry','','[]','歲除還有歲更新，華髮相看手足親。',64,'全唐诗/poet.song.194000.json','["歲除還有歲更新，華髮相看手足親。", "千古風流企王謝，兩家情味匹朱陳。", "纏紅飲徹椒觴曉，剪綵歡生綺席春。", "瓜葛綢繆寧易有，况兼樂事與良辰。"]'),
('d0822325-ff99-42aa-8ffe-a4b419cc00b8','禱雪麻仙洞前立春一日湫壓縣境而雪霰已集連日六花呈瑞以元宵設供權父及士友皆賦詩二首和韻以謝  其一','程公許','宋','宋诗','song-poetry','','[]','駑怯深慙政理愆，驕陽積擅北風權。',64,'全唐诗/poet.song.194000.json','["駑怯深慙政理愆，驕陽積擅北風權。", "青鸞趣駕賓蒼皞，白鳳先驅從列仙。", "坯蟄夢驚離貝闕，裂龜渴飲變瓊田。", "空餐那有涓埃報，只辦爐薰薦洞天。"]'),
('fbf0860c-59de-47b9-a5c1-ba9e7b254a5d','禱雪麻仙洞前立春一日湫壓縣境而雪霰已集連日六花呈瑞以元宵設供權父及士友皆賦詩二首和韻以謝  其二','程公許','宋','宋诗','song-poetry','','[]','陽烏且緩浴虞淵，瑞白春花勝臘前。',64,'全唐诗/poet.song.194000.json','["陽烏且緩浴虞淵，瑞白春花勝臘前。", "臺笠看人爭播種，扶犁撩我夢歸田。", "千金何術能醫國，十雨從今更問天。", "暫駐飈游須浄供，元宵未暇寶燈燃。"]'),
('5785625e-f099-4540-80fd-fd1fec87aad9','觀壁間鄭宣威早春賞杏花之作司令洪丈命余即事用韻  其一','程公許','宋','宋诗','song-poetry','','[]','乍聽歸燕語窗櫳，催放蓮燈萬炬紅。',64,'全唐诗/poet.song.194000.json','["乍聽歸燕語窗櫳，催放蓮燈萬炬紅。", "掃盡妖氛春色外，喚回和氣雨聲中。", "時機翻覆須天定，人事扶持願歲豐。", "幕府賢勞愧羣彥，吟詩留俟採民風。"]'),
('4b9cdfe2-2c21-4742-a82f-3972292a8f32','觀壁間鄭宣威早春賞杏花之作司令洪丈命余即事用韻  其二','程公許','宋','宋诗','song-poetry','','[]','過雨麴塵繰淺綠，倚風綬带娜殷紅。',64,'全唐诗/poet.song.194000.json','["過雨麴塵繰淺綠，倚風綬带娜殷紅。", "稍知春在酒深處，尤覺日長書課中。", "典記誤令參鄴下，封囊也擬學新豐。", "黄雲催熟崆峒麥，破敵何須鶴唳風。"]'),
('b379052a-83ae-4bb5-a513-8a0e7aa83406','邑令招講上元故事與簿尉同賦二首  其一','程公許','宋','宋诗','song-poetry','','[]','星弁熒煌鼎足三，河陽春意十分添。',64,'全唐诗/poet.song.194000.json','["星弁熒煌鼎足三，河陽春意十分添。", "和衷總是清時瑞，令節應須樂事兼。", "山徑晚陪瓊玉佩，訟堂夜醉水晶簾。", "羽書撤警年方熟，賸折梅花插帽簷。"]'),
('907f65a7-d1d7-4d21-85a4-369d5f6c6402','邑令招講上元故事與簿尉同賦二首  其二','程公許','宋','宋诗','song-poetry','','[]','人情悅豫樂音諧，新覺華譙氣象佳。',64,'全唐诗/poet.song.194000.json','["人情悅豫樂音諧，新覺華譙氣象佳。", "璧月輝輝三夕永，榆星歷歷九霄排。", "笙歌圍坐花如海，殽核堆山酒若淮。", "富貴方來付公等，五雲深處豈無階。"]'),
('30e4d1ad-85b8-4242-9095-588babf11fb1','借寓楊和王府秀芳空屋寬靜爽潔意甚樂之','程公許','宋','宋诗','song-poetry','','[]','紅塵難得安棲處，借屋三間委巷深。',64,'全唐诗/poet.song.194000.json','["紅塵難得安棲處，借屋三間委巷深。", "地僻喜無車馬過，官閒不廢簡編尋。", "傍牆幸有數竿竹，護筍看成滿院陰。", "須信市朝爲大隠，心無事累即山林。"]'),
('65b08533-caee-4a5a-8204-84ec4e47b786','李德夫司理即永康官居闢小軒賦詩二首求京花和韻遣送  其一','程公許','宋','宋诗','song-poetry','','[]','老於俗嗜異酸鹹，枯木無心倚碧巖。',64,'全唐诗/poet.song.194000.json','["老於俗嗜異酸鹹，枯木無心倚碧巖。", "花事因循渾漫與，吟邊荒落幾曾芟。", "似聞公館小軒闢，遥揖靈峰萬石漸。", "竹素堆床官事省，燕梁日永語呢喃。"]'),
('d31695f7-4e38-484c-8640-391d66b59a66','李德夫司理即永康官居闢小軒賦詩二首求京花和韻遣送  其二','程公許','宋','宋诗','song-poetry','','[]','西洛風流壓衆芳，十分國艷與天香。',64,'全唐诗/poet.song.194000.json','["西洛風流壓衆芳，十分國艷與天香。", "護持翠幕千窠錦，羞澁青銅兩鬢霜。", "不怕眼花疑保福，且將色相問空王。", "書窗不要笙歌雜，茗椀相娛味更長。"]'),
('1881b931-78b8-4134-8a01-65b1d4b93f92','賀府尹董侍郎落成貢院','程公許','宋','宋诗','song-poetry','','[]','縱壑潛蛟變化秋，岷精表瑞協人謀。',64,'全唐诗/poet.song.194000.json','["縱壑潛蛟變化秋，岷精表瑞協人謀。", "萬間指顧璇杓運，千柱穹窿玉斧修。", "小試鳳樓心匠巧，快看蟻陣戰功收。", "向來三策天人學，盍爲諸生一點頭。"]'),
('20549491-f103-4976-8433-c97827ee7786','廣漠亭二首和陳憲益之舊韻  其一','程公許','宋','宋诗','song-poetry','','[]','百乘去爲天下宰，暮年嶺瘴隔京都。',64,'全唐诗/poet.song.194000.json','["百乘去爲天下宰，暮年嶺瘴隔京都。", "君看封禁嚴邊瑣，力碎調停此範模。", "赤舄儻來金鉉貴，青衫依舊紙屏糊。", "秦關北望烟雲渺，何日重還舊地圖。"]'),
('41d3f9ec-f561-4a41-8273-c095e0df6d53','廣漠亭二首和陳憲益之舊韻  其二','程公許','宋','宋诗','song-poetry','','[]','萬峰銀雪排天險，千里封溝闢蜀都。',64,'全唐诗/poet.song.194000.json','["萬峰銀雪排天險，千里封溝闢蜀都。", "盡揖瀆靈趨几席，始知國相妙規模。", "心同典午深衣樂，褊笑荆文紙閣糊。", "元祐風流如可問，羣賢登用是良圖。"]'),
('742d5651-1456-4be8-b22c-41069e045cea','陪憲節飲見易亭及萬里樓和韻二首  其一','程公許','宋','宋诗','song-poetry','','[]','郭洞春深物象妍，得陪繡斧漾觥船。',64,'全唐诗/poet.song.194000.json','["郭洞春深物象妍，得陪繡斧漾觥船。", "連山崷崒檐楹外，六畫分明几席前。", "記就儘教騰紙價，碑成還恐費松烟。", "熟知邱壑饒心賞，正未能忘賦下泉。"]'),
('a4a9728b-1a40-4132-9dd2-831749e42f11','陪憲節飲見易亭及萬里樓和韻二首  其二','程公許','宋','宋诗','song-poetry','','[]','天宇修眉分外妍，雷垣波靜穩行船。',64,'全唐诗/poet.song.194000.json','["天宇修眉分外妍，雷垣波靜穩行船。", "向來蛟鰐驕無奈，今日鳧鷖戲滿前。", "爽氣逼人漙瑞露，醉題眩眼爛非烟。", "薄才羞與雲龍啜，脫骨端須第一泉。"]'),
('4bdbe499-cbc0-46ac-894f-60680e132298','余爲華陽尉三年事制置使榷牧都漕兩使者皆以文字辱知不盡責以吏也既滿戍擬濛陽丞歸親旁范使者爲改註左綿學官瘧病再作未即就戍成二詩呈兄長及諸友  其一','程公許','宋','宋诗','song-poetry','','[]','錦江傲吏真癡絕，公事無多日賦詩。',64,'全唐诗/poet.song.194000.json','["錦江傲吏真癡絕，公事無多日賦詩。", "風月諱人貪捃拾，烟霞痼我費醫治。", "非關瘧鬼工爲厲，豈有詩人不耐饑。", "三月不曾吟一句，汗顔何以有毛錐。"]'),
('8065f715-9902-474e-8189-86bf78c91660','余爲華陽尉三年事制置使榷牧都漕兩使者皆以文字辱知不盡責以吏也既滿戍擬濛陽丞歸親旁范使者爲改註左綿學官瘧病再作未即就戍成二詩呈兄長及諸友  其二','程公許','宋','宋诗','song-poetry','','[]','拄笏西山興已濃，蚌溪邀我採芙蓉。',64,'全唐诗/poet.song.194000.json','["拄笏西山興已濃，蚌溪邀我採芙蓉。", "客遊舊有詩盟在，官冷新添野性慵。", "世路今方悲梗塞，家山暫許樂從容。", "等閒袖手棋枰外，紫電中宵掣劍鋒。"]'),
('d19e96d8-8d93-41f7-aba9-ffaf685b4acd','和馮潔己節夜見過二首  其一','程公許','宋','宋诗','song-poetry','','[]','我生恨不際休嘉，浩蕩憂思未有涯。',64,'全唐诗/poet.song.194000.json','["我生恨不際休嘉，浩蕩憂思未有涯。", "書劍伴人常作客，氍毹暖夢暫還家。", "葭灰漸喜回陽律，麥隴時須潤雪花。", "休沐許寬書檄繞，靜中較似日長些。"]'),
('bdac1f99-789d-4a84-bc0b-766fb826aeeb','和馮潔己節夜見過二首  其二','程公許','宋','宋诗','song-poetry','','[]','破悶孤斟莫厭深，風箏時爲送清音。',64,'全唐诗/poet.song.194000.json','["破悶孤斟莫厭深，風箏時爲送清音。", "平生遇境無餘戀，令節因君忽愴心。", "梅角吹殘愁不寐，柳枝放去杳難尋。", "蛾眉列屋功成後，未用凄涼學越吟。"]'),
('4429f723-c701-4aa3-a1dd-77c69e417fb5','載酒泛芙蓉溪游富樂伯用再和前韻牽課同作','程公許','宋','宋诗','song-poetry','','[]','霸氣凄凉憶豫州，薜蘿掩映小山幽。',64,'全唐诗/poet.song.194000.json','["霸氣凄凉憶豫州，薜蘿掩映小山幽。", "不知今古幾枰誤，空使英雄兩淚流。", "借問長槍威塞外，何如短棹老滄洲。", "臨分更隔芙蓉語，投贈慙無玉可舟。"]'),
('cade301d-667b-4306-a98e-d7538891d18c','江漲有感','程公許','宋','宋诗','song-poetry','','[]','惆悵天涯私自憐，錦囊有句愧重編。',64,'全唐诗/poet.song.194000.json','["惆悵天涯私自憐，錦囊有句愧重編。", "忍心寬作青梅約，眩眼俄驚丹荔燃。", "浩蕩修途今幾驛，紛紜歸思日如年。", "不因煤穎相料理，何以遣懷風月前。"]'),
('b774fe78-ee2c-42c0-811e-7fd928d98828','買舟至崖祀陸使君','程公許','宋','宋诗','song-poetry','','[]','水曹羈我窘于囚，貸與潼江一釣舟。',64,'全唐诗/poet.song.194000.json','["水曹羈我窘于囚，貸與潼江一釣舟。", "柂轉清灘微觱沸，棹移曲巷且夷猶。", "偶因檥岸穿沙徑，絕愛寒烟簇晚洲。", "明日玉屏重覩面，九歌待續水安流。"]'),
('4877d4e8-ad98-4900-a521-480ac0a1ea32','溪亭春日二首  其一','程公許','宋','宋诗','song-poetry','','[]','借屋三間俯近郊，溪流如練繞蘭皋。',64,'全唐诗/poet.song.194000.json','["借屋三間俯近郊，溪流如練繞蘭皋。", "聊同彭澤歸栽菊，肯向玄都問種桃。", "別久心情渾漫浪，相看鬚髮轉蕭騷。", "只因舊學荒尤甚，政藉談餘爲櫛薅。"]'),
('19d2ba6a-4bf1-49fa-9178-d75d8cefe0f6','溪亭春日二首  其二','程公許','宋','宋诗','song-poetry','','[]','極目青天蜀道難，無因長坂得聯驂。',64,'全唐诗/poet.song.194000.json','["極目青天蜀道難，無因長坂得聯驂。", "思鄉浪費腸回九，行世何妨臂折三。", "楊柳風微生百媚，棠梨晝永带餘酣。", "天涯猶頼春娛客，那得鄰山寄一菴。"]'),
('b87ab266-a960-4713-abc0-7a48646422c6','丙子寅月九日五鼓夢餘憶舊作因用韻','程公許','宋','宋诗','song-poetry','','[]','業識縈牽豈自由，幸逢此劫在儒流。',64,'全唐诗/poet.song.194000.json','["業識縈牽豈自由，幸逢此劫在儒流。", "昏昏心似未磨鏡，役役身如不纜舟。", "聞道無緣時已晚，養生欠術鬢先秋。", "向平可謂真男子，家事無關五嶽遊。"]'),
('4721149f-9c7c-4bd0-8aac-d32e99b0894a','立秋後三日得二侄并侄孫家書','程公許','宋','宋诗','song-poetry','','[]','萬里書來印籀紅，慰情何但萬金同。',64,'全唐诗/poet.song.194000.json','["萬里書來印籀紅，慰情何但萬金同。", "懸絲性命幸存活，掃地生涯甘阨窮。", "老去憂心長似醉，秋來衰鬢亂飛蓬。", "故園未有西歸日，且願平安信數通。"]'),
('4a7e5965-6838-4a74-9208-bb12c439250f','施明可自湘潭還霅川以詩編相示摘其中重陽一篇次韻題似明可','程公許','宋','宋诗','song-poetry','','[]','倦游何似雁隨陽，愁緒知添幾線長。',64,'全唐诗/poet.song.194000.json','["倦游何似雁隨陽，愁緒知添幾線長。", "歸路驛梅多未破，吟邊汀芷藹餘香。", "寄聲鷗鷺舊同社，可奈鷖鳬紛着行。", "乞與東風一吹送，偃松猶及共流觴。"]'),
('a4af376c-a407-46c0-bf46-c3e3cae01d97','重陽即事','程公許','宋','宋诗','song-poetry','','[]','爛漫三年藥市遊，饑驅忽到字江頭。',64,'全唐诗/poet.song.194000.json','["爛漫三年藥市遊，饑驅忽到字江頭。", "凄凉風色欄干暮，靉靆晴雲䆉稏秋。", "紅葉不知人恨遠，黄花慣與客供愁。", "諸君正爾癡官事，誰共高吟百尺樓。"]'),
('76fe9960-0e85-446b-8579-da84ef66cca3','題秋芳菊蝶圖','程公許','宋','宋诗','song-poetry','','[]','故山歲歲霜秋杪，手折黄花岸接䍦。',64,'全唐诗/poet.song.194000.json','["故山歲歲霜秋杪，手折黄花岸接䍦。", "粉蝶笑窺人老大，玉蛆撩動句新奇。", "雨荒靖節醉吟處，風亂韓憑飛舞時。", "卧展新圖續歸夢，晚香有味我同誰。"]'),
('ae1c1289-a411-4d71-9315-32ee49326d6c','子思賦中秋翫月詞借韻作詩','程公許','宋','宋诗','song-poetry','','[]','山路相呼游冶盤，何妨月下更追歡。',64,'全唐诗/poet.song.194000.json','["山路相呼游冶盤，何妨月下更追歡。", "情知一夕秋無價，看徹三更酒未闌。", "衰鬢侵愁羞自照，回腸索句大應難。", "可能散髮扁舟去，一到垂虹亭上看。"]'),
('a691c9a7-2b46-435f-bc9f-817b3b88c51a','以梨橙寄景韓景韓有詩來謝因和韻奉答','程公許','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','離腸不耐食張梨，併裹橙金遣使齎。',64,'全唐诗/poet.song.194000.json','["離腸不耐食張梨，併裹橙金遣使齎。", "薄饋羞同園吏菜，好詞空費外孫虀。", "含消漢苑夢頻渴，霜落洞庭書續題。", "莫遣楚嬌多勸飲，怨歌難解太常妻。"]'),
('15aece36-5918-4af1-8017-e99f06f73122','和洪司令春日客懷二首  其一','程公許','宋','宋诗','song-poetry','','[]','寂寂春愁何許來，詩翁得句凌歐梅。',64,'全唐诗/poet.song.194000.json','["寂寂春愁何許來，詩翁得句凌歐梅。", "一百五日火將換，二十四風花遞開。", "玉壘新詩未題遍，鏡山歸夢寧須催。", "人生田舍差足樂，我亦欲尋榿木栽。"]'),
('d00641ae-feea-46e0-881f-f953d45e9e67','和洪司令春日客懷二首  其二','程公許','宋','宋诗','song-poetry','','[]','好風排闥錦囊來，咀味真如渴望梅。',64,'全唐诗/poet.song.194000.json','["好風排闥錦囊來，咀味真如渴望梅。", "櫻筍算無多日事，棠梨約有幾分開。", "社醅熟倩提壺勸，春種忙應布穀催。", "早願時清歸亦好，小山幽桂賸須栽。"]'),
('8cac21f9-4118-4a94-84be-a47d886b88b8','和可道約同館於都統衙','程公許','宋','宋诗','song-poetry','','[]','至理玄同孔老瞿，客塵覺似漸消除。',64,'全唐诗/poet.song.194000.json','["至理玄同孔老瞿，客塵覺似漸消除。", "一生嚼蠟有餘味，兩載離家能幾書。", "君已灰心參祖意，我猶滯相問童初。", "寶巖不作桑間戀，榆館能來慰索居。"]'),
('82a86b14-b48a-415b-b400-182a39f5a960','謝檢閲牟存叟袖啟相訪','程公許','宋','宋诗','song-poetry','','[]','井絡西瞻劫火殘，天涯執手語含酸。',64,'全唐诗/poet.song.194000.json','["井絡西瞻劫火殘，天涯執手語含酸。", "鄉人爲把子虛誦，國典能推良吏難。", "老我棲遲同燕雀，送君翔翥上鴛鸞。", "長風借與還鄉便，猶喜白鷗盟未寒。"]'),
('f68a9a88-b46c-4f4a-a8c8-9bfb03f823b0','爲王山尹子渚賦潛齋末句寄聲葉新之','程公許','宋','宋诗','song-poetry','','[]','斯文宗緒自河南，妙處元非故紙鑽。',64,'全唐诗/poet.song.194000.json','["斯文宗緒自河南，妙處元非故紙鑽。", "萬里夢歸伊闕遠，一窗靜對玉峰攢。", "林深霧豹南山隠，海闊風鵬北溟摶。", "刻楮自憐無一補，寫心寄與故人看。"]'),
('97ac99d9-24da-402b-93ce-3e96e6eb0928','彥尹姪追送至南江','程公許','宋','宋诗','song-poetry','','[]','猶子匆匆遽索違，三甥小住未爲非。',64,'全唐诗/poet.song.194000.json','["猶子匆匆遽索違，三甥小住未爲非。", "追隨寬作一程計，摻執那知幾歲歸。", "唳鶴警寒排字密，浴鷗嬉暖着羣飛。", "物情撩我離情黯，射策催來覲日畿。"]'),
('f07aefdd-ce9b-436e-a444-045126e5ff85','送葉鎮之釋褐授信州推官歸台州','程公許','宋','宋诗','song-poetry','','[]','天涯一見便綢繆，二十年間詫兩優。',64,'全唐诗/poet.song.194000.json','["天涯一見便綢繆，二十年間詫兩優。", "不以聲名誇衆雋，欲將文行輩前修。", "懷章趁酌椒觴壽，分幙還尋璧水游。", "蜀客念歸歸路梗，卜鄰儻許傍丹丘。"]'),
('18af9757-0e71-4a2d-9cb0-d687ecb05340','別凌雲士友','程公許','宋','宋诗','song-poetry','','[]','三生緣法熟嘉州，乘興俄成十月留。',64,'全唐诗/poet.song.194000.json','["三生緣法熟嘉州，乘興俄成十月留。", "山水縱觀方得趣，交朋莫逆忽抽頭。", "淋漓張飲梅花岸，慘淡分携杜若洲。", "恨欠白崖陪杖屨，春風和暖及同游。"]'),
('0f0b6d46-bdaa-4cb6-8280-33716ed6c707','別謝德芳','程公許','宋','宋诗','song-poetry','','[]','艤棹江干得款留，曾將避世與君謀。',64,'全唐诗/poet.song.194000.json','["艤棹江干得款留，曾將避世與君謀。", "誰知事變即勘定，端藉儒先寬顧憂。", "分陝續書勞會計，借籌偶暇語綢繆。", "分携竟作春風約，梅驛瞻雲黯暮愁。"]'),
('fb53a7bd-b74c-4015-b4d1-3c7572825521','別帥垣登舟泝江','程公許','宋','宋诗','song-poetry','','[]','暫來偶作兩旬留，下榻慚非孺子儔。',64,'全唐诗/poet.song.194000.json','["暫來偶作兩旬留，下榻慚非孺子儔。", "西閣夜闌猶跋燭，北巖晚霽趣歸舟。", "高城回首烟波暝，短棹支頤水國秋。", "歲晚束書岷下去，梁園空復羨枚鄒。"]'),
('8bc61cf8-a635-442b-9641-899f15b317ae','和喬擇善別若水韻','程公許','宋','宋诗','song-poetry','','[]','尼嶺飈遊不可期，寥空無路寄幽思。',64,'全唐诗/poet.song.194000.json','["尼嶺飈遊不可期，寥空無路寄幽思。", "階蘭競秀有誰省，貝錦傷讒徒爾爲。", "默坐勿書殷浩怪，擬騷休作楚臣悲。", "君看雪澗凌霄幹，長有毿毿綠滿枝。"]'),
('958241b8-f138-4bef-9f85-9e575a8602f4','沙津連日風雨阻行舟發即晴寄李成之','程公許','宋','宋诗','song-poetry','','[]','江陵五日惡風雨，知我欲行舒小晴。',64,'全唐诗/poet.song.194000.json','["江陵五日惡風雨，知我欲行舒小晴。", "渺渺雲沙連恨遠，冥冥烟樹喚愁生。", "上牢下牢險入夢，東瀼西瀼詩有聲。", "同是天涯更分手，銷魂風月與誰平。"]'),
('0f8287c1-a87a-4c83-92f8-5eda4ed41b4e','虛舟相逐至岳陽錄示舊日避風詩和韻紀事','程公許','宋','宋诗','song-poetry','','[]','繫船三日風當止，雨欲逗晴雲亂飛。',64,'全唐诗/poet.song.194000.json','["繫船三日風當止，雨欲逗晴雲亂飛。", "沽酒店家都是薄，買蔬山市晚方歸。", "客裝淹速信難料，友社歡諧知可依。", "喚起玄真共心賞，桃花流水鱖魚肥。"]'),
('34d862a1-de2b-4a0d-823d-53e6a537b717','得臺檄視堰至上皇設黄籙會親友自遠而至者孫承父表兄用晦弟彥威有年彥尹彥濟四姪勝父王甥虛中句甥司馬行父宗人季然共十七人次日首途久雨開霽','程公許','宋','宋诗','song-poetry','','[]','肅敞芝壇大面峰，擬憑方寸遡璇穹。',64,'全唐诗/poet.song.194000.json','["肅敞芝壇大面峰，擬憑方寸遡璇穹。", "夜窗滴盡三更雨，曉霧吹開萬壑風。", "孤鶴肯來隨伴去，十龜相逐賞心同。", "未應佳氣高臺擅，一覽西岷面勢雄。"]'),
('fa0e22b2-a99e-4161-ab58-9cc3cc59f83d','成都踰旬陰冷深冬時節借館超悟得子敬德夫二兄相晤語差慰寂寥','程公許','宋','宋诗','song-poetry','','[]','屯陰不動紫金盤，三月凄風橫作寒。',64,'全唐诗/poet.song.194000.json','["屯陰不動紫金盤，三月凄風橫作寒。", "待旦重衾纔得暖，感時對酒祇長歎。", "黑雲何日三舍避，黄道中天萬目看。", "不有對床清夜語，客懷何以解憂端。"]'),
('881c10ed-c6ae-4054-9c3f-9e326c2289d1','送道傳姪補中國學二首  其一','程公許','宋','宋诗','song-poetry','','[]','竹林挺挺固多賢，子更姱修鼎盛年。',64,'全唐诗/poet.song.194000.json','["竹林挺挺固多賢，子更姱修鼎盛年。", "一縷千鈞扶世緒，三條八韻壓儒先。", "辟雍振鷺翔而集，幽谷鳴鶑自此遷。", "可但積分縻好爵，事須學識細磨研。"]'),
('aef7e264-6444-41f7-9bf6-8ab3f0f79819','送道傳姪補中國學二首  其二','程公許','宋','宋诗','song-poetry','','[]','冰霜一節感親恩，褒詔東來耀里門。',64,'全唐诗/poet.song.194000.json','["冰霜一節感親恩，褒詔東來耀里門。", "孝敬自能通造物，否臧勿用較煩言。", "靈椿未老須三釜，折桂歸來共一尊。", "須信倚門朝夕望，未容六館駐何蕃。"]'),
('38362924-5c30-45f3-abba-afe869bf52ee','余拉威濟取山路歸家用光獨泝江再和見貽仍同賦','程公許','宋','宋诗','song-poetry','','[]','冠藤衣葛自蕭閒，巖壑精神繪畫難。',64,'全唐诗/poet.song.194000.json','["冠藤衣葛自蕭閒，巖壑精神繪畫難。", "着脚兔庭聊試險，同盟鷗社未應寒。", "快晴山色凝朝采，急雨汗流吼夜灘。", "近日詩情差覺勝，賸加礲錯怕人看。"]'),
('f28ddb94-b91b-4eb3-82a8-8462d5e7c2bf','遊中巖晴烟如春尤覺林壑之勝也','程公許','宋','宋诗','song-poetry','','[]','晴嵐暖翠中巖寺，十二年間得再遊。',64,'全唐诗/poet.song.194000.json','["晴嵐暖翠中巖寺，十二年間得再遊。", "三筍龕深香不散，萬松山擁霧難收。", "鷲峰付囑雖常住，雁蕩經行豈易求。", "欲識老師真面目，白雲深處澗泉流。"]'),
('6c85569c-1f00-4c21-8f58-75532ace3976','陪尚書遊中巖夜大風雨尚書及任卿史石泉皆耆年德清諧季并余以晚輩侍','程公許','宋','宋诗','song-poetry','','[]','中天臺殿倚竛竮，憶昨深登六歲零。',64,'全唐诗/poet.song.194000.json','["中天臺殿倚竛竮，憶昨深登六歲零。", "霧鎖巖扉須玉鑰，雲扶革履上青冥。", "三峰靜對厖眉秀，雙璧驚回醉眼醒。", "風雨三更龍象集，祖師意旨付誰聽。"]'),
('99e8511f-14d6-40d9-920f-6bc928272bf2','泛舟登弁山祥應宮之絕頂望太湖窺黄龍洞過倪尚書雲巖','程公許','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','蘋浪蹴帆移別浦，筍輿邀我度遥岑。',64,'全唐诗/poet.song.194000.json','["蘋浪蹴帆移別浦，筍輿邀我度遥岑。", "雲開震澤水銀溢，風掠洞庭螺翠深。", "神井千尋龍起蟄，幽巖四面石成林。", "蘇仙詩句倪公賦，萬古清風僭嗣音。"]'),
('b5168a1b-eed6-4282-ad0b-d2d859c46186','道山諸丈置酒飲餞秀野園以詩謝別','程公許','宋','宋诗','song-poetry','','[]','去國飄然一障乘，都門祖帳集華簪。',64,'全唐诗/poet.song.194000.json','["去國飄然一障乘，都門祖帳集華簪。", "黄梅未雨熱如沸，白葛當風凉滿襟。", "江國頗堪千里寄，蓬山遥想五雲深。", "論思禁闥須公等，肯念交盟數寄音。"]'),
('2710e1a5-f0c3-4239-9e61-cccdbda80241','遊道何二山晚飲倪氏玉湖','程公許','宋','宋诗','song-poetry','','[]','草草盤蔬一酒壺，虎巖小憩轉金輿。',64,'全唐诗/poet.song.194000.json','["草草盤蔬一酒壺，虎巖小憩轉金輿。", "靜觀生物春風裏，笑拂詩牌劫火餘。", "散策松陰寒悄悄，擷香梅逕雪踈踈。", "歸航未迫西山暮，碧浪湖邊看網魚。"]'),
('82947152-edff-4b42-81c9-5a83dc68e4f3','馬當山','程公許','宋','宋诗','song-poetry','','[]','往事空聞傳記誇，石磯依舊鎖晴霾。',64,'全唐诗/poet.song.194000.json','["往事空聞傳記誇，石磯依舊鎖晴霾。", "定知貝闕通溟極，誰着叢祠倚斷崖。", "乞與一帆風借便，應憐萬里客傷懷。", "文章有體神知否，霞鶩雖工語類俳。"]'),
('42718420-143d-4b49-befe-7dad9d1157c8','夜過馬當山','程公許','宋','宋诗','song-poetry','','[]','獨載詩書趁野航，自憐漂泊度時光。',64,'全唐诗/poet.song.194000.json','["獨載詩書趁野航，自憐漂泊度時光。", "殘年準擬登牛首，連夜匆忙過馬當。", "古廟荒寒江浸影，斷崖悽慘石凝霜。", "壯懷未分甘衰老，回首長懷恨更長。"]'),
('ee2df57e-6c30-4a76-baa4-523e6d6c4062','廬山雪','程公許','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','倚天無數玉巉巖，心覺廬山是雪山。',64,'全唐诗/poet.song.194000.json','["倚天無數玉巉巖，心覺廬山是雪山。", "未暇雙林尋凈侶，試招五老對蒼顔。", "遠遊借問有何好，勝賞何曾容暫閒。", "却恨此生雲水脚，誤隨人去踏塵寰。"]'),
('e86edb37-1a7b-4941-a431-9cf10ce6eae7','姑蘇臺','程公許','宋','宋诗','song-poetry','','[]','館娃陳迹久蓬蒿，留得蘇臺數仞高。',64,'全唐诗/poet.song.194000.json','["館娃陳迹久蓬蒿，留得蘇臺數仞高。", "隔水雲山青斷絕，繞城溝蕩碧周遭。", "遥憐讓國清風遠，忍見連艘戰血鏖。", "滿目凄凉千古事，長洲仍舊柳如繅。"]'),
('684b2846-70b3-4d6a-975b-f592a958cc5d','絕勝亭','程公許','宋','宋诗','song-poetry','','[]','入眼江郊杜集中，勝游何必恨匆匆。',64,'全唐诗/poet.song.194000.json','["入眼江郊杜集中，勝游何必恨匆匆。", "糢糊樹木丹青古，詰曲汀沙篆籀工。", "昏曉之分含一氣，乾坤底處是全功。", "西南佳境冥搜遍，總合亭前立下風。"]'),
('45b131c5-81df-49a0-951d-2f3023055eb9','題江東陳氏江亭','程公許','宋','宋诗','song-poetry','','[]','漁艇閒撐過水東，亂雲含雨晚溟濛。',64,'全唐诗/poet.song.194000.json','["漁艇閒撐過水東，亂雲含雨晚溟濛。", "絕憐郊墅依林壑，更拓軒窗貯竹風。", "剩與烟波開靄杳，却須菑翳略疎通。", "閒居可忍虛吟嘯，載酒來時社友同。"]'),
('9a4c23df-355f-4c27-ae2f-d45dbf314cf0','題巴東縣秋風亭','程公許','宋','宋诗','song-poetry','','[]','萬山寂寂巴東縣，千古堂堂寇長官。',64,'全唐诗/poet.song.194000.json','["萬山寂寂巴東縣，千古堂堂寇長官。", "野水可無詩問訊，秋風長對淚汍瀾。", "著樓無地儘渠詫，折箠立功非我難。", "君看公安一梢竹，向來許國寸心丹。"]'),
('5da1a17b-3936-4faa-884a-317e796832cf','同楊景韓飲虞獻子江亭用壁間文與可韻','程公許','宋','宋诗','song-poetry','','[]','晴灘屬玉翫烟霏，照眼琅玕碧四圍。',64,'全唐诗/poet.song.194000.json','["晴灘屬玉翫烟霏，照眼琅玕碧四圍。", "堂蔭白茅娛子美，江吟凈練憶玄暉。", "誰家鼓吹觀遊去，何處笭箵罷釣歸。", "尚想江南圖畫裏，風帆夜落道人磯。"]'),
('d8f1d6ea-64de-41fb-bbd9-1cb0f32bc600','自七曲祠下乘馬至上亭二首  其一','程公許','宋','宋诗','song-poetry','','[]','征鞍不怕朔風顛，攬盡魚鳬氣脈全。',64,'全唐诗/poet.song.194000.json','["征鞍不怕朔風顛，攬盡魚鳬氣脈全。", "秦嶺劍攢青不斷，潼江带小碧相連。", "五雲樓殿元皇宅，一柱西南半壁天。", "分職幽明兩無愧，玉關快馬洗風烟。"]'),
('e5102f91-a6f0-4cb3-9783-d0f38598b1c0','自七曲祠下乘馬至上亭二首  其二','程公許','宋','宋诗','song-poetry','','[]','仗衛森嚴九虎關，從前錯爲敵人寬。',64,'全唐诗/poet.song.194000.json','["仗衛森嚴九虎關，從前錯爲敵人寬。", "那知黄竹瑶池夢，歷盡青天蜀道難。", "回首烟塵三輔隔，驚心風雨五更寒。", "淋鈴一曲上亭驛，好並千秋金鏡看。"]'),
('da38b3d4-6c34-4111-b62d-b631f5b66fd9','宿驛亭和前韻末句屬可道','程公許','宋','宋诗','song-poetry','','[]','千里因人作遠遊，一番風景釀清秋。',64,'全唐诗/poet.song.194000.json','["千里因人作遠遊，一番風景釀清秋。", "眼明驚羽新碕岸，心折狼烟舊戍樓。", "山驛解鞍才晚霽，夜床驚雨滾溪流。", "壁間唐律須揚搉，却恨宗風隔果州。"]'),
('96ce4801-eb30-489a-a8fc-840afc1e9437','遊玉林午飯九曲池觀偃松過法華院至上方觀東坡題柱晚至沈氏小玲瓏施兄携酒來會施本成都人僑居湖三世矣','程公許','宋','宋诗','song-poetry','','[]','玉林散策才亭午，九曲流觴對偃松。',64,'全唐诗/poet.song.194000.json','["玉林散策才亭午，九曲流觴對偃松。", "脫盡皮膚見真實，卧看桃李競丰容。", "上方細看錐沙刻，丈室連澆玉乳濃。", "蜀客相逢天萬里，不妨暖酌小玲瓏。"]'),
('b87f678e-9fd4-449c-aeec-1add4b29a27a','劍門','程公許','宋','宋诗','song-poetry','','[]','壯心低劍類龜藏，北度關山稍激昂。',64,'全唐诗/poet.song.194000.json','["壯心低劍類龜藏，北度關山稍激昂。", "誰遣五丁通蜀險，擘開雙劍倚天長。", "山川豈爲姦雄誤，形勢終歸道德强。", "輸與雲遊癡寶誌，巖前冷看幾興亡。"]'),
('f35f1bd0-2c25-4aa0-b38d-03c459e2db6c','過萬里橋辛巳春仲二十五日送別先君於此俛仰四年不勝感愴','程公許','宋','宋诗','song-poetry','','[]','漲綠平堤萬里橋，安輿欲去此遲留。',64,'全唐诗/poet.song.194000.json','["漲綠平堤萬里橋，安輿欲去此遲留。", "了知薪盡無餘火，猶復情癡認刻舟。", "終古不磨方寸恨，深恩未有一分酬。", "回頭菽水中年樂，擁袂汍瀾涕莫收。"]'),
('04149fc5-82ff-47f1-800e-773b10c23fef','曉過羅江縣','程公許','宋','宋诗','song-poetry','','[]','霽雲破曉湧金盤，夙駕馳驅萬古安。',64,'全唐诗/poet.song.194000.json','["霽雲破曉湧金盤，夙駕馳驅萬古安。", "雲蓋展開山色潤，羅紋蹙動水光寒。", "周遭曲港柳彫碧，點綴遥林楓渥丹。", "游子莫誇工覓句，竟輸老衲一蒲團。"]'),
('6fe1ef81-1fd2-42e6-8190-56749fece4b0','東川懷古','程公許','宋','宋诗','song-poetry','','[]','平生不踏東川路，乘興春風爛漫游。',64,'全唐诗/poet.song.194000.json','["平生不踏東川路，乘興春風爛漫游。", "文冢姓名懸日月，書堂冤憤慘林丘。", "欲呼千載醉魂起，那復少陵詩句遒。", "啼鳥不知人意緒，弄晴剛自說春愁。"]'),
('6b9c030a-7cae-48ca-b08b-a4e0c59e3456','步自南定樓至海觀','程公許','宋','宋诗','song-poetry','','[]','南定樓西徑女牆，等閒傑觀借相羊。',64,'全唐诗/poet.song.194000.json','["南定樓西徑女牆，等閒傑觀借相羊。", "山連六詔夐深阻，城挾三江交淼茫。", "薄晚渡船人意急，清秋倚檻客情荒。", "乾坤殺氣凄凉甚，浮海吾寧逐磬襄。"]'),
('dda6dd55-841e-4a8d-a628-1673d4847c42','浙江觀潮','程公許','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','浙岸携觴差一日，秋風吹爽軼層霄。',64,'全唐诗/poet.song.194000.json','["浙岸携觴差一日，秋風吹爽軼層霄。", "怒濤奮擊三千里，壯觀元同十八潮。", "蓬閬何曾雲海隔，偓佺未散玉京潮。", "琴高背穩容追逐，借與天風遞玉簫。"]'),
('293fcd40-5d3d-4791-ab9b-1c77223133fb','十日祭先農拂曉過劉寺','程公許','宋','宋诗','song-poetry','','[]','喔喔晨鷄喚出城，籃輿兀睡忽天明。',64,'全唐诗/poet.song.194000.json','["喔喔晨鷄喚出城，籃輿兀睡忽天明。", "偶因半路松招客，始覺空山雨未晴。", "蘸水一梢偏韻勝，攙空萬壑自天成。", "奉祠猶得搜奇觀，始信容臺職最清。"]'),
('73a55920-2536-4084-af36-a742012fb8ed','綿竹大中祥符寺通悟聖師所創寺前老柏係師手植因賦此','程公許','宋','宋诗','song-poetry','','[]','六百年前事異哉，二龍委骨致瓌材。',64,'全唐诗/poet.song.194000.json','["六百年前事異哉，二龍委骨致瓌材。", "雖然懸讖識興廢，要以無心爲去來。", "寺裏塔模天竺樣，門前柏是聖師栽。", "若將鴈嶺較喧寂，寂定光中定一咍。"]'),
('a1e3a1cb-623a-4f9e-823f-d64a0aeee713','賦柳池寺護國靈泉','程公許','宋','宋诗','song-poetry','','[]','忍淚淋泠過上亭，柳池泂酌重消魂。',64,'全唐诗/poet.song.194000.json','["忍淚淋泠過上亭，柳池泂酌重消魂。", "脫身蜀道千山險，屈指開元幾葉孫。", "鴆毒由來藏袵席，瘡痍未易補乾坤。", "行人但賞三泉冷，興替相尋可復論。"]'),
('496f6e0d-8a7d-4f4a-8670-eb396cb51294','借宿靈隠翌旦曉粥後步遊上竺','程公許','宋','宋诗','song-poetry','','[]','華鯨吼粥月朦朧，滿意枝筇落手中。',64,'全唐诗/poet.song.194000.json','["華鯨吼粥月朦朧，滿意枝筇落手中。", "金碧三分靈鷲嶺，烟雲高峙補陀峰。", "一貧未辦莊嚴供，九品堅持憶念功。", "欲問耳根參透處，曉寒山靜數聲鐘。"]'),
('69811e0d-204c-42cd-a301-338f8edda8d5','題總持寺','程公許','宋','宋诗','song-poetry','','[]','息臺山上最高峰，異事相傳管氏童。',64,'全唐诗/poet.song.194000.json','["息臺山上最高峰，異事相傳管氏童。", "檀幣昔嫌三窟擅，齋盂今喜十方同。", "中宵急灑竹間雨，萬壑俄喧松下風。", "欲記徽絃寫心事，賞音喚起石林翁。"]'),
('bfff37c7-71f8-4337-a1a6-0c62295ca207','題羅江雲蓋寺二首  其一','程公許','宋','宋诗','song-poetry','','[]','雲蓋山前往返頻，過門不入愧山靈。',64,'全唐诗/poet.song.194000.json','["雲蓋山前往返頻，過門不入愧山靈。", "晚烟莽蒼亂流去，夜雨淋浪欹枕聽。", "遍索寺碑尋往話，但餘轍跡護禪扃。", "老權有句堪呈佛，誰爲援毫刻翠屏。"]'),
('29cc8744-095c-4b28-9692-ce40a06d2edf','題羅江雲蓋寺二首  其二','程公許','宋','宋诗','song-poetry','','[]','處處名山屐齒留，儘忙也合此閒游。',64,'全唐诗/poet.song.194000.json','["處處名山屐齒留，儘忙也合此閒游。", "重樓高壓青螺頂，二水橫分白鷺洲。", "歲月儘饒僧結足，風烟耐與客消愁。", "紅塵岐路重回首，車轂憧憧古益州。"]'),
('00d14e11-9b0b-489d-8f78-92221250f76f','遊永康靈巖寺','程公許','宋','宋诗','song-poetry','','[]','詰曲山蹊遠世氛，荒寒古寺薦爐熏。',64,'全唐诗/poet.song.194000.json','["詰曲山蹊遠世氛，荒寒古寺薦爐熏。", "清泉迸石韻寒玉，翠邏倚天施白雲。", "半藏石經真健婦，一龕古貌現聲聞。", "遲留恐遇魚鳬叟，嵐靄浮空日易曛。"]'),
('35b1ef42-8d45-4293-b553-2bd0acc68135','覽鏡鬢間兩三點雪','程公許','宋','宋诗','song-poetry','','[]','志士傷心髀肉生，寒儒努力在青春。',64,'全唐诗/poet.song.194000.json','["志士傷心髀肉生，寒儒努力在青春。", "課書恨失囊螢聚，覽鏡驚呼鬢雪新。", "歲晚何妨勤秉燭，行迷猶可復通津。", "餘功剩暖丹爐火，莫待幽人喚孔賓。"]'),
('70151597-60d1-4bae-ad6d-ce0505f7e986','和程使君勞農仙雲山拜揚子雲像蔣丞相墳','程公許','宋','宋诗','song-poetry','','[]','使君文采郁卿雲，聲利場中三沐薰。',64,'全唐诗/poet.song.194000.json','["使君文采郁卿雲，聲利場中三沐薰。", "繭紙晝閒臨晉帖，魚膏夜永課皇墳。", "劭農懇惻車頻駐，弔古凄凉酒易醺。", "笑我坐窗甘獨冷，吟情强半被愁分。"]'),
('04f345dd-0451-4888-8015-61a1f85b165b','挽虞提幹仲房','程公許','宋','宋诗','song-poetry','','[]','滄江亭上極綢繆，况復蘭階託勝游。',64,'全唐诗/poet.song.194000.json','["滄江亭上極綢繆，况復蘭階託勝游。", "邂逅磬川分別袂，傳聞邊邑費良籌。", "諸公推上青雲轂，一夢驚移夜壑舟。", "生死交情那忍負，霜風吹淚錦江頭。"]'),
('ccbe64f3-1620-4cb3-9477-eada37c27d8a','挽廖山父','程公許','宋','宋诗','song-poetry','','[]','忘年幸接使君游，仲氏論交意最稠。',64,'全唐诗/poet.song.194000.json','["忘年幸接使君游，仲氏論交意最稠。", "桂蘤方看霏月露，蘭芽何遽隕霜秋。", "遺編薈粹兼三傳，英氣崢嶸閟一丘。", "忍見翣車隨二老，彭殤試與問莊周。"]'),
('3ae09c25-5b4e-4e50-8759-ec8084f2e5cc','挽順慶使君寶章李十三丈二首  其一','程公許','宋','宋诗','song-poetry','','[]','東齋嫡子巽巖孫，醖釀詩書氣味醇。',64,'全唐诗/poet.song.194000.json','["東齋嫡子巽巖孫，醖釀詩書氣味醇。", "桃李七州春不盡，松筠一節晚彌新。", "恤章峻直寧王寶，治行高推漢吏循。", "四尺墳前千字誄，清名不與跡俱陳。"]'),
('abf83be2-cc29-4f26-93e2-59ba033d0394','挽順慶使君寶章李十三丈二首  其二','程公許','宋','宋诗','song-poetry','','[]','金相玉質素心降，每見令人折幔幢。',64,'全唐诗/poet.song.194000.json','["金相玉質素心降，每見令人折幔幢。", "亦有薦敭當使傳，若爲淹泊只侯邦。", "款門心訝三醫謁，藏壑舟驚半夜扛。", "搔首薰風丹旐舉，些歌凄斷不成腔。"]'),
('f9c3140f-9256-4516-b0b4-5a0d909968f6','覺空寺','程公許','宋','宋诗','song-poetry','','[]','箯輿選勝暑風輕，渺渺西岑得化城。',64,'全唐诗/poet.song.194000.json','["箯輿選勝暑風輕，渺渺西岑得化城。", "應供佛元無住相，教忠皇爲錫嘉名。", "竹窗櫛髮晨光薄，松徑褰裳午蔭清。", "安得一單長寄此，跏趺靜看篆香縈。"]'),
('5da68a81-8d19-4557-bbad-6b52a0dfd524','謁普德崈德懃濟三祠','程公許','宋','宋诗','song-poetry','','[]','冠建芙蓉佩綴瓊，水沉馥袂謁靈君。',64,'全唐诗/poet.song.194000.json','["冠建芙蓉佩綴瓊，水沉馥袂謁靈君。", "支分一道岷山雪，鼎峙三宮玉壘雲。", "露積大田雙象鼻，駿奔全蜀萬羊羣。", "百年征調何當息，乞與乾坤凈戰氛。"]'),
('0529d787-d64c-4b1a-9f9d-80ef2c138088','謁周孝公祠','程公許','宋','宋诗','song-poetry','','[]','斬蛟潭近款叢祠，逸少行書小陸碑。',64,'全唐诗/poet.song.194000.json','["斬蛟潭近款叢祠，逸少行書小陸碑。", "穹壤英名長不泯，烝嘗故里有餘思。", "排門簫鼓競禳賽，挾彈羅紈羣笑嬉。", "煮酒流霞魚饌玉，荆溪可欠我題詩。"]'),
('88956cac-0f3f-4ea0-9960-70af04ded965','臘月二十六日部宿雪甚登天官廳後亭子','程公許','宋','宋诗','song-poetry','','[]','衝寒趁襆青綾被，奇事粧成白粉闈。',64,'全唐诗/poet.song.194000.json','["衝寒趁襆青綾被，奇事粧成白粉闈。", "老怯憑高銀海眩，渴因引滿玉池肥。", "七旬蜀道才通信，兩月淮壖未解圍。", "澒洞憂端深似海，鬢霜爭與六花飛。"]'),
('b44caac1-9f7e-401c-a844-27f2140e8e75','成都蕭寺度臘即事示彥威姪二首  其一','程公許','宋','宋诗','song-poetry','','[]','瀟洒僧廬蹔此留，靜看急景意悠悠。',64,'全唐诗/poet.song.194000.json','["瀟洒僧廬蹔此留，靜看急景意悠悠。", "戲呼道韞詠飛絮，况有阿戎同頌椒。", "三考癡頑成底事，一同親愛外何求。", "囊無儲俸貧如舊，謾整圖書訊便舟。"]'),
('dc3485ae-409c-4ae2-8fa5-a6d35d73bec8','成都蕭寺度臘即事示彥威姪二首  其二','程公許','宋','宋诗','song-poetry','','[]','掣電光陰不可追，回頭四十九年非。',64,'全唐诗/poet.song.194000.json','["掣電光陰不可追，回頭四十九年非。", "萬緣勘破姑隨順，至道精探識指歸。", "感慨未能忘世慮，因循深恐悞時機。", "寒窗細話經綸策，來歲昕廷爲發揮。"]'),
('3803a456-81c9-43d4-9723-2fc0840d6a14','同二姪一甥游靈隠凈慈寺','程公許','宋','宋诗','song-poetry','','[]','韶華倏已三旬過，南北山分兩日游。',64,'全唐诗/poet.song.194000.json','["韶華倏已三旬過，南北山分兩日游。", "翠邏晚寒催暖酒，綠楊風軟緩移舟。", "無多官事妨行樂，有許吟情奪隠憂。", "三揖孤山林處士，泰和容許隠巢由。"]'),
('1de87836-ec0c-4195-aab4-b28b37158e41','金山寺','程公許','宋','宋诗','song-poetry','','[]','畫圖省識金山面，短褐風吹入畫圖。',64,'全唐诗/poet.song.194000.json','["畫圖省識金山面，短褐風吹入畫圖。", "玉鏡臺空螺髻直，海潮音散蜃樓孤。", "歸田擬共江神約，鼓枻容追越相逋。", "百一十城才發軔，指南端不負文書。"]'),
('d98c7dae-0035-476c-ad17-9840a0ae49a0','熙老拉泰叔同伴山行由馬溪寺攀躋險絕歷龍洞上羅漢洞洞前小菴極幽邃下有龍潭潭水窈深一綠蟾蜍踞坐石間意若神龍守護者抵暮還憩雙峰閣看十三夜月和泰叔韻','程公許','宋','宋诗','song-poetry','','[]','扶携羅漢洞前去，誰信此中天地寬。',64,'全唐诗/poet.song.194000.json','["扶携羅漢洞前去，誰信此中天地寬。", "澗水翻成千偈快，嶺雲肯放一塵干。", "倚巖菴好無僧住，積石潭深照影寒。", "歸對雙峰看月吐，薇花浴露色如丹。"]'),
('c8ad8296-a51a-42a2-8090-7f064fb3ef17','訪雲端菴居','程公許','宋','宋诗','song-poetry','','[]','夢想雲端路屈盤，幽尋今果到雲端。',64,'全唐诗/poet.song.194000.json','["夢想雲端路屈盤，幽尋今果到雲端。", "三間矮屋烟霏擁，一片閒情宇宙寬。", "土銼間搜靈藥煮，天壇不遣篆香殘。", "誰能好事時供給，結足空山也不難。"]'),
('e10b82e2-bb7d-404d-aa3c-907e5da4e2ed','叔存姪伯仲拉登平蓋觀','程公許','宋','宋诗','song-poetry','','[]','彭模來往無虛歲，平度山纔一度游。',64,'全唐诗/poet.song.194000.json','["彭模來往無虛歲，平度山纔一度游。", "卜宅舊傳楊蜀郡，題詩宛在薛嘉州。", "江雲杳靄吞天遠，松檻蕭寒喚客留。", "欲與殊庭追古意，略須桃杏植巖幽。"]'),
('5d7f0109-364f-4f72-81c5-06049e3028a4','長生觀拜謁碧落侍中觀巨楠','程公許','宋','宋诗','song-poetry','','[]','功行三千未易圓，活人陰德最爲先。',64,'全唐诗/poet.song.194000.json','["功行三千未易圓，活人陰德最爲先。", "一瓢酒釀春江醁，百尺楠藏洞府天。", "道骨想從玄祖受，高風應許裔孫傳。", "珥貂碧落猶官府，何似鞭鸞陪散仙。"]'),
('e03f10cb-b634-4d77-ad67-286d9b93193a','八月十日夜夢登青城最高峰醮仙官醮罷同羽士二三人散策月下濯足澗水意甚適也推枕惘然紀以唐律','程公許','宋','宋诗','song-poetry','','[]','崷崒孤岑碧四圍，分明佳氣是祠西。',64,'全唐诗/poet.song.194000.json','["崷崒孤岑碧四圍，分明佳氣是祠西。", "星壇醮罷天如水，羽褐追遊月滿溪。", "真境可容兵劫壞，天涯長恐夢魂迷。", "烟霞舊侶今誰在，還肯丹梯手共携。"]'),
('ae93ec4a-d051-4b39-b6dc-8a082e24dfc4','九月晦齋宿太一宮都監姚高士示劉長翁及湯仲能諸公唱酬詩軸因和韻二首  其一','程公許','宋','宋诗','song-poetry','','[]','擾擾東華車馬塵，烟霞何日拂衣襟。',64,'全唐诗/poet.song.194000.json','["擾擾東華車馬塵，烟霞何日拂衣襟。", "空花想已銷浮念，枯木猶能發至音。", "白鶴不來紅日暮，金鱗自躍碧潭深。", "五千言外無餘旨，苦更研朱學洗心。"]'),
('e65a7bfa-f95b-4c1a-aeef-3c967739750c','九月晦齋宿太一宮都監姚高士示劉長翁及湯仲能諸公唱酬詩軸因和韻二首  其二','程公許','宋','宋诗','song-poetry','','[]','孤雲蹤跡混風塵，藹藹陽和滿一襟。',64,'全唐诗/poet.song.194000.json','["孤雲蹤跡混風塵，藹藹陽和滿一襟。", "招得鴛班同勝賞，肯教牛鐸嗣清音。", "菴當黛面雪霜峭，洞鎖玉臺烟雨深。", "何日與師携手去，胎仙同看舞琴心。"]'),
('d8cd7152-8011-454c-9c36-a5f509abeac4','祝聖清旦登星壇唱步虛下壇曉霧四開晴景熙然','程公許','宋','宋诗','song-poetry','','[]','峻極先峰接絳霄，佩環催肅大昕朝。',64,'全唐诗/poet.song.194000.json','["峻極先峰接絳霄，佩環催肅大昕朝。", "步虛杳渺吟崆峒，飈馭依稀駐鬰蕭。", "擬效嵩呼騰漢闕，細聽天籟響虞韶。", "班回徙倚危欄望，紅日初昇宿霧消。"]'),
('89ef41f9-e343-4b18-9239-3e069debd5b5','山中醮後一日雨雪仍留山中霧雨溟濛混然如一氣未分也','程公許','宋','宋诗','song-poetry','','[]','香霧回翔八景輿，帝觴邀我適華胥。',64,'全唐诗/poet.song.194000.json','["香霧回翔八景輿，帝觴邀我適華胥。", "戲將餘瀝作零雨，旋有六花飛太虛。", "意恐混淪凝祖氣，心疑圓嶠沒歸墟。", "題詩不作人間語，呵手殘爐小楷書。"]'),
('11118402-c810-4370-8445-44196bdccaef','登伏龍觀看雪和張權父韻','程公許','宋','宋诗','song-poetry','','[]','暖日噓雲釀六霙，一元亭毒歲功成。',64,'全唐诗/poet.song.194000.json','["暖日噓雲釀六霙，一元亭毒歲功成。", "霓裳舞散廣寒殿，鶴氅朝回七寶城。", "决雨會看三月漲，屯邊全要萬倉盈。", "離堆邂逅成奇觀，一笑能令萬慮輕。"]'),
('ef786456-ac95-4762-bf31-671155694f4d','行黑水谷三十里以耳目聞見有賦','程公許','宋','宋诗','song-poetry','','[]','自過三泉境，紆回谷道中。',120,'全唐诗/poet.song.194000.json','["自過三泉境，紆回谷道中。", "居民雖漸復，生理頓成空。", "敗屋翳蒿逕，頹牆荒棘叢。", "稻田多宿莽，麥隴間鋪茸。", "耕織豈當廢，傷殘甘忍窮。", "遑憐已死骨，使得掩幽宮。", "梨粉偏饒白，桃腮也自紅。", "羈游愁滿眼，感憤氣填胸。", "家計艱營葺，人謀有異同。", "熟爲根本慮，無使浪施功。"]'),
('5098a2a9-fc9e-41ad-ace9-294f0bcdad4a','大雪同楊景韓程子敬登寺樓','程公許','宋','宋诗','song-poetry','','[]','雪中佳士集，同倚寺樓看。',72,'全唐诗/poet.song.194000.json','["雪中佳士集，同倚寺樓看。", "晁蕩迷滄海，空明迫廣寒。", "重城和氣浹，萬井語聲歡。", "瑞接三冬白，憂寬一寸丹。", "漁船尋剡曲，戰馬渡桑乾。", "天意俱慳與，無氈分冷官。"]'),
('ae14ea49-e368-4d5c-820c-f585fc1c6cac','遊東坡和柯山潘邠老舊賦','程公許','宋','宋诗','song-poetry','','[]','恭惟廊廟具，歲晚落江湖。',240,'全唐诗/poet.song.194000.json','["恭惟廊廟具，歲晚落江湖。", "豈不三緘舌，深慙七尺軀。", "若爲周士貴，翻作楚囚拘。", "詩款催供上，皇聰莫可呼。", "孔融成幸免，柳子豈真愚。", "瓢酒那能醉，叉錢可得腴。", "貧雖無四壁，夢不到清都。", "赤壁一枝笛，寒溪十幅蒲。", "故交同縞紵，廢壘借耰耡。", "未分徑爭捷，可憐錐也無。", "是非端自定，流落坐成迂。", "四海老泉水，一時丹穴雛。", "士皆憐大器，手不轉洪樞。", "擬問靈蓍卜，難憑造化爐。", "喑喑櫪下馬，汎汎水中鳬。", "富貴危探虎，烟波夢釣鱸。", "定知鏗舍瑟，終不亂吹竽。", "榛莽開金地，江山稱畫圖。", "何當麾斗柄，相與第天吳。", "生世須如此，不然非丈夫。"]'),
('cb269295-92f3-49b8-9faa-b7f087158d0c','送憲使江寺簿赴召','程公許','宋','宋诗','song-poetry','','[]','沃野三千里，春風十六城。',288,'全唐诗/poet.song.194000.json','["沃野三千里，春風十六城。", "顧憂寧易釋，遣送定非輕。", "憶昔光華賦，隨軒老稚迎。", "根株探吏蠹，疴癢察人情。", "漢網寧疏漏，周原數按行。", "堰渠豐䆉稏，犴戶絕笞榜。", "六詔寂無警，三農容雜耕。", "與民爲父母，斂惠到孤惸。", "江漢今猶昔，人才世載英。", "頹流無砥柱，公道莽榛荆。", "能使薰蕕別，端由藻鑑明。", "綱條雖整肅，襟度乃恢宏。", "行路無思犯，濡絲已載賡。", "前旒應渴見，方底趣終更。", "豈有坳堂水，能容碧海鯨。", "佇翔幽谷羽，入囀上林鶑。", "聞道宗風媺，推高月旦評。", "榮非同象笏，愛亦異金籯。", "博士尤姱節，端公更直聲。", "流芳鎸琬琰，仍世盛簪纓。", "早並膠庠彥，同爲館下生。", "詩書勤澡濯，聲譽響鏗鍧。", "棘路仙班近，麻壇守紱榮。", "徒勞將使指，未足展修名。"]'),
('ea4c5222-38af-4c22-9741-008e6d89cd7a','又上座主李左史八十韻','程公許','宋','宋诗','song-poetry','','[]','江路三年別，心旌萬里摇。',288,'全唐诗/poet.song.194000.json','["江路三年別，心旌萬里摇。", "登龍空有夢，蟄蟻困無聊。", "側聽除書峻，深期廟論調。", "方看儀玉筍，胡遽理蓀橈。", "在昔推華族，於今壯本朝。", "談遷承緒遠，坡潁更難超。", "江漢英風迥，堪輿間氣饒。", "文傳千戶印，和備九成簫。", "撼地喧雷鼓，當空插斗杓。", "靈龜韜遠見，瘦鶴峙孤標。", "久矣駑陵驥，凄其鵠避鵰。", "與時爲準的，立己有科條。", "蚤歲趨嚴詔，修名聳百僚。", "青藜窺夜讀，紈箑障塵飄。", "洊綰藩侯紱，連驅使者軺。", "通才期用世，所至藹騰謠。", "將略雄諸葛，皇靈格有苗。", "帝思前席問，命下賜環招。", "敷奏趨丹陛，疏榮逼紫霄。", "一朝驚玉立，三館看纓彯。", "曉露坳螭潤，春風砌藥嬌。", "倚才兼夕拜，專對禠天驕。", "草詔鑾坡夜，橫經鶴禁朝。", "紫荷班已峻，黄閣路非遥。"]'),
('53dfff14-18b6-490b-932b-45ac7f39290c','上曹憲使五十韻','程公許','宋','宋诗','song-poetry','','[]','驥不稱其力，文當與德兼。',288,'全唐诗/poet.song.194000.json','["驥不稱其力，文當與德兼。", "褊能多悻悻，小器或惉惉。", "行世吾誰與，窺公意自厭。", "秉心溫以恪，植操靜而廉。", "信矣天資媺，加之學力漸。", "巖巖疑壁立，灧灧乃淵潛。", "李杜波瀾闊，黄陳律令嚴。", "鏗鈜諧律呂，璀璨溢緗縑。", "振采賢關闢，疏榮物議僉。", "董帷終日下，戴席幾重添。", "江漢荆之望，龜蒙魯所瞻。", "鷁飛俄引却，蝶夢一何恬。", "萬里紆朱紱，孤峰對白鹽。", "清吟憑月檻，長嘯倚風簷。", "偶過伊川洞，高褰刺史襜。", "簡寬疏訟缿，惻怛到窮閻。", "治行流江海，除書降陛廉。", "六條頒屬部，五聽察蒼黔。", "紫塞塵方暗，紅巾黨未殲。", "人情彌震洶，鄰境倍危阽。", "所恃福星照，能令妖焰熸。", "民皆欣抃手，公亦笑掀髯。", "鳳綍搜才切，驪珠信手拈。", "春雷掀舊蟄，秋月吐新蟾。"]'),
('d0e35d4c-fb64-4738-b0ae-0c1466c93b8c','上瀘州楊尚書四十韻','程公許','宋','宋诗','song-poetry','','[]','清瑩玻璃水，巉巖石筍峰。',288,'全唐诗/poet.song.194000.json','["清瑩玻璃水，巉巖石筍峰。", "孕才供世用，有道致時雍。", "閥閲宋清節，源流唐靖恭。", "異時先太史，司匭事光宗。", "忠憤排黄闥，憂危溢皁封。", "扶顛重立極，涉筆但司農。", "餘地勤菑穫，連城薦璧琮。", "羽毛參薛鳳，頭角半荀龍。", "赫奕誇分鼎，鏗鍧響大鏞。", "雲霄才直上，時運快遭逢。", "袖馥麋丸賜，芸繙蠹簡重。", "亨衢無齟齬，按轡獨從容。", "監寺雖平進，班行歎乏供。", "賜茶經幄暝，濡筆殿坳彤。", "曉陛荷囊擁，春墀革履跫。", "時來如邂逅，慮遠妙彌縫。", "霖雨睿思渴，雲山歸興濃。", "入辭親黼座，宣勸灩金鍾。", "可使安耕稼，無勞訪枸筇。", "錦衣華故里，茸纛拂遐衝。", "龍駕攀無及，烏號涕莫從。", "嗣皇初訪落，達孝極思庸。", "故老尤紆眷，庭臣孰比蹤。", "威名震滇僰，治體嗣黄龔。"]'),
('3287fc70-bbea-48fb-b0d5-45037645c8c4','壽茶使三十韻','程公許','宋','宋诗','song-poetry','','[]','湖海裒英氣，星凰瑞聖朝。',288,'全唐诗/poet.song.194000.json','["湖海裒英氣，星凰瑞聖朝。", "黄鍾回暖律，紫毳下層霄。", "平武登巍選，高才局下僚。", "一朝翻渤海，萬里羾扶摇。", "遷次更州牧，澄清奉漢條。", "帑藏參會計，閫寄竦嫖姚。", "帝想重關阻，雲連八水遼。", "近知敵運盡，不復舊時驕。", "遣送紆天寵，將輸伏使軺。", "艱難須力濟，氛祲覺潜銷。", "還把天隅繡，來題駟馬橋。", "留良無復恨，擷秀自應饒。", "倚重藩條布，尤先政理調。", "根株探吏蠹，襦袴藹民謠。", "流地金錢溢，褰風錦幄飄。", "異時司榷牧，永日但逍遥。", "誰似躬行美，能知燕處超。", "兵厨疎螘味，訟牘列牛腰。", "苦節同儒素，清風起俗囂。", "世途猶梗塞，士氣况陰消。", "竭澤無餘算，何時罷擊刁。", "定知虛宁久，可卜賜環招。", "經世須材略，猶農力蔉穮。", "牧時宜解瑟，渴治急聞韶。"]'),
('bf709f66-c6ca-43de-aa4d-8f59f780c826','餞秘書郎劉侯出守龍舒分韻得亭字','程公許','宋','宋诗','song-poetry','','[]','皖伯疏封有故城，新堂猶寶李翺銘。',192,'全唐诗/poet.song.194000.json','["皖伯疏封有故城，新堂猶寶李翺銘。", "三峰秀出塵區外，二水空流戰血腥。", "在昔建邦專地勢，祇今誤計寄沙汀。", "集鴻底處容棲宿，冠鶡何人稱使令。", "輪對適當三館彥，忠純能聳四聰聽。", "俄聞命綰邦侯組，應是名題御坐屏。", "地有險夷何可擇，事方艱棘不遑寧。", "扶持羸憊爲耕叟，收斂奸雄作戰丁。", "遺愛重尋朱邑廟，壯圖仍訪呂蒙亭。", "可能舊觀珠還浦，試拓新規刃發硎。", "少待烽烟清紫塞，却持筆橐侍彤庭。", "男兒莫作分携恨，勳業相期汗簡青。"]'),
('13164484-8d44-4d3f-98e1-837d5c12ac45','代壽李參預鴈湖先生五十韻','程公許','宋','宋诗','song-poetry','','[]','仙李蟬嫣系緒長，丹崖譜牒自曹王。',384,'全唐诗/poet.song.194000.json','["仙李蟬嫣系緒長，丹崖譜牒自曹王。", "滔滔江漢流波漫，濯濯芝蘭奕葉芳。", "陵井已偕儒術顯，巽巖尤擅史才良。", "榆枌倍借千鈞重，閥閲高騰萬丈光。", "在昔五之皆瑞晉，祇今三薛共推唐。", "何人說似公初誕，趺坐從來見未嘗。", "不是老聃鍾瑞異，也應太白減精芒。", "直從上界飄霞佩，來向塵寰艷織襄。", "疑夢無因嗤衛玠，問炊不餡比元方。", "鯉庭早熟蘭膏讀，蟾窟濃分桂子香。", "秘館繙書推博洽，著庭紬史極精詳。", "歸來兩郡驅紅旆，還入修門荷紫囊。", "議禮挽回周典制，代言直似漢文章。", "一朝誰作兵端啟，萬里應勞使指將。", "射鴈子卿歸亦幸，棄豚竇憲勢方張。", "披肝九陛獰羣吠，回首三邊已戰場。", "妙選何心榮寵利，扶顛有意爲周防。", "事難忍作抽身計，幾密方明疾惡腸。", "鸞鳳得朋應漸集，鴟鴞鎩羽可能翔。", "魚頭熟念衣寬带，虎士歡趨氣涌湯。", "詔下九天銜袖滿，人知二府畫謀臧。", "古來所貴真儒用，天定何憂敵國强。", "刑典已先明兩觀，和盟便許復侵疆。", "論功自合專台席，讒口胡爲弄巧簧。"]'),
('16314153-64b6-423b-8922-3b41636fcdb5','送別制置董侍郎東歸','程公許','宋','宋诗','song-poetry','','[]','荷囊曉趁紫宸朝，玉立堂堂侍冕旒。',384,'全唐诗/poet.song.194000.json','["荷囊曉趁紫宸朝，玉立堂堂侍冕旒。", "帝爲蠶叢精擇帥，詔頒虎節往分憂。", "旌幢雲合三千乘，錦繡春濃六十州。", "儀鳳雅應爲國瑞，烹鮮何忍與民仇。", "陽和噓暖松州雪，膏澤長隨錦水流。", "酒賤途歌喧夜市，彘肥社鼓響春疇。", "教條寬簡難輕犯，鑑戒高明不暗投。", "建學文翁先美俗，雄邊德裕有良籌。", "若爲殿角頻憂顧，何恨天涯久逗遛。", "幾度璽書頒北闕，四時朱履簇西樓。", "神全削堊無機露，德厚如山鎮俗浮。", "邊騎誰令輕犯塞，羽書忽訝急飛郵。", "禡牙往度重關險，建旐那容一刻留。", "明月三更悲鼓角，晴烟萬竈宿貔貅。", "乘墉妄意窺吾境，奠枕何由奈敵讐。", "忠孝全軍齊縞素，嫖姚列校奮戈矛。", "金牌不與全腰膂，鐵胄安能芘髑髏。", "戰勝遊魂驚鋌鹿，凱旋享士趣椎牛。", "三秦席卷非難事，偏將星奔悵寡謀。", "坐屈戎昭親跋履，申嚴師律戢姦偷。", "人知福德如中令，誰省恩威似武侯。", "過眼七年勞節制，焦心九陛渴才猷。", "賜環笑拆封泥詔，疊鼓催裝下峽舟。", "織錦何傷讒口捷，憩棠翻作去思愁。"]'),
('f9323534-a069-484b-bfe8-9b5d639981ad','代壽安宣相','程公許','宋','宋诗','song-poetry','','[]','帝祐炎圖合中興，風雲嘉會契千齡。',320,'全唐诗/poet.song.194000.json','["帝祐炎圖合中興，風雲嘉會契千齡。", "石田旱暵須膏澤，蟄戶陰凝聳震霆。", "審象巖間同說命，絕韋聖處見羲經。", "立談解使梟羹爛，餘事能空兔窟腥。", "岌岌危機還奠枕，恢恢游刃發新硎。", "坐令含哺娛黄耈，忍使供徭困白丁。", "河带已知申漢誓，雲和聊復訪湘靈。", "歸來旌節華仁里，寄傲壺觴等大庭。", "天厭游氛侵上國，風傳飛羽警邊亭。", "汗顔何限指空血，膠柱誰云瑟可聽。", "斧鉞重開都督府，緌紳盛集小朝廷。", "白波坐壓風濤洶，黄紙恩濃雨露泠。", "重與蜀民司命脈，定知天陛渴儀形。", "着高何病棋難活，事定端如醉得醒。", "萬里車書寧久隔，三邊鼙鼓幾時停。", "西南屹立擎天柱，子午長驅建屋瓴。", "會見輿圖恢故境，便紆公衮坐頭廳。", "無窮壽福由忠赤，不朽功名付汗青。", "自笑此生同塞馬，若爲有幸列侯鯖。", "誦詩起爲蒼生賀，南極星環帝座星。"]'),
('cf8ca2e3-bd92-432a-a9a4-01290f507541','同諸友山行分袂言別五首  其一','程公許','宋','宋诗','song-poetry','','[]','共蠟登山屐，俄尋下水船。',24,'全唐诗/poet.song.194000.json','["共蠟登山屐，俄尋下水船。", "到家人怪問，滿袖挾風烟。"]'),
('a378dcfe-9ab8-421b-95b1-1a311e067734','同諸友山行分袂言別五首  其二','程公許','宋','宋诗','song-poetry','','[]','大面窈深處，神仙碧玉壺。',24,'全唐诗/poet.song.194000.json','["大面窈深處，神仙碧玉壺。", "孫郎妙心眼，催作後山圖。"]'),
('276c793a-9d4b-4d5e-8c38-77519c34a78c','同諸友山行分袂言別五首  其三','程公許','宋','宋诗','song-poetry','','[]','神都旬浹住，大面欠窮探。',24,'全唐诗/poet.song.194000.json','["神都旬浹住，大面欠窮探。", "未盡山中趣，重來賦蔚藍。"]'),
('debb57ea-72d2-41ea-9e4a-5a8483a11779','同諸友山行分袂言別五首  其四','程公許','宋','宋诗','song-poetry','','[]','羅家隔香積，天國近花坪。',24,'全唐诗/poet.song.194000.json','["羅家隔香積，天國近花坪。", "何日同搜覽，題詩索載賡。"]'),
('9077451a-32e9-47a2-aa37-9f61892b101b','同諸友山行分袂言別五首  其五','程公許','宋','宋诗','song-poetry','','[]','名山遍宇宙，歷歷紀輿圖。',24,'全唐诗/poet.song.194000.json','["名山遍宇宙，歷歷紀輿圖。", "安得身雲水，孤筇自給扶。"]'),
('1256053e-3dff-4fa2-a027-93607befe0af','楓橋寺小憩  其一','程公許','宋','宋诗','song-poetry','','[]','雲已安排雪，天仍慘淡風。',24,'全唐诗/poet.song.194000.json','["雲已安排雪，天仍慘淡風。", "纜船投古剎，撥火共談空。"]'),
('9ef7bd28-96a5-4492-9188-5aa1881bd643','楓橋寺小憩  其二','程公許','宋','宋诗','song-poetry','','[]','寂歷少林壁，酸寒飯顆山。',24,'全唐诗/poet.song.194000.json','["寂歷少林壁，酸寒飯顆山。", "相逢如有舊，示我亦無還。"]'),
('80a675bf-cce5-4bd3-8669-bc9ef4eba15e','楓橋寺小憩  其三','程公許','宋','宋诗','song-poetry','','[]','往事驚心折，三年撚指間。',24,'全唐诗/poet.song.194000.json','["往事驚心折，三年撚指間。", "西州門外淚，華屋遽青山。"]'),
('5da8933f-1a2d-4ce4-ba3c-b42f37cf868e','楓橋寺小憩  其四','程公許','宋','宋诗','song-poetry','','[]','唐人舊吟處，古殿晝多陰。',24,'全唐诗/poet.song.194000.json','["唐人舊吟處，古殿晝多陰。", "欲去有餘戀，片雲飛碧岑。"]'),
('be518e88-98e4-474d-90b8-68bc65db3132','鎖宿餘半月得閒讀書喜而有賦  其一','程公許','宋','宋诗','song-poetry','','[]','日月疾跳丸，簡篇浩烟海。',24,'全唐诗/poet.song.194000.json','["日月疾跳丸，簡篇浩烟海。", "弓旌誤誘去，歎息可中悔。"]'),
('c5e457d1-4c60-4459-a19b-f2ddbb98765e','鎖宿餘半月得閒讀書喜而有賦  其二','程公許','宋','宋诗','song-poetry','','[]','馬瘏僕亦倦，得休苦無多。',24,'全唐诗/poet.song.194000.json','["馬瘏僕亦倦，得休苦無多。", "剝啄復剝啄，奈此分陰何。"]'),
('368c3af2-bcab-4a21-ac38-e2fbf4507080','鎖宿餘半月得閒讀書喜而有賦  其三','程公許','宋','宋诗','song-poetry','','[]','薰風鎖重棘，襆被去何勇。',24,'全唐诗/poet.song.194000.json','["薰風鎖重棘，襆被去何勇。", "私我幾日閒，此意千金重。"]'),
('dcc75fe6-8977-4eb9-9de4-becbcad34a4e','鎖宿餘半月得閒讀書喜而有賦  其四','程公許','宋','宋诗','song-poetry','','[]','晴檐蔭虛白，夜燈耿閴寥。',24,'全唐诗/poet.song.194000.json','["晴檐蔭虛白，夜燈耿閴寥。", "自憐聲吾伊，亦復如聞韶。"]'),
('ff4e3858-5007-4023-be08-33bb724efb57','鎖宿餘半月得閒讀書喜而有賦  其五','程公許','宋','宋诗','song-poetry','','[]','王事有期程，稱意不可再。',24,'全唐诗/poet.song.194000.json','["王事有期程，稱意不可再。", "寄言山中友，勿誤青衫愛。"]'),
('9f6af313-f0a4-400e-b3a9-37750f5a6724','和雁湖先生病起自警八章  其一','程公許','宋','宋诗','song-poetry','','[]','觀空得舍筏喻，示病無散花天。',28,'全唐诗/poet.song.194000.json','["觀空得舍筏喻，示病無散花天。", "從渠幻起幻滅，我自燕處超然。"]'),
('1d3f26ea-d693-4456-8345-61687a3e57ef','和雁湖先生病起自警八章  其二','程公許','宋','宋诗','song-poetry','','[]','葆光悟老子說，游仙續景純詩。',28,'全唐诗/poet.song.194000.json','["葆光悟老子說，游仙續景純詩。", "木鑽可使石透，槃水猶嚴手持。"]'),
('acf297b0-fa42-4157-bbfe-e51c1121772e','和雁湖先生病起自警八章  其三','程公許','宋','宋诗','song-poetry','','[]','專氣如嬰兒相，觀心得宿命通。',28,'全唐诗/poet.song.194000.json','["專氣如嬰兒相，觀心得宿命通。", "認取無聲無色，了知非瞽非聾。"]'),
('bde3b795-18da-472d-ae64-06c117f1e818','和雁湖先生病起自警八章  其四','程公許','宋','宋诗','song-poetry','','[]','三關中隠玉閣，七言味在蘂珠。',28,'全唐诗/poet.song.194000.json','["三關中隠玉閣，七言味在蘂珠。", "妙得養生真訣，善刀四顧躊躇。"]'),
('e289f026-7792-4dfd-b650-37b235979a67','和雁湖先生病起自警八章  其五','程公許','宋','宋诗','song-poetry','','[]','學仙寧復華念，爲士苦畏四鄰。',28,'全唐诗/poet.song.194000.json','["學仙寧復華念，爲士苦畏四鄰。", "鐵彈茅茨何在，兩翁心豈違人。"]'),
('c427e83e-3536-4592-a67e-ff8ddb65c396','和雁湖先生病起自警八章  其六','程公許','宋','宋诗','song-poetry','','[]','殘編幸出壞宅，滴露何能闡微。',28,'全唐诗/poet.song.194000.json','["殘編幸出壞宅，滴露何能闡微。", "萬古聖賢心法，未饒西竺傳衣。"]'),
('0d0e8af0-7dc5-4e4e-b30f-015635a9365a','和雁湖先生病起自警八章  其七','程公許','宋','宋诗','song-poetry','','[]','永夜朝元騫樹，蕭晨晞髮扶桑。',28,'全唐诗/poet.song.194000.json','["永夜朝元騫樹，蕭晨晞髮扶桑。", "妙處本來一貫，何異心齋坐忘。"]'),
('77129056-4e36-47b4-8fb7-2b7c8599d3c2','和雁湖先生病起自警八章  其八','程公許','宋','宋诗','song-poetry','','[]','貪夫孜孜爲利，烈士汲汲徇名。',28,'全唐诗/poet.song.194000.json','["貪夫孜孜爲利，烈士汲汲徇名。", "誰似先生元尚，名標七寶宮城。"]'),
('4a23fa33-8fbd-472a-81e0-9e36cfef0b9a','郡事多冗命繩翁拉彥翔則明德素遊趙園彥翔歸以五章示教用韻  其一','程公許','宋','宋诗','song-poetry','','[]','戰氛塞蠶叢國，决策下勝峰山。',28,'全唐诗/poet.song.194000.json','["戰氛塞蠶叢國，决策下勝峰山。", "避地客江湖久，著書無頃刻閒。"]'),
('fc8d9a4b-6223-40b2-9e4a-7ee9f9e46642','郡事多冗命繩翁拉彥翔則明德素遊趙園彥翔歸以五章示教用韻  其二','程公許','宋','宋诗','song-poetry','','[]','世溷溷爭捷徑，髮種種不勝簪。',28,'全唐诗/poet.song.194000.json','["世溷溷爭捷徑，髮種種不勝簪。", "款門恰來石友，倚檻同觀玉岑。"]'),
('893d0e93-45e8-4104-91ba-0b0ce5dee1fe','郡事多冗命繩翁拉彥翔則明德素遊趙園彥翔歸以五章示教用韻  其三','程公許','宋','宋诗','song-poetry','','[]','簡編得趣自熟，軒冕於我何加。',28,'全唐诗/poet.song.194000.json','["簡編得趣自熟，軒冕於我何加。", "喜爲勝遊着句，未須歸賦落霞。"]'),
('18791e6e-6b01-44ce-aac6-590ac7a5031c','郡事多冗命繩翁拉彥翔則明德素遊趙園彥翔歸以五章示教用韻  其四','程公許','宋','宋诗','song-poetry','','[]','俗氛妨人選勝，危坐待歸啜茶。',28,'全唐诗/poet.song.194000.json','["俗氛妨人選勝，危坐待歸啜茶。", "聽渠說山說水，撩我清夢還家。"]'),
('f24d94df-b520-4cf1-ae6e-2b952ed45261','郡事多冗命繩翁拉彥翔則明德素遊趙園彥翔歸以五章示教用韻  其五','程公許','宋','宋诗','song-poetry','','[]','浮生何適非寄，百慮非言可宣。',28,'全唐诗/poet.song.194000.json','["浮生何適非寄，百慮非言可宣。", "誰能尋訪樂土，籲天僑立西川。"]'),
