('102ea726-99a0-4747-a409-6541974dc10b','除夕和唐人張繼張祐即事四絕句  其二','程公許','宋','宋诗','song-poetry','','[]','經世無才慕管蕭，風塵搔首故鄉遥。',32,'全唐诗/poet.song.194000.json','["經世無才慕管蕭，風塵搔首故鄉遥。", "瘦藤忽夢尋梅去，裊裊寒溪獨木橋。"]'),
('efbb8053-ab9e-4fd1-9863-0fdcc9747cdc','除夕和唐人張繼張祐即事四絕句  其三','程公許','宋','宋诗','song-poetry','','[]','一笑升沉休問天，贊房贏得日高眠。',32,'全唐诗/poet.song.194000.json','["一笑升沉休問天，贊房贏得日高眠。", "五湖浪透門前港，何不乘風穩放船。"]'),
('38243a7d-2f38-488a-a6f0-108f5b124a30','除夕和唐人張繼張祐即事四絕句  其四','程公許','宋','宋诗','song-poetry','','[]','一簪華髮雪蕭蕭，流景星馳道轉遥。',32,'全唐诗/poet.song.194000.json','["一簪華髮雪蕭蕭，流景星馳道轉遥。", "撥倦寒爐雞唱曉，春風携手趙州橋。"]'),
('c1481534-4327-4b63-8941-3173d8d652fe','上後溪劉閣學','程公許','宋','宋诗','song-poetry','','[]','如來藏有大經卷，無古無今無成壞。',320,'全唐诗/poet.song.194000.json','["如來藏有大經卷，無古無今無成壞。", "卷之可納一毫端，舒之彌綸於法界。", "衆生與佛同受持，謂有定法便虛假。", "祇園食飽洗鉢坐，何曾有意一場話。", "空生强起鑿太虛，立字安名爲般若。", "三十二相不可著，况有卵胎并濕化。", "要知人與法俱空，何須到岸筏方舍。", "雙林大士更周遮，來對蕭翁閒拍報。", "至今唱頌四十九，同此經傳四天下。", "稽首後溪老尊宿，第一義諦最深解。", "以宿誓願悲濟心，具堅固力清浄戒。", "父子孫曾一道場，良窳精粗大爐冶。", "綵衣堂上春融融，後先十日𣂏壽斝。", "耆齡天爲開九袠，後學心知宗大雅。", "吾親千里意勤劬，授我軸書字端楷。", "金銀絢爛滿雲藍，是不誑語真語者。", "鬼神祕護知幾年，持以壽翁翁勿詫。", "願翁覺性日圓明，願翁眉壽備純嘏。", "如金剛體不可壞，以大方便福朝野。", "亦願吾親壽似翁，歲歲持觴拜堂下。"]'),
('d8fd1be3-7115-4517-90f7-ce427dedfda3','鴈湖先生揆初在旦某以家藏唐畫熾盛光如來像一軸祝先生壽稽首說偈云','程公許','宋','宋诗','song-poetry','','[]','十方世界香水海，如微塵數無邊億。',336,'全唐诗/poet.song.194000.json','["十方世界香水海，如微塵數無邊億。", "諸佛各以本誓願，遍坐道場作饒益。", "稽首兩足熾盛光，具有廣大神通力。", "剛風其上羅諸天，日月星宿與梵釋。", "手持宮殿充妙供，雨香花雲作嚴飾。", "慈悲爲車衆寶聚，載以萬行波羅蜜。", "周游三界一彈指，善行何曾有轍迹。", "我曾禮足持祕呪，寶繪偶得唐人筆。", "素縑一幅幾斷爛，丹青慘澹古顔色。", "巍巍趺坐寶蓮臺，冠佩環趨星拱極。", "未論畫手入何品，成壞難以有相詰。", "龍天守護敢不戒，一會靈山儼如昔。", "恭惟鴈湖老尊宿，佛地位人人不識。", "偶年與世作依怙，意倦還歸弄泉石。", "願持畫本祝修齡，往與浄名分半席。", "刀兵之劫遍大地，三界同聚一火宅。", "要須開士運悲心，立大津梁拯羣溺。", "豈同小乘專利己，塊守空山縛禪寂。", "金輪慈光耀今古，願與我公占壽籍。", "向來摩頂經授記，堅拂許令親入室。", "夜深急雪欲齊腰，不室巖前好消息。"]'),
('26c0128b-e607-413f-8e7a-44baf96e51b3','壽後溪劉侍郎','程公許','宋','宋诗','song-poetry','','[]','朱顔白髮炯雙瞳，一念平生造物通。',64,'全唐诗/poet.song.194000.json','["朱顔白髮炯雙瞳，一念平生造物通。", "內閣圖書真學士，西園几杖老仙翁。", "木公金母人間現，桂子桐孫壽籍同。", "遥想綵衣圜四世，後溪無日不春風。"]'),
('7ba560e0-e61f-49c1-9fcd-4758342c13b6','步虛蕊珠七言','程公許','宋','宋诗','song-poetry','','[]','玄蓋之天高崒嵂，自兩天眼支一脈。',387,'全唐诗/poet.song.194000.json','["玄蓋之天高崒嵂，自兩天眼支一脈。", "嶙峋四面森翠壁，中有瑶柱倚天立。", "窈窈鬰鬰仙者宅，涵雲蓄霧九鎖隔。", "石扉誰遣玉{𥫗氐}擘，通行豈虞虎豹搤。", "雲臺散吏青城客，掉頭三島風烟窄。", "南薰駕我來散策，晴天萬里展笑色。", "祖龍驅山山辟易，仙人抵住如刻劃。", "武皇情念膏火迫，宮壇經營競奚益。", "惟我章聖薦簡璧，心與天同綿寶歷。", "高皇中天定都邑，脫屣大位駐清蹕。", "至今仙館閟奎畫，跪拜締眎涕霑臆。", "大滌棲真轉石室，幽巖邃竇杳莫測。", "似聞句曲通咫尺，飈游何曾有轍跡。", "天壇可望不可陟，翠箬閃閃丹氣溢。", "我名何自標洞額，得非三生託真籍。", "一念之差甘墮謫，拊心靜慮深咎責。", "羽衣窺我慘不懌，爲我洗琖酌琥珀。", "沈沈古井龍嗜蟄，誰令怒吼捲飛帛。", "夜涼健倒風雨急，醒悟乃是巖溜滴。", "西瞻氛祲羌堛塞，玉華故棲歸未得。", "文舉遠遊記夙昔，借一菴地紬隠帙。", "百六行度運會厄，列真校錄曉繼夕。", "恫憫含生沛德澤，罷征寬斂戢鋒鏑。", "名山是處可棲逸，不材我自安社櫟。"]'),
('56a63d8e-b270-4e77-8d6c-f3b33fb29775','紅白芙蓉','程公許','宋','宋诗','song-poetry','','[]','木蕖三數株，能白又能朱。',48,'全唐诗/poet.song.194000.json','["木蕖三數株，能白又能朱。", "曉暮淺深色，醉醒容態姝。", "流霞𣂏玉斝，抽汞養丹爐。", "模寫終難盡，秋江有畫圖。"]'),
('cecd484d-1ffa-4335-8ceb-4782944691ba','曉月未沒順風泛太湖期以明日與悅齋會','程公許','宋','宋诗','song-poetry','','["\u592a\u6e56"]','明月伴我酒家眠，五更順風催放船。',112,'全唐诗/poet.song.194000.json','["明月伴我酒家眠，五更順風催放船。", "月波蕩湖湖欲溢，扶桑奪染半天赤。", "湖山破曉鬰青蒼，坐覺山與船低昂。", "少年負氣隘湖海，老雖斂縮餘習在。", "叩舷一笑宇宙寬，甕天那可差別觀。", "蒲帆瞬息幾百里，峨峨閶門尺有咫。", "五湖千古自清風，詰朝持叩伏柱史。"]'),
('c6e38c00-f138-4de1-97fc-1db434b011d3','倅教授判官皆爲東湖有賦次韻  其一','程公許','宋','宋诗','song-poetry','','[]','逶迤三徑带重湖，心眼經營念厥初。',64,'全唐诗/poet.song.194000.json','["逶迤三徑带重湖，心眼經營念厥初。", "問俗只須無事治，僝工適際有年書。", "雪融趁急栽花柳，春到隨宜辦果蔬。", "最喜城隅便來往，不嫌奔走費臺輿。"]'),
('6f6952be-8655-4c25-86f0-581c812bbd00','倅教授判官皆爲東湖有賦次韻  其二','程公許','宋','宋诗','song-poetry','','[]','交情郁穆兩監州，采藻依蓮總俊遊。',64,'全唐诗/poet.song.194000.json','["交情郁穆兩監州，采藻依蓮總俊遊。", "冰潔霜明相並照，渭清涇濁豈同流。", "虢堂擬把新題和，錦里還思故事修。", "荷蕩花溪總幽絕，賸須栽竹柰霜秋。"]'),
('f8785311-89c1-4f24-8799-2786117b1072','正之二十八日忽小霽領數客過東湖若水有賦爲次韻','程公許','宋','宋诗','song-poetry','','[]','積雨釀成寒料峭，漫遊稍覺意清真。',64,'全唐诗/poet.song.194000.json','["積雨釀成寒料峭，漫遊稍覺意清真。", "癡雲妬日吞還吐，弱柳含烟巧鬭新。", "簪屐招呼參楚蜀，肴蔬飣餖雜冬春。", "却嫌車從妨佳趣，那得臨流岸白綸。"]'),
('71508c9f-82a3-4d83-8cd4-8d578eb92533','李貳車約飲東湖','程公許','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖繞遍又東湖，永夜論文酒淺𣂏。',32,'全唐诗/poet.song.194000.json','["西湖繞遍又東湖，永夜論文酒淺𣂏。", "最愛霜林梅蘸水，擬撐小艇訪林逋。"]'),
('41aa88f8-d6bb-4dd0-a10f-99a6db29653d','范石湖東歸過鄉國名之芙蓉城余以季夏來遊適荷花稱意紅之時雁湖環湖尤甚盛李子先家小池界金數朵花品之最高者各紀以詩  其一','程公許','宋','宋诗','song-poetry','','[]','振袂芙蓉城裏游，香風十里勸人留。',32,'全唐诗/poet.song.194000.json','["振袂芙蓉城裏游，香風十里勸人留。", "瓦盆最恨廉泉陋，歸與誇張定自羞。"]'),
('c8a33529-7249-4b4c-ada0-9cd22b8bde42','范石湖東歸過鄉國名之芙蓉城余以季夏來遊適荷花稱意紅之時雁湖環湖尤甚盛李子先家小池界金數朵花品之最高者各紀以詩  其二','程公許','宋','宋诗','song-poetry','','[]','芙蓉城下六月秋，最好雁湖湖上游。',32,'全唐诗/poet.song.194000.json','["芙蓉城下六月秋，最好雁湖湖上游。", "周遭一機雲錦爛，併與老仙供唱酬。"]'),
('d39a77ff-f85f-4514-9207-4a08fd42245a','范石湖東歸過鄉國名之芙蓉城余以季夏來遊適荷花稱意紅之時雁湖環湖尤甚盛李子先家小池界金數朵花品之最高者各紀以詩  其三','程公許','宋','宋诗','song-poetry','','[]','環湖曲曲露香清，醉袖褰風取意行。',32,'全唐诗/poet.song.194000.json','["環湖曲曲露香清，醉袖褰風取意行。", "翻愛李園方沼碧，界金幾朶艷羞頳。"]'),
('ff64d026-de93-4839-b1ce-2ec6bbb34305','遊石湖','程公許','宋','宋诗','song-poetry','','[]','雨過春塘水慢流，喚船聊作石湖遊。',64,'全唐诗/poet.song.194000.json','["雨過春塘水慢流，喚船聊作石湖遊。", "水亭風檻今餘幾，越壘吳臺相對愁。", "笑拂壁題如覿面，憶從鄉老話遨頭。", "不知化鶴曾歸否，更撚梅花一餉留。"]'),
('c9e541e5-a0b8-4e33-858c-f3326256646e','三湖','程公許','宋','宋诗','song-poetry','','["\u897f\u6e56"]','官柳三千詑蜀州，天涯流浪得重遊。',32,'全唐诗/poet.song.194000.json','["官柳三千詑蜀州，天涯流浪得重遊。", "苦無東閣梅花句，小爲西湖竹色留。"]'),
('16f63ad0-9a1e-4cac-a89e-450a5fc19dac','入青城山門詩  其一','程公許','宋','宋诗','song-poetry','','[]','入山佳氣異他山，翠邏周遭幾復關。',32,'全唐诗/poet.song.194000.json','["入山佳氣異他山，翠邏周遭幾復關。", "流水白雲無盡藏，莫教容易到人間。"]'),
('bbde1068-21d4-4e53-9241-1acf34f0f91e','入青城山門詩  其二','程公許','宋','宋诗','song-poetry','','[]','一逕石牆分竹色，兩橋澗水和松風。',32,'全唐诗/poet.song.194000.json','["一逕石牆分竹色，兩橋澗水和松風。", "山靈憐我嗜幽勝，洗出林巒晚照紅。"]'),
('539b6730-b0c5-4023-8f7a-67cc5c745232','借宿洞門五絕  其一','程公許','宋','宋诗','song-poetry','','[]','身是西來旦過僧，洞門一再解行縢。',32,'全唐诗/poet.song.194000.json','["身是西來旦過僧，洞門一再解行縢。", "老師若許中分魯，也會漫天話葛藤。"]'),
('7bd0d6de-a911-4d5c-b5d7-682cb33d664e','借宿洞門五絕  其二','程公許','宋','宋诗','song-poetry','','[]','傳語巖前五百牛，塵緣誤我意無憀。',32,'全唐诗/poet.song.194000.json','["傳語巖前五百牛，塵緣誤我意無憀。", "靈山幸有三生契，更約天台度石橋。"]'),
('7a7fe4a9-5bbf-4c41-99c8-5a11b5aee885','借宿洞門五絕  其三','程公許','宋','宋诗','song-poetry','','[]','一枕齁齁客夢長，忽聞鐘梵響雲堂。',32,'全唐诗/poet.song.194000.json','["一枕齁齁客夢長，忽聞鐘梵響雲堂。", "舌根久厭虀鹽味，洗鉢聊分豆粥香。"]'),
('571b1e2f-e8ca-4035-923a-5813cfc5aff6','借宿洞門五絕  其四','程公許','宋','宋诗','song-poetry','','[]','意行忽上凌雲閣，粉雉周遭山四圍。',32,'全唐诗/poet.song.194000.json','["意行忽上凌雲閣，粉雉周遭山四圍。", "何似清音亭上座，峨眉掃翠雪濤飛。"]'),
('1c0029c6-da04-4ae9-90db-7d56e03a0191','借宿洞門五絕  其五','程公許','宋','宋诗','song-poetry','','[]','石筍巖頭爛熳遊，異聞要驗佛低頭。',32,'全唐诗/poet.song.194000.json','["石筍巖頭爛熳遊，異聞要驗佛低頭。", "却教古佛低頭笑，笑殺癡人枉刻舟。"]'),
('c89c9b97-9ac0-4234-a807-1f61436eade0','謝慧明王道士自大面山寄贈三詩并蜜黄精  其一','程公許','宋','宋诗','song-poetry','','[]','與君一再會岷山，共把匏尊中聖賢。',64,'全唐诗/poet.song.194000.json','["與君一再會岷山，共把匏尊中聖賢。", "强說市朝爲大隠，何如山澤友臞仙。", "空中皓月參心地，海面浮漚悟世緣。", "安得一龕時晤語，笑披雲霧豁青天。"]'),
('0385efa4-fb26-442d-aaf0-bb13c44967ca','謝慧明王道士自大面山寄贈三詩并蜜黄精  其二','程公許','宋','宋诗','song-poetry','','[]','尺書覼縷寫衷誠，大面山前兩日程。',64,'全唐诗/poet.song.194000.json','["尺書覼縷寫衷誠，大面山前兩日程。", "黄獨潤含崖谷味，清詩吟作澗泉聲。", "灰心久已安枯寂，月指何勞借發明。", "更與草菴求扁榜，太虛底處强安名。"]'),
('f5dfae48-b9c6-44c2-a5c4-d63a59afe607','謝慧明王道士自大面山寄贈三詩并蜜黄精  其三','程公許','宋','宋诗','song-poetry','','[]','三復君詩想洛陽，令人憤極意飛揚。',64,'全唐诗/poet.song.194000.json','["三復君詩想洛陽，令人憤極意飛揚。", "鼎湖知有威靈在，魏闕欣聞孝里彰。", "一念變遷無量劫，寸心寂照大圓光。", "君能勘破皆泡幻，長與喬松燕玉房。"]'),
('0ea31690-6d3f-4fb2-a5df-09165c5ea5ed','贈山老借館','程公許','宋','宋诗','song-poetry','','[]','三生雲水僧，失脚困下吏。',120,'全唐诗/poet.song.194000.json','["三生雲水僧，失脚困下吏。", "每逢道人語，莫逆猶夙嗜。", "況茲法龍象，共飲良有味。", "寶坊寄囂氛，一室淡如水。", "蹇馿劣馳騖，入門輒心醉。", "向來箠楚塵，火急須湔洗。", "浄名方丈室，逼塞諸天侍。", "可恡一毫端，借我容膝地。", "後來支許交，清真遺世累。", "團蒲與茗椀，共談第一義。"]'),
('beaf4197-b274-424c-a46c-90e01dd28bec','行至羅江以代者爽期得史者書復還涪濱徑走富樂山中借館  其一','程公許','宋','宋诗','song-poetry','','[]','瞻雲日懷歸，及瓜法當代。',48,'全唐诗/poet.song.195000.json','["瞻雲日懷歸，及瓜法當代。", "喜同縚鷹掣，翻作風鷁退。", "誓言不可寒，幽賞夙所愛。", "但恐彼上人，雄辨費酬對。"]'),
('5982da72-ef0c-45a8-a189-9ac764d75a53','行至羅江以代者爽期得史者書復還涪濱徑走富樂山中借館  其二','程公許','宋','宋诗','song-poetry','','[]','淋浪一日雨，浩蕩千巖秋。',48,'全唐诗/poet.song.195000.json','["淋浪一日雨，浩蕩千巖秋。", "莞彼石澗水，奔霆撼林丘。", "須臾忽斂縮，幽咽鏘琳璆。", "混混須有本，萬古江河流。"]'),
('ed128f70-5de3-4e84-bcc6-a6e0f58a0795','行至羅江以代者爽期得史者書復還涪濱徑走富樂山中借館  其三','程公許','宋','宋诗','song-poetry','','[]','山中有何樂，淹留不復嘆。',48,'全唐诗/poet.song.195000.json','["山中有何樂，淹留不復嘆。", "濯足澗泉碧，洗耳松風寒。", "清磬度林杪，枯禪兀蒲團。", "拙不會參請，幸勿催抽單。"]'),
('ff8a2307-5344-430d-89fa-66dbc89bf0ce','初度詣葛仙化奉香火歸邑之明日有馴鹿自中徑入縣庭士友異其事賦詩相慶用張權父韻','程公許','宋','宋诗','song-poetry','','[]','閬風觴九醖，膾鯨羞玉麟。',168,'全唐诗/poet.song.195000.json','["閬風觴九醖，膾鯨羞玉麟。", "宿命憶往劫，隠訣聞至人。", "失脚五濁海，未泯一念仁。", "就盈紀良月，揆度逢佳辰。", "深恩感顧復，瓣香謁仙真。", "同來山中吏，得非我同倫。", "巖泉千仞雪，澗草四時春。", "雅嗜自幽閒，胡爲此逡巡。", "憐我久埃𡏖，爲記三生因。", "野性欣得友，不待呼孔賓。", "鼓瑟趣升歌，明當下溫淪。", "嘉燕屬君等，努力語去陳。", "靈囿豈予慕，願交惟梓椿。", "方寸有玄感，清都寧隔塵。"]'),
('b1521683-198e-430a-839d-5be61f15e8f7','繩翁初度','程公許','宋','宋诗','song-poetry','','[]','男兒十六已非孩，心地迷雲漸剔開。',64,'全唐诗/poet.song.195000.json','["男兒十六已非孩，心地迷雲漸剔開。", "雖復詞章當藻繪，要從德性植根荄。", "謙和孝友能無愧，富貴功名付儻來。", "但願時平早還蜀，田間伴我斸蒿萊。"]'),
('9731838d-7944-4db3-989f-4b6aedd57ce3','東川節度歌','程公許','宋','宋诗','song-poetry','','[]','東川節度兵馬雄，我嘗聞之浣溪翁。',396,'全唐诗/poet.song.195000.json','["東川節度兵馬雄，我嘗聞之浣溪翁。", "五百年間人事紛變滅，惟有青山衮衮今古同。", "春官侍郎李太史，沃絲昔日來觀風。", "八年俛仰一炊黍，蔚藍臺上烟雨愁溟濛。", "棠郊蔽芾公所憩，還有竹騎馳兒童。", "是時北塵轉騷屑，綠林之寇紛內訌。", "洛波殷雷躍雙龍，遂也長公潼少公。", "少公赴鎮先十日，千夫煌煌飛旆紅。", "金城一面森戌削，賊戈自此不復鋒。", "三災之劫偶參會，天豈薄於遂而私於潼。", "屹然洚波之砥柱，艱哉安宅之集鴻。", "險夷一節貫金石，玉山對峙雙玲瓏。", "春風送客來，束書一短篷。", "恨無春色浮山之傑句，空有帝鄉愁緒之孤忠。", "舉頭山城新百雉，繚繞下與州城通。", "高如石首矗萬仞，堅並鐵甕盤層穹。", "樓棚丹霞未爲麗，形勢墨守何可攻。", "向來牛頭著亭處，晴烟萬井歷歷明雙瞳。", "徹桑未雨寧過計，路旁築屋難爲功。", "侍郎憂國秉卓識，始謀肯使輕傷農。", "登登之築紛百堵，一朝𡽱嶪如金墉。", "初疑化城爲佛幻，又恐鬼役非人工。", "浣溪曩賦冬狩行，恨不回轡擒四戎。", "向令眼前見此事，奇偉大篇當復加舂容。"]'),
('fa1fc8ac-8d25-4bfc-8e55-712d22076ee6','送家歸侍旁','程公許','宋','宋诗','song-poetry','','[]','隨牒走千里，携家恰二年。',48,'全唐诗/poet.song.195000.json','["隨牒走千里，携家恰二年。", "送君歸戲綵，笑我覓行纏。", "忍話關山遠，須憑信息傳。", "抱持嬌小女，恣索老人憐。"]'),
('76442cb1-f4e1-4228-92cb-eabb703dc9a1','送別彥威姪西歸侍母  其一','程公許','宋','宋诗','song-poetry','','[]','先集載行橐，叩閽書萬言。',48,'全唐诗/poet.song.195000.json','["先集載行橐，叩閽書萬言。", "風雲乘快便，雨露沐殊恩。", "客裏仍分袂，天涯想倚門。", "去留交喜戚，情不盡離尊。"]'),
('10fa4c41-bcdf-4345-af6c-d79675f3c9a7','送別彥威姪西歸侍母  其二','程公許','宋','宋诗','song-poetry','','[]','況自宦情薄，未忘嫠緯憂。',48,'全唐诗/poet.song.195000.json','["況自宦情薄，未忘嫠緯憂。", "聖知非我責，若要盡心酬。", "牛隴松蘿月，鷗汀水竹秋。", "丁寧與將護，待我賦歸休。"]'),
('58a45f43-9427-4788-b24b-930a6d9106fe','送別彥威姪西歸侍母  其三','程公許','宋','宋诗','song-poetry','','[]','宇宙暗矛戟，吾當何處歸。',48,'全唐诗/poet.song.195000.json','["宇宙暗矛戟，吾當何處歸。", "故山幾幸免，暮景儻同依。", "若見親知問，愁無羽翮飛。", "一簞元自足，底用带金圍。"]'),
('b32ffd86-4a36-4cd2-9878-4ef5c3e075fc','野塘雜興  其一','黄敏求','宋','宋诗','song-poetry','','[]','仕進固所願，貧賤亦所憂。',72,'全唐诗/poet.song.195000.json','["仕進固所願，貧賤亦所憂。", "抱璞不自珍，過取則足羞。", "不如寂寞濱，橫此野水舟。", "時乎儻可爲，肯遜伊與周。", "著書俟百世，亦可軻與丘。", "進退兩不惡，久矣吾其籌。"]'),
('7d47fb62-9e07-4b42-9541-db3f232b43dc','野塘雜興  其二','黄敏求','宋','宋诗','song-poetry','','[]','地僻車馬稀，柴門不須扃。',84,'全唐诗/poet.song.195000.json','["地僻車馬稀，柴門不須扃。", "晨興正衣冠，浣手供爐馨。", "奈此日永何，閒課離騷經。", "一片蘭茝心，千古日月明。", "爾豈乏忠憤，所欠惟和平。", "要之仕與止，奚必分重輕。", "吾但適吾可，不願得爾名。"]'),
('ca3df748-283a-4284-bd1b-c540f9a8e1e1','別詩人余叔雲  其一','黄敏求','宋','宋诗','song-poetry','','[]','萬柳堤邊住，挑雲過艾東。',48,'全唐诗/poet.song.195000.json','["萬柳堤邊住，挑雲過艾東。", "未應爲計左，輕去犯詩窮。", "雙屐江湖上，清名宇宙中。", "折梅作行供，香已破椒紅。"]'),
('6e4e1df4-94fa-434b-bbc7-6bd48b5b4d89','別詩人余叔雲  其二','黄敏求','宋','宋诗','song-poetry','','[]','筆硯無靈久，寒檠自掩門。',48,'全唐诗/poet.song.195000.json','["筆硯無靈久，寒檠自掩門。", "虛名何預我，漫刺重煩君。", "茶外無祗待，詩邊得細論。", "別懷莫兒女，相祝張吾軍。"]'),
('a2bb7fee-3b50-4c07-8634-6f4158f83c3a','書齋','黄敏求','宋','宋诗','song-poetry','','[]','新闢書齋鶴柵寬，一簾風月儘幽閑。',64,'全唐诗/poet.song.195000.json','["新闢書齋鶴柵寬，一簾風月儘幽閑。", "百年易向忙中過，萬事偏於好處慳。", "漫說折腰營斗米，何如留眼看雲山。", "只消一卷梅花句，留得林逋在世間。"]'),
('f5ea76f4-b98c-46a7-b3ed-dffde23dfae6','題陳篔谷陳野逸吟藁','黄敏求','宋','宋诗','song-poetry','','[]','謝却梅花吟課少，苦無心事惱陶泓。',64,'全唐诗/poet.song.195000.json','["謝却梅花吟課少，苦無心事惱陶泓。", "得君近日詩編讀，增我晴窗眼力明。", "爽似暑風秋九夏，清踰夜月晝三更。", "後山衣鉢塵埃久，頼有雙英主夏盟。"]'),
('7fe5523c-8fb7-439b-962c-58e025cdea72','予丙子辛巳兩遊解空寺己亥秋又至思上人徙舊徑自怪石中頓發奇觀叔亮弟取山谷詩文名閣曰卧龍巖曰青玉盎山之門曰天下勝處令泳之作隸扁爲賦七言','黄敏求','宋','宋诗','song-poetry','','[]','兩扣雲關記昔曾，重來詩眼倍晶明。',64,'全唐诗/poet.song.195000.json','["兩扣雲關記昔曾，重來詩眼倍晶明。", "路移巖石中間入，人在洞天深處行。", "玉盎虛明添翠色，霜鐘清冽带秋聲。", "與君小摘涪翁句，留得青山不朽名。"]'),
('61816454-17ea-4599-983a-2cb2254cfec4','凉棚','黄敏求','宋','宋诗','song-poetry','','[]','未庚赫日已焚空，亭午西齋坐甑同。',64,'全唐诗/poet.song.195000.json','["未庚赫日已焚空，亭午西齋坐甑同。", "橫竹旋排蒼葉密，小窗移在綠陰中。", "情知瑣碎妨新月，稍喜牽連得暑風。", "分我清凉詩境界，一蟬吟到夕陽紅。"]'),
('3b72c797-d56a-4f6e-8767-ea8004b1ab28','經理順寧別墅','黄敏求','宋','宋诗','song-poetry','','[]','未必餘資辦草廬，先從意匠起規模。',64,'全唐诗/poet.song.195000.json','["未必餘資辦草廬，先從意匠起規模。", "某池宜植荷千柄，此地合栽梅幾株。", "怕礙看山牆矮築，要寬種菊徑深鋤。", "林泉隨分成幽趣，誰計東郊入畫圖。"]'),
('0c2fba58-caf9-4df7-9079-21c0024c7dfa','書鄭亦山冷澹生活','黄敏求','宋','宋诗','song-poetry','','["\u897f\u6e56"]','九陌紅塵不肯居，携家租屋住西湖。',64,'全唐诗/poet.song.195000.json','["九陌紅塵不肯居，携家租屋住西湖。", "月香水影賡和靖，雨色晴光憶大蘇。", "詩比晚唐成冷淡，人如東野更清臞。", "晴窗盡展芳編看，一片寒冰浸玉壺。"]'),
('f226ab38-d3de-4ff8-8121-70865eec67c0','遊落星寺','黄敏求','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','星江山水甲江東，所到僧房各不同。',64,'全唐诗/poet.song.195000.json','["星江山水甲江東，所到僧房各不同。", "拳石不知何代隕，數椽恰占一湖中。", "廬山屏倚朝昏碧，彭蠡帆分上下風。", "除却金焦相伯仲，其他無此水晶宮。"]'),
('81078bd0-8105-44b5-8d4a-65205b0860ed','柳絮','黄敏求','宋','宋诗','song-poetry','','[]','近日柔絲可着鴉，又分晴絮落天涯。',64,'全唐诗/poet.song.195000.json','["近日柔絲可着鴉，又分晴絮落天涯。", "絕無氣力元非雪，空費形容不是花。", "便解與春遮去路，也添爲客重思家。", "雨餘留得閒蹤跡，綠染浮萍夜聽蛙。"]'),
('3231077e-2034-4fb7-ab91-baf53704fe4e','寄題靈川簿廨存愛堂二首  其一','黄敏求','宋','宋诗','song-poetry','','[]','一命如何解濟人，細看存字最精神。',32,'全唐诗/poet.song.195000.json','["一命如何解濟人，細看存字最精神。", "莫專紙上求明愛，胸次渾涵不盡春。"]'),
('a8274e54-95d8-4662-ab9d-21a1ade9ac3b','寄題靈川簿廨存愛堂二首  其二','黄敏求','宋','宋诗','song-poetry','','[]','愛無差等墨之徒，理一由來分則殊。',32,'全唐诗/poet.song.195000.json','["愛無差等墨之徒，理一由來分則殊。", "愛只是情仁是性，合於仁上着工夫。"]'),
('a4bf24b2-7247-4fb8-b81b-c9cd1725c53a','初秋白雲道院  其一','黄敏求','宋','宋诗','song-poetry','','[]','檜柏株樟竹與松，四山互長翠陰濃。',32,'全唐诗/poet.song.195000.json','["檜柏株樟竹與松，四山互長翠陰濃。", "逼教秋暑無來路，輸與山僧坐晚鐘。"]'),
('6e33ddac-1cd2-48b7-a34f-e9521ecada52','初秋白雲道院  其二','黄敏求','宋','宋诗','song-poetry','','[]','莫道秋容冷淡加，秋英風露勝春葩。',32,'全唐诗/poet.song.195000.json','["莫道秋容冷淡加，秋英風露勝春葩。", "拒霜巖桂休相遜，占得開時各自花。"]'),
('26fc5148-de86-4af0-90ee-28906492bfc3','初秋白雲道院  其三','黄敏求','宋','宋诗','song-poetry','','[]','閒來汲水浸菖蒲，浄洗塵埃半點無。',32,'全唐诗/poet.song.195000.json','["閒來汲水浸菖蒲，浄洗塵埃半點無。", "濯得老根如法瘦，養教矮葉十分臞。"]'),
('e34ee37e-9909-4d46-8253-ba623588b636','次鄭亦山求茶韻','黄敏求','宋','宋诗','song-poetry','','[]','山谷松風賦響湯，茗甌今带六經香。',32,'全唐诗/poet.song.195000.json','["山谷松風賦響湯，茗甌今带六經香。", "君詩莫道窮無對，高出車聲遶九羊。"]'),
('a2377165-9689-4b63-8703-9cbef154f879','訊黄乙山於壽寧寺  其一','黄敏求','宋','宋诗','song-poetry','','[]','客中聽雨况僧寮，盡日無人訪寂寥。',32,'全唐诗/poet.song.195000.json','["客中聽雨况僧寮，盡日無人訪寂寥。", "一枕秋聲供痛快，隔窗風裏有芭蕉。"]'),
('5a6124aa-52e1-425a-83dd-14c84b989108','訊黄乙山於壽寧寺  其二','黄敏求','宋','宋诗','song-poetry','','[]','草草茅亭古木間，萬琅玕裏一禪關。',32,'全唐诗/poet.song.195000.json','["草草茅亭古木間，萬琅玕裏一禪關。", "秋陰只俟風收盡，分我浮生半日閑。"]'),
('2c4757a2-f19b-49e3-a940-dd916717fa66','水墨水仙','黄敏求','宋','宋诗','song-poetry','','[]','玉潤金寒情窈窕，縞裙翠带態輕盈。',32,'全唐诗/poet.song.195000.json','["玉潤金寒情窈窕，縞裙翠带態輕盈。", "只愁微月清無對，更畫梅礬作弟兄。"]'),
('1b3233bb-bbdf-4efb-86cb-86af825efdf0','古香亭  其一','黄敏求','宋','宋诗','song-poetry','','[]','矮屋簷前老桂叢，清陰分破廣寒宮。',32,'全唐诗/poet.song.195000.json','["矮屋簷前老桂叢，清陰分破廣寒宮。", "誰知萬古香無價，藏在黄金一粟中。"]'),
('2a0435ae-852a-47a7-9e32-e211e5b6912a','古香亭  其二','黄敏求','宋','宋诗','song-poetry','','[]','鵝黄雪綴碧瑶枝，占斷風高露下時。',32,'全唐诗/poet.song.195000.json','["鵝黄雪綴碧瑶枝，占斷風高露下時。", "吏散予方有公事，嚼花斟酒古香詩。"]'),
('9166cd00-1bfe-49dc-8bf3-7905c67b356f','偶成','黄敏求','宋','宋诗','song-poetry','','[]','熨開詩眼靜中觀，春在虛無杳靄間。',64,'全唐诗/poet.song.195000.json','["熨開詩眼靜中觀，春在虛無杳靄間。", "風老山樊香世界，日烘躑躅錦屏山。", "峙糧備歲蜂開戶，堅壁防春燕抱關。", "不被東風相鼓弄，蒼波依舊白鷗閑。"]'),
('11b87cec-6ef0-4f31-b2dc-a1e272cbcc55','村樂  其一','黄敏求','宋','宋诗','song-poetry','','[]','槿籬圍裹三間屋，棘塹週遭數畝山。',32,'全唐诗/poet.song.195000.json','["槿籬圍裹三間屋，棘塹週遭數畝山。", "雨後課兒耕種了，茅簷晴曝一冬閑。"]'),
('054ad853-36ec-45cb-b006-2a2df2e25778','村樂  其二','黄敏求','宋','宋诗','song-poetry','','[]','刈盡稻雲蕎再雪，搗空粒玉粟仍金。',32,'全唐诗/poet.song.195000.json','["刈盡稻雲蕎再雪，搗空粒玉粟仍金。", "己償一飽知無欠，圍坐青燈語夜深。"]'),
('d42b50a7-bf27-40b4-bf38-dc84bba2c9b1','村樂  其三','黄敏求','宋','宋诗','song-poetry','','[]','敲冰汲淥供茶鼎，撼雪梯薪給地爐。',32,'全唐诗/poet.song.195000.json','["敲冰汲淥供茶鼎，撼雪梯薪給地爐。", "圃有麥苗畦有菜，更於何地享膏腴。"]'),
('50971719-2ace-4660-8661-7090c9af7692','村樂  其四','黄敏求','宋','宋诗','song-poetry','','[]','白首老人紉永日，青裙幼婦饁田間。',32,'全唐诗/poet.song.195000.json','["白首老人紉永日，青裙幼婦饁田間。", "那知紅袖青樓女，帳煖銷金倚玉山。"]'),
('3096e983-d4d9-4543-baf8-d1dc4664b9ff','村樂  其五','黄敏求','宋','宋诗','song-poetry','','[]','桑樹鳴鷄深巷犬，南山磵水北山雲。',32,'全唐诗/poet.song.195000.json','["桑樹鳴鷄深巷犬，南山磵水北山雲。", "五侯門地人如沸，誰識村中樂是君。"]'),
('c80ba43f-f5c6-426c-af51-0ea3d52f6701','滌齋','趙雷','宋','宋诗','song-poetry','','[]','想象盤銘號滌齋，滌齋端得苦安排。',32,'全唐诗/poet.song.195000.json','["想象盤銘號滌齋，滌齋端得苦安排。", "清清流出源頭水，浴德澄清未有涯。"]'),
('5f3f6014-ab7d-4bae-bcae-107042847dd2','書樓課子','趙雷','宋','宋诗','song-poetry','','[]','雲頭月出倚樓看，老桂深深發廣寒。',32,'全唐诗/poet.song.195000.json','["雲頭月出倚樓看，老桂深深發廣寒。", "底事嫦娥深愛惜，他年摘爲少年簪。"]'),
('1d89bf2a-1c1a-4d08-ba46-b2f02c5a8464','書富陽驛壁','趙元魚','宋','宋诗','song-poetry','','[]','少年書劍幾經過，沽酒譚文還自歌。',32,'全唐诗/poet.song.195000.json','["少年書劍幾經過，沽酒譚文還自歌。", "今日重來春意閙，老梅枝上着花多。"]'),
('292627ce-d5d1-489d-8061-6c00a75ed802','夷陵道上','趙元魚','宋','宋诗','song-poetry','','[]','山麓林梢烟翠橫，寒天日色半陰晴。',64,'全唐诗/poet.song.195000.json','["山麓林梢烟翠橫，寒天日色半陰晴。", "道邊廢宅空椽瓦，巖下居人困甲兵。", "破膽每驚腰劍客，傷弓時怯羽書聲。", "癡兒弱女渾多病，留寄鄉村念爾情。"]'),
('37ee54e1-f2c1-41ec-a3ee-2184800c29d0','玉簪花','鄭大惠','宋','宋诗','song-poetry','','[]','玉色瓷盆綠柄深，夜涼移向小窗陰。',32,'全唐诗/poet.song.195000.json','["玉色瓷盆綠柄深，夜涼移向小窗陰。", "兒童莫訝心難展，未展心時玉似簪。"]'),
('25f43ea3-8334-40d3-b205-fb610b90bbad','哀夏孝女','鄭大惠','宋','宋诗','song-poetry','','[]','射生戶，北山有虎何不射。',170,'全唐诗/poet.song.195000.json','["射生戶，北山有虎何不射。", "豈不聞夏家有女年十五，隨父樵薪入山塢，父行在前忽遭虎。", "女見父傷奮不懼，號泣逐之爲虎語。", "逐之不已虎反顧，棄其父□銜女去。", "人言其父死亦苦，我言最苦是其女。", "想女失父逐虎時，眼不見虎惟見父。", "射生戶，我今重告汝。", "汝之生，豈無父與母。", "勿謂官差尚猶豫，被爾甲兮張爾弩，况虎殺害人多天已怒。", "嗚呼，虎害人多天若怒，天又何必使渠生下土。"]'),
('1af22190-f07b-4f37-b305-08849c0606be','題曹娥墓','翁元龍','宋','宋诗','song-poetry','','[]','自從西子入吳宮，幸有英娥可勸忠。',64,'全唐诗/poet.song.195000.json','["自從西子入吳宮，幸有英娥可勸忠。", "同姓最慙曹孟德，垂名只許叔先雄。", "虛生浪死人何限，白日青天古一同。", "看得冢頭三寸草，也嫌桃李嫁東風。"]'),
('c32d1ed3-e6a6-4196-9c1e-fda80dde7c7b','總宜園','翁元龍','宋','宋诗','song-poetry','','[]','此間不愧總宜名，山色湖光任雨晴。',32,'全唐诗/poet.song.195000.json','["此間不愧總宜名，山色湖光任雨晴。", "鴻雁一聲秋意慘，疏楊摇曳尚多情。"]'),
('3fccf0be-8422-43d2-b2cc-1f7e46f3d88a','句  其一','馮去辯','宋','宋诗','song-poetry','','[]','饟事十年當結局，襟期千古舉同牢。',16,'全唐诗/poet.song.195000.json','["饟事十年當結局，襟期千古舉同牢。"]'),
('4ce05387-9a07-4bd8-879a-a5d6754d248a','句  其二','馮去辯','宋','宋诗','song-poetry','','[]','琴心自誤誰料理，犢鼻雖貧未主臣。',16,'全唐诗/poet.song.195000.json','["琴心自誤誰料理，犢鼻雖貧未主臣。"]'),
('69124723-9529-4d89-a552-36cd64e59177','重修聖濟院','陳有聲','宋','宋诗','song-poetry','','[]','蒙泉距宜春，相去百餘里。',288,'全唐诗/poet.song.195000.json','["蒙泉距宜春，相去百餘里。", "有僧來問余，借問何姓氏。", "乃余昔所敬，見之蹙然喜。", "敘余語未既，省記到山始。", "屋廬今何如，舊者存有幾。", "一別十八年，再見復在此。", "僧云今勝前，百蠹費更理。", "昔茅塞蹊徑，今道平如砥。", "昔門不容蓋，今可駟結軌。", "昔堂地一坳，今去天尺咫。", "翬飛兩廡列，翼從萬瓦起。", "古殿布丹雘，雲龕照青紫。", "臨流地寬曠，一带碧清泚。", "竹院密回環，松關秀兩峙。", "峰巒對青眼，泉石洗幽耳。", "最上兩龍湫，層崖狀奇詭。", "水旱凡禱祈，響答應甚邇。", "載念此招提，明禪祖基址。", "傳燈焰不續，老子心所耻。", "莊嚴七寶界，因果非偶爾。", "問余求篇題，以爲歲月紀。", "余老書最拙，況在塵箠裏。", "欲到身未能，欲輟請未已。", "忽然若天會，拈筆書滿紙。"]'),
('2cab0ee9-7ffe-4b8a-af49-044023cf14ce','流化亭','陳有聲','宋','宋诗','song-poetry','','[]','惟聖觀化，自源而流。',250,'全唐诗/poet.song.195000.json','["惟聖觀化，自源而流。", "惟吏觀化，自邑而州。", "聖念於民，吏職其憂。", "民壅於化，則吏之尤。", "我相此邦，此邦之休。", "昔民睽睽，胥戕以劉。", "今民熙熙，式歌且謳。", "昔民啼饑，穀粒不收。", "今民夷懌，無佩犢與牛。", "是曰化國，莫知其由。", "我儀圖之，惟孝友張侯。", "侯有令德，不競不絿。", "澤濡而春，令肅而秋。", "靡夙夜不勤，惟民之諏。", "孰冤而伸，孰貧而賙。", "孰梗而頑，去其賊蟊。", "孰巧而奸，鍛其戈矛。", "惟教化不行，如疾弗瘳。", "既觀厥成，泮渙以賙。", "經之營之，爰始爰謀。", "乃築斯亭，于江之陬。", "如跂斯翼，如方斯輈。", "如虹維橋，如鷁維舟，如蓬萊瀛洲。", "匪曰予觀，臨深極幽。"]'),
('2ec161e2-57ab-4442-abe6-0bf3907f1e71','穿山月巖','胡仲威','宋','宋诗','song-poetry','','[]','石磴𡼭嶔□□□，坐來心跡自雙清。',64,'全唐诗/poet.song.195000.json','["石磴𡼭嶔□□□，坐來心跡自雙清。", "不知渾沌何年鑿，便有嬋娟一鏡明。", "周穆馬蹄何寂寞，謝公屐齒□□□。", "□然欲御長風□，□□烟雲脚底生。"]'),
('e962b2c0-1145-4ea7-be9a-21220bfcedfd','融州老君洞敕賜真仙巖之圖','杜應然','宋','宋诗','song-poetry','','[]','古號黔南今號融，真仙第一勝高嵩。',384,'全唐诗/poet.song.195000.json','["古號黔南今號融，真仙第一勝高嵩。", "仙關標榜門增麗，聖像威靈民敬崇。", "帝賜御書藏寶閣，天生石像老仙翁。", "瓶爐羅列非雕琢，幢蓋周圍奪巧工。", "足履分明深踏石，仙衣彷彿挂玲瓏。", "青牛水畔藏頭角，白鶴溪邊飲羽㚇。", "獅子像前如拜伏，猿猴梯上若登空。", "龍田龍迹施鱗甲，蛇藏蛇身似錦紅。", "羅漢數軀朝向北，斗星七位轉回東。", "浮橋佇望金星座，仙徑平瞻水月宮。", "丹井千秋泉不竭，芝田萬頃草常豐。", "餘清近酌潺潺水，聳翠遥觀疊疊松。", "石柱經年堅且直，壽溪度歲淼無窮。", "呂仙隠迹居于壁，□□□容坐得穹。", "彩仗彩儀皆擁護，仙床仙室盡高雄。", "化巖夏月生寒凜，和洞冬天都暖烘。", "棋畫臺中人弈戯，樹生石內月朦朧。", "列三寺觀學俱近，會一樓堂像闡洪。", "道院庵中居上道，風雩臺畔自生風。", "橋名步扣登融石，樓號鴻音撞巨鐘。", "花圃西南前可望，釣臺泉石景堪充。", "劉侯布德于融郡，父宿興祠立壽容。", "廣地可容千位客，照天高挂一燈籠。", "洞天要比應難比，福地雖同未肯同。"]'),
('6ecb7403-ab56-4d2d-8904-51cb6a0a59d0','句','陳貴誼','宋','宋诗','song-poetry','','[]','行人自逐楊花去，不是楊花肯送人。',16,'全唐诗/poet.song.195000.json','["行人自逐楊花去，不是楊花肯送人。"]'),
('1f9f3270-6e39-4184-97d7-1cf148cfcc3b','九吟詩 九鎖','吳昌裔','宋','宋诗','song-poetry','','[]','上界神仙住九華，故留靈鎖護烟霞。',32,'全唐诗/poet.song.195000.json','["上界神仙住九華，故留靈鎖護烟霞。", "雲根欲斷溪回處，流出常山幾片花。"]'),
('86290890-0ebb-441b-b900-d50a96f645e0','九吟詩 棲真','吳昌裔','宋','宋诗','song-poetry','','[]','鑿破千年渾沌心，石楠當戶洞愔愔。',32,'全唐诗/poet.song.195000.json','["鑿破千年渾沌心，石楠當戶洞愔愔。", "詩臞猶怯春寒在，捫石梯雲不敢深。"]'),
('609c6ea4-3835-4a1e-b85a-e965fd2de16e','九吟詩 天柱','吳昌裔','宋','宋诗','song-poetry','','[]','柱天屹嶪斷鼇根，卧草蒙茸伏虎痕。',32,'全唐诗/poet.song.195000.json','["柱天屹嶪斷鼇根，卧草蒙茸伏虎痕。", "想見山中明月夜，有人長嘯抱崑崙。"]'),
('5ac1ba72-b440-410b-8c5c-68382623b339','九吟詩 石室','吳昌裔','宋','宋诗','song-poetry','','[]','竹几蒲團石室中，細書抱朴校參同。',32,'全唐诗/poet.song.195000.json','["竹几蒲團石室中，細書抱朴校參同。", "寄聲碧眼朱高士，何必携琴下閬風。"]'),
('8cae0e37-72f4-4e8c-844e-65c71421550f','九吟詩 清音','吳昌裔','宋','宋诗','song-poetry','','[]','山出涓寒一道泉，暗聲落澗玉錚然。',32,'全唐诗/poet.song.195000.json','["山出涓寒一道泉，暗聲落澗玉錚然。", "轆轤引上泥丸頂，便是人間赤脚仙。"]'),
('09fa9488-bc6f-46f2-90e1-c6a8230218dd','九吟詩 來賢','吳昌裔','宋','宋诗','song-poetry','','[]','杖挂松花酒一瓢，手挼柏子雜香燒。',32,'全唐诗/poet.song.195000.json','["杖挂松花酒一瓢，手挼柏子雜香燒。", "山空露冷吟招隠，掉首諸賢不受招。"]'),
('f450502c-b961-457f-aa71-a4e2bcf6da90','九吟詩 翠蛟','吳昌裔','宋','宋诗','song-poetry','','[]','蒼松翠石束寒流，飛下長身白玉虬。',32,'全唐诗/poet.song.195000.json','["蒼松翠石束寒流，飛下長身白玉虬。", "吐出英雲千尺雨，須臾雷霽水痕收。"]'),
('4c6c1b97-66b1-475c-9b9d-f520d45ea807','九吟詩 飛玉','吳昌裔','宋','宋诗','song-poetry','','[]','誰擘巖扉石竇開，中流玉水潄蒼苔。',32,'全唐诗/poet.song.195000.json','["誰擘巖扉石竇開，中流玉水潄蒼苔。", "有時卷雪從天下，端是源頭蓄得來。"]'),
('8accf3e6-c088-4b28-a8b3-21f64a59e96f','偈頌八十七首  其一','釋慧開','宋','宋诗','song-poetry','','[]','父子不傳，百無一有。',20,'全唐诗/poet.song.195000.json','["父子不傳，百無一有。", "狹路相逢，推門落臼。"]'),
('98038ed0-aa7a-4c3d-a5cf-34dd57528ad0','偈頌八十七首  其二','釋慧開','宋','宋诗','song-poetry','','[]','禮拜即是，不禮即是。',20,'全唐诗/poet.song.195000.json','["禮拜即是，不禮即是。", "黄面瞿曇，在我脚底。"]'),
('53c4e102-1625-4f53-b149-d3907eb4b942','偈頌八十七首  其三','釋慧開','宋','宋诗','song-poetry','','[]','山圍仙壠，水遶佳城。',20,'全唐诗/poet.song.195000.json','["山圍仙壠，水遶佳城。", "言中有響，句下分明。"]'),
('bc17c7b2-517b-4c7a-a4ed-0e2e4b66308b','偈頌八十七首  其四','釋慧開','宋','宋诗','song-poetry','','[]','一著高一著，一步闊一步。',24,'全唐诗/poet.song.195000.json','["一著高一著，一步闊一步。", "撥轉上頭關，乾坤全體露。"]'),
