('de679f00-0609-4fdf-85b5-ce2c4a9b0b94','偈頌八十七首  其三六','釋慧開','宋','宋诗','song-poetry','','[]','瞿曇遺下葛藤窠，翻覆看來脫處多。',32,'全唐诗/poet.song.195000.json','["瞿曇遺下葛藤窠，翻覆看來脫處多。", "不是兒孫重檢點，古今爭得絕誵訛。"]'),
('32c7fca9-28d0-4a70-8200-076f8ba7896e','偈頌八十七首  其三七','釋慧開','宋','宋诗','song-poetry','','[]','參禪要真實，直造無疑地。',48,'全唐诗/poet.song.195000.json','["參禪要真實，直造無疑地。", "聞非未必非，說是未必是。", "黄龍設三關，曹洞列五位。", "坐斷主人公，且不落第二。"]'),
('c252762c-aab6-4dc0-b115-c9c849545922','偈頌八十七首  其三八','釋慧開','宋','宋诗','song-poetry','','[]','循規守短，無繩自縛。',110,'全唐诗/poet.song.195000.json','["循規守短，無繩自縛。", "縱橫無礙，外道魔軍。", "存心澄寂，默照邪禪。", "恣意忘緣，解脫深坑。", "惺惺不昧，带鎖擔枷。", "思善思惡，地獄天堂。", "佛見法見，二鐵圍山。", "念起即覺，弄精魂漢。", "兀然習定，鬼家活計。", "進則迷理，退則乖宗。", "不進不退，有氣死人。"]'),
('3dde12c2-fe31-4e06-9d59-4e8070743586','偈頌八十七首  其三九','釋慧開','宋','宋诗','song-poetry','','[]','烈焰亙天，洪濤輥底。',20,'全唐诗/poet.song.195000.json','["烈焰亙天，洪濤輥底。", "眨上眉毛，劍去久矣。"]'),
('c889ed44-9465-4b9e-8cef-377ebdf950b9','偈頌八十七首  其四○','釋慧開','宋','宋诗','song-poetry','','[]','春山疊亂青，春水漾虛碧。',40,'全唐诗/poet.song.195000.json','["春山疊亂青，春水漾虛碧。", "春光漏泄盡，誰識春消息。", "多年枯木再抽枝，撼動春風生八極。"]'),
('711a311c-d91e-4337-a2ac-78d741ceed72','偈頌八十七首  其四一','釋慧開','宋','宋诗','song-poetry','','[]','撥轉玄關，一彈指頃。',26,'全唐诗/poet.song.195000.json','["撥轉玄關，一彈指頃。", "看看平地起風雲，門近洪崖千尺井。"]'),
('057dd919-4ada-468c-8ad4-96afa13176a6','偈頌八十七首  其四二','釋慧開','宋','宋诗','song-poetry','','[]','死心室內，移身移步。',32,'全唐诗/poet.song.195000.json','["死心室內，移身移步。", "日日香燈，朝朝話墮。", "稽首齊安王，鐵蛇橫大道。"]'),
('13e726b8-2279-4222-9df3-a95131d37d91','偈頌八十七首  其四三','釋慧開','宋','宋诗','song-poetry','','[]','春山疊亂青，春水漾虛碧。',24,'全唐诗/poet.song.195000.json','["春山疊亂青，春水漾虛碧。", "寥寥天地間，滿眼皆相識。"]'),
('7d21f8cb-a89b-40d3-b8e9-7bb715d9faed','偈頌八十七首  其四四','釋慧開','宋','宋诗','song-poetry','','[]','三月清明節禁烟，桃華带雨倍鮮妍。',32,'全唐诗/poet.song.195000.json','["三月清明節禁烟，桃華带雨倍鮮妍。", "皆言當日靈雲悟，笑破禪和口半邊。"]'),
('f263e530-7bb9-4826-bd07-e295ef305605','偈頌八十七首  其四五','釋慧開','宋','宋诗','song-poetry','','[]','今朝三月初十，擊鼓禪徒畢集。',42,'全唐诗/poet.song.195000.json','["今朝三月初十，擊鼓禪徒畢集。", "欲知時節因緣，雨落階頭便濕。", "會即各自歸堂，不會何勞久立。"]'),
('323dba5b-185d-4b8c-99e2-c9be812bd6c7','偈頌八十七首  其四六','釋慧開','宋','宋诗','song-poetry','','[]','翠巖絕嶮巇，元不涉階梯。',40,'全唐诗/poet.song.195000.json','["翠巖絕嶮巇，元不涉階梯。", "去來無窒礙，彼此更何疑。", "珍重洪源湖海衆，箇中不隔一毫釐。"]'),
('957f0d52-613b-4129-9803-a73dd288ca36','偈頌八十七首  其四七','釋慧開','宋','宋诗','song-poetry','','[]','無門爲法門，三關何用立。',24,'全唐诗/poet.song.195000.json','["無門爲法門，三關何用立。", "熟處既難忘，又從這裏入。"]'),
('3d3b2fb2-ca59-457e-a401-9d2417fb8a75','偈頌八十七首  其四八','釋慧開','宋','宋诗','song-poetry','','[]','靈山一會，泥團土塊。',20,'全唐诗/poet.song.195000.json','["靈山一會，泥團土塊。", "問訊燒香，和贓捉敗。"]'),
('e3f741bd-e518-4322-a7ef-eeec28463f0c','偈頌八十七首  其四九','釋慧開','宋','宋诗','song-poetry','','[]','熱喝粗拳，佛來也打。',20,'全唐诗/poet.song.195000.json','["熱喝粗拳，佛來也打。", "臨濟德山，一時擒下。"]'),
('7cd4bd1e-a07d-403f-ab8a-7c9685e32681','偈頌八十七首  其五○','釋慧開','宋','宋诗','song-poetry','','[]','不是護身符，亦非斷貫索。',44,'全唐诗/poet.song.195000.json','["不是護身符，亦非斷貫索。", "直饒鼻孔遼天，也被這箇穿却。", "無門老漢還免得麽，却請維那下箇注脚。"]'),
('2de8e3c0-851b-4308-bbb3-1c97fe5a3093','偈頌八十七首  其五一','釋慧開','宋','宋诗','song-poetry','','[]','讚嘆無門，也是這箇。',36,'全唐诗/poet.song.195000.json','["讚嘆無門，也是這箇。", "駡詈無門，也是這箇。", "文彩未彰誰辨得，却煩首座通消息。"]'),
('7f9d41bb-63f4-4a9e-9b15-62945d69b44f','偈頌八十七首  其五二','釋慧開','宋','宋诗','song-poetry','','[]','不動脚頭，青雲獨步。',26,'全唐诗/poet.song.195000.json','["不動脚頭，青雲獨步。", "箇是尋常行履處，須知更有通霄路。"]'),
('24a6f61c-d243-4752-9b24-3c97f19922cf','偈頌八十七首  其五三','釋慧開','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','掣斷繩頭欲自由，那知定業未容休。',32,'全唐诗/poet.song.195000.json','["掣斷繩頭欲自由，那知定業未容休。", "再償拽杷拖犁債，鼓得西江水逆流。"]'),
('4130bda1-f301-4055-98ae-ca4929c62733','偈頌八十七首  其五四','釋慧開','宋','宋诗','song-poetry','','[]','八兩還他是半斤，陳年桃核舊時仁。',32,'全唐诗/poet.song.195000.json','["八兩還他是半斤，陳年桃核舊時仁。", "大家出手共提掇，行看叢林氣象新。"]'),
('f2926769-07a3-4beb-94c3-545297c9d428','偈頌八十七首  其五五','釋慧開','宋','宋诗','song-poetry','','[]','黄龍結制沒規繩，超過諸方半月程。',32,'全唐诗/poet.song.195000.json','["黄龍結制沒規繩，超過諸方半月程。", "莫怪七顛并八倒，大家日午打三更。"]'),
('718a5341-e115-42da-a153-4bb2883002e8','偈頌八十七首  其五六','釋慧開','宋','宋诗','song-poetry','','[]','薰風自南來，殿閣生微凉。',48,'全唐诗/poet.song.195000.json','["薰風自南來，殿閣生微凉。", "百年渾似醉，三萬六千場。", "休擬議，莫思量。", "錦鱗一躍化龍去，無限癡人戽夜塘。"]'),
('1b9a1cfe-4bb2-46cb-a7e1-428f325b1c41','偈頌八十七首  其五七','釋慧開','宋','宋诗','song-poetry','','[]','歸來一月餘日，內外人事已畢。',56,'全唐诗/poet.song.195000.json','["歸來一月餘日，內外人事已畢。", "恣意飽飯噇眠，說甚金圈栗棘。", "分明告報諸禪，直下便須委悉。", "更若擬議躊躇，照顧腦門霹靂。"]'),
('3aff2f4c-a834-44e0-84be-759a40137fb9','偈頌八十七首  其五八','釋慧開','宋','宋诗','song-poetry','','[]','六月炎炎如火聚，寂然不動於中住。',48,'全唐诗/poet.song.195000.json','["六月炎炎如火聚，寂然不動於中住。", "炎炎火聚却清凉，清凉却是炎炎處。", "等閑坐斷兩頭關，撞牆撞壁通霄路。"]'),
('2a39290b-917f-4e62-ac9b-1945752164b9','偈頌八十七首  其五九','釋慧開','宋','宋诗','song-poetry','','[]','石跟常有千年潤，海眼曾無一日乾。',48,'全唐诗/poet.song.195000.json','["石跟常有千年潤，海眼曾無一日乾。", "天下蒼生待霖雨，不知龍向此間蟠。", "霹靂一聲頭角露，傾湫倒嶽鼓波瀾。"]'),
('d3d150b3-54ff-455c-a1c6-a41f16cc21fd','偈頌八十七首  其六○','釋慧開','宋','宋诗','song-poetry','','[]','圖列千山開畫嶂，带圍一水遶蓬瀛。',32,'全唐诗/poet.song.195000.json','["圖列千山開畫嶂，带圍一水遶蓬瀛。", "脚頭未舉已先入，不用門前彈指聲。"]'),
('4896f15c-642c-4b9f-9e57-951a67537129','偈頌八十七首  其六一','釋慧開','宋','宋诗','song-poetry','','[]','動絃別曲，葉落知秋。',62,'全唐诗/poet.song.195000.json','["動絃別曲，葉落知秋。", "禾山打鼓，雪峰輥毬。", "睦州擔板，投子提油。", "趙州狗子，溈山牯牛。", "青原垂足，俱胝指頭。", "一隊破落戶，各自逞風流。"]'),
('0e00393c-175b-4989-8ba8-246e11739453','偈頌八十七首  其六二','釋慧開','宋','宋诗','song-poetry','','[]','布袋頭開今日始，滿目江山秋色裏。',32,'全唐诗/poet.song.195000.json','["布袋頭開今日始，滿目江山秋色裏。", "驀然踏斷草鞋跟，元來却是自家底。"]'),
('b56620ac-6e64-4099-ab23-866260b5729f','偈頌八十七首  其六三','釋慧開','宋','宋诗','song-poetry','','[]','信脚行去絕埃塵，信手拈來用得親。',32,'全唐诗/poet.song.195000.json','["信脚行去絕埃塵，信手拈來用得親。", "信口道出驚天地，信心悟入獨超羣。"]'),
('719e6311-1777-4332-9726-edbdb3bbf764','偈頌八十七首  其六四','釋慧開','宋','宋诗','song-poetry','','[]','陰極陽生，日添一線。',25,'全唐诗/poet.song.195000.json','["陰極陽生，日添一線。", "獨有山僧拄杖子，不屬陰陽遷變。"]'),
('51d65ac1-2032-4b52-b702-72605bf8cb6f','偈頌八十七首  其六五','釋慧開','宋','宋诗','song-poetry','','[]','昨日去年去，今朝今歲來。',24,'全唐诗/poet.song.195000.json','["昨日去年去，今朝今歲來。", "去年去不去，今歲來不來。"]'),
('6d991968-c3f0-4557-9362-cbb228daf91c','偈頌八十七首  其六六','釋慧開','宋','宋诗','song-poetry','','[]','現種種形，說種種法。',36,'全唐诗/poet.song.195000.json','["現種種形，說種種法。", "形法皆非，假名菩薩。", "更於諸相覓圓通，當人正眼俱戳瞎。"]'),
('b456a8dc-3101-4e22-8d0c-8214f42e44a6','偈頌八十七首  其六七','釋慧開','宋','宋诗','song-poetry','','[]','咄這乾屎橛，生來太妖孽。',24,'全唐诗/poet.song.195000.json','["咄這乾屎橛，生來太妖孽。", "堪笑老雲門，一棒打不殺。"]'),
('e00a9935-dd97-4a99-9a8a-5482e68195df','偈頌八十七首  其六八','釋慧開','宋','宋诗','song-poetry','','[]','衲僧今日路頭通，拄杖生雲興已濃。',32,'全唐诗/poet.song.195000.json','["衲僧今日路頭通，拄杖生雲興已濃。", "要探江湖深與淺，前途更有妙高峰。"]'),
('0d740dc6-7be8-48c6-ab39-b04df62b26fa','偈頌八十七首  其六九','釋慧開','宋','宋诗','song-poetry','','[]','開爐半月，火種全無。',20,'全唐诗/poet.song.195000.json','["開爐半月，火種全無。", "冷灰豆爆，驚動江湖。"]'),
('b1b42f4f-4962-4ba9-9e9c-95ebb6269ca7','偈頌八十七首  其七○','釋慧開','宋','宋诗','song-poetry','','[]','燕國當年植福田，身如水月印三千。',32,'全唐诗/poet.song.195000.json','["燕國當年植福田，身如水月印三千。", "渠無生死歸何處，春早梅華放曉烟。"]'),
('c6f40a49-14cb-43cb-8d00-91e67180174b','偈頌八十七首  其七一','釋慧開','宋','宋诗','song-poetry','','[]','是聖是凡，過這邊立。',20,'全唐诗/poet.song.195000.json','["是聖是凡，過這邊立。", "擬議不來，青天霹靂。"]'),
('5a8c37cd-973b-4dad-b39d-10db6e585e88','偈頌八十七首  其七二','釋慧開','宋','宋诗','song-poetry','','[]','摧邪顯正，一印印定。',20,'全唐诗/poet.song.195000.json','["摧邪顯正，一印印定。", "盡大地人，諦聽諦聽。"]'),
('0267502f-40c1-45e8-98f8-6df3cb0b06ab','偈頌八十七首  其七三','釋慧開','宋','宋诗','song-poetry','','[]','遇家裏人，說家裏事。',20,'全唐诗/poet.song.195000.json','["遇家裏人，說家裏事。", "一句無私，龍翔鳳翥。"]'),
('5f462102-b18d-47a6-a570-413479603f58','偈頌八十七首  其七四','釋慧開','宋','宋诗','song-poetry','','[]','諸方浩浩，舉古明今。',20,'全唐诗/poet.song.195000.json','["諸方浩浩，舉古明今。", "送人上樹，不是好心。"]'),
('f9fc351b-27a9-4fd8-86ed-ef2bc200b742','偈頌八十七首  其七五','釋慧開','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','銅沙鑼裏滿盛油，故國山河在眼頭。',32,'全唐诗/poet.song.195000.json','["銅沙鑼裏滿盛油，故國山河在眼頭。", "試向鳳凰臺上望，長江無日不東流。"]'),
('65ec8023-1608-438d-94ae-ca00eafc3d29','偈頌八十七首  其七六','釋慧開','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老來無日不思閑，深隠西湖第一山。',32,'全唐诗/poet.song.195000.json','["老來無日不思閑，深隠西湖第一山。", "無奈退菴賢制置，遠移公帖入松關。"]'),
('d5a5a9a2-80c5-443c-b515-e3c29e100a3f','偈頌八十七首  其七七','釋慧開','宋','宋诗','song-poetry','','[]','天陰性地昏，日出心光耀。',64,'全唐诗/poet.song.195000.json','["天陰性地昏，日出心光耀。", "拄杖笑呵呵，禪牀也𨁝跳。", "管甚歲餘閏，一任月大小。", "淈𣸩幾春秋，用處非常峭。", "可憐五十三知識，未曾夢見頂門竅。"]'),
('a379042f-001b-4429-bda2-8445af8615f6','偈頌八十七首  其七八','釋慧開','宋','宋诗','song-poetry','','[]','靈山大法王，末運希所遇。',76,'全唐诗/poet.song.195000.json','["靈山大法王，末運希所遇。", "聲名遍天下，乾坤恣獨步。", "草鞋掛龍牀，三宣渾不顧。", "凌滅曹源生，訓徒參活句。", "宗門箇樣師，熟不生戀慕。", "天庭重降勅黄來，凌霄峰頂施甘露。"]'),
('d2598bff-6a76-49c5-8165-3e78ccd77cdf','偈頌八十七首  其七九','釋慧開','宋','宋诗','song-poetry','','[]','威鎮戎夷，掃清魔孽。',50,'全唐诗/poet.song.195000.json','["威鎮戎夷，掃清魔孽。", "羣靈歸敬，忠心如鐵。", "破蔡滅金，守黄勦賊。", "雪百年二帝難雪之耻，成中興四將未成之業。"]'),
('205fcc97-ed8f-4e2d-9369-02baae0eb4b3','偈頌八十七首  其八○','釋慧開','宋','宋诗','song-poetry','','[]','三教聖人，同歸一理。',50,'全唐诗/poet.song.195000.json','["三教聖人，同歸一理。", "理長則行，理短則止。", "虛空無心，牆壁有耳。", "不涉言詮，單提直指。", "口縫纔開，不是不是。"]'),
('f3e957a7-9848-445a-a377-cf040da10780','偈頌八十七首  其八一','釋慧開','宋','宋诗','song-poetry','','[]','山前麥熟已如雲，覿面當機爲指陳。',32,'全唐诗/poet.song.195000.json','["山前麥熟已如雲，覿面當機爲指陳。", "驀地一番梅雨過，青山洗出畫圖新。"]'),
('6c682f0b-a434-4131-ad51-26bbf8413981','偈頌八十七首  其八二','釋慧開','宋','宋诗','song-poetry','','[]','元正啟祚，萬物咸新。',29,'全唐诗/poet.song.195000.json','["元正啟祚，萬物咸新。", "衲僧拄杖黑{粦皮}皴，不屬陰陽別是春。"]'),
('5d32712e-61dd-445d-afb4-61475de717dd','偈頌八十七首  其八三','釋慧開','宋','宋诗','song-poetry','','[]','出洞昂頭角，回山露尾巴。',24,'全唐诗/poet.song.195000.json','["出洞昂頭角，回山露尾巴。", "恩承饒舌力，累我受波查。"]'),
('a009421b-799c-4345-aad3-6e228e5abb30','偈頌八十七首  其八四','釋慧開','宋','宋诗','song-poetry','','[]','針芥相投，體用俱全。',20,'全唐诗/poet.song.195000.json','["針芥相投，體用俱全。", "衲僧門下，十萬八千。"]'),
('4ea63757-1065-42eb-9623-515264cabb21','偈頌八十七首  其八五','釋慧開','宋','宋诗','song-poetry','','[]','名高不用鎸頑石，路上行人口是碑。',32,'全唐诗/poet.song.195000.json','["名高不用鎸頑石，路上行人口是碑。", "大宋正傳天子令，直教諸國豎降旗。"]'),
('ed0bd4a5-3670-4ac0-aa01-dc10646a5a6b','偈頌八十七首  其八六','釋慧開','宋','宋诗','song-poetry','','[]','普賢行願等三千，正是清明首夏天。',32,'全唐诗/poet.song.195000.json','["普賢行願等三千，正是清明首夏天。", "要見大人真境界，月明常照御樓前。"]'),
('83fa19dc-e4d5-4dd8-bfed-9a7fff375d64','偈頌八十七首  其八七','釋慧開','宋','宋诗','song-poetry','','[]','爛柴頭，火一團。',24,'全唐诗/poet.song.195000.json','["爛柴頭，火一團。", "急著眼，莫顢頇，星在秤兮不在盤。"]'),
('c403b611-5236-41b4-9d1d-29c6b4980c8d','偈頌二首  其一','釋慧開','宋','宋诗','song-poetry','','[]','黄龍結制不尋常，只用閻羅斷命方。',32,'全唐诗/poet.song.195000.json','["黄龍結制不尋常，只用閻羅斷命方。", "生鐵一團紅嚥下，死中再活獲清涼。"]'),
('c3d45ee2-9fcd-4624-91d9-b7580f22cde5','偈頌二首  其二','釋慧開','宋','宋诗','song-poetry','','[]','欲把生蛇化活龍，先將毒藥灌喉嚨。',32,'全唐诗/poet.song.195000.json','["欲把生蛇化活龍，先將毒藥灌喉嚨。", "常教滿腹如針刺，拋向洪波大浪中。"]'),
('d7c961b0-59d0-4eb3-8318-93c9ddd5a9f5','無量壽佛贊','釋慧開','宋','宋诗','song-poetry','','[]','乾屎橛兮麻三斤，當陽拈出少知音。',32,'全唐诗/poet.song.195000.json','["乾屎橛兮麻三斤，當陽拈出少知音。", "時人不識自家佛，却向丹青畫處尋。"]'),
('3e90f417-6cab-44ed-8169-2c7dc84bb2c9','佛頭圓相贊','釋慧開','宋','宋诗','song-poetry','','[]','生怕雲門打殺伊，韜光晦迹許多時。',32,'全唐诗/poet.song.195000.json','["生怕雲門打殺伊，韜光晦迹許多時。", "而今再出頭來也，天上人間更有誰。"]'),
('6d23dae5-6206-46b5-b984-a2bb31f11437','圓通大士贊','釋慧開','宋','宋诗','song-poetry','','[]','足蹈雙蓮灑楊柳，面目端嚴世希有。',32,'全唐诗/poet.song.195000.json','["足蹈雙蓮灑楊柳，面目端嚴世希有。", "梵音妙音海潮音，祇這而今誰動口。"]'),
('d8f7b7f6-3268-42da-8070-64219b1781f4','持二十五輪頂彌陀蹈蓮葉贊','釋慧開','宋','宋诗','song-poetry','','[]','機輪纔轉，作者猶迷。',36,'全唐诗/poet.song.195000.json','["機輪纔轉，作者猶迷。", "頂𩕳一著，獨弄單提。", "自從蹈得這些子，便向風波險處施。"]'),
('0c27de12-69a5-4329-b24e-8af7343f2ef1','三十二應贊','釋慧開','宋','宋诗','song-poetry','','[]','現種種形，說種種法。',36,'全唐诗/poet.song.195000.json','["現種種形，說種種法。", "形法皆非，假名菩薩。", "更於諸相覓圓通，當人正眼俱戳瞎。"]'),
('041aea6d-4120-44a8-8f53-7703f62afe8c','持珠坐石贊','釋慧開','宋','宋诗','song-poetry','','[]','手輪摩尼珠，身坐盤陀石。',24,'全唐诗/poet.song.195000.json','["手輪摩尼珠，身坐盤陀石。", "普請大地人，念彼觀音力。"]'),
('e40b7589-d8d1-4cca-b161-50419fdcf325','達磨莖蘆贊','釋慧開','宋','宋诗','song-poetry','','[]','脚下莖蘆，到岸也未。',20,'全唐诗/poet.song.195000.json','["脚下莖蘆，到岸也未。", "隨流入流，浮逼逼地。"]'),
('2edb1810-0482-40d9-8d59-1b41c6eaa824','達磨大師贊','釋慧開','宋','宋诗','song-poetry','','[]','賊身未露罪全彰，攪得西乾沸似湯。',32,'全唐诗/poet.song.195000.json','["賊身未露罪全彰，攪得西乾沸似湯。", "項上鐵枷無計脫，却來東土强攤贓。"]'),
('c9620ddd-a1d2-436b-9254-438b8a91dca4','大祖禪師贊','釋慧開','宋','宋诗','song-poetry','','[]','三拜起來依位立，普天匝地黑漫漫。',32,'全唐诗/poet.song.195000.json','["三拜起來依位立，普天匝地黑漫漫。", "可憐隻臂空輪却，千古令人作笑端。"]'),
('89b6d77c-7c12-4a8a-88b7-4cfc2711e9bc','鏡智禪師贊','釋慧開','宋','宋诗','song-poetry','','[]','彌天罪犯無門懺，紅爛通身世莫醫。',32,'全唐诗/poet.song.195000.json','["彌天罪犯無門懺，紅爛通身世莫醫。", "已是四稜俱塌地，儘教後代亂針錐。"]'),
('17e1d382-5329-45de-b071-75ec4924dfb0','大醫禪師贊','釋慧開','宋','宋诗','song-poetry','','[]','堅辭鳳闕紫泥詔，玷辱宗風箇古錐。',32,'全唐诗/poet.song.195000.json','["堅辭鳳闕紫泥詔，玷辱宗風箇古錐。", "坐斷雙峰無寸草，愛松留得礙人枝。"]'),
('5bf240cf-e873-43a2-b753-7161529b40fa','大滿禪師贊','釋慧開','宋','宋诗','song-poetry','','[]','再出頭來滿面塵，那堪鼓舌與摇唇。',32,'全唐诗/poet.song.195000.json','["再出頭來滿面塵，那堪鼓舌與摇唇。", "松枯石爛憑誰委，累及癡獃蹈碓人。"]'),
('39107908-0d29-471e-a05e-0f5a466474eb','大鑑禪師贊','釋慧開','宋','宋诗','song-poetry','','[]','菩提無樹鏡非臺，臭口分明鬼擘開。',32,'全唐诗/poet.song.195000.json','["菩提無樹鏡非臺，臭口分明鬼擘開。", "幸是賣柴無事獠，剛然惹得一身災。"]'),
('0f701496-4779-4ccf-a237-dbaff82c7d5b','思大禪師贊','釋慧開','宋','宋诗','song-poetry','','[]','一生討頭不見，二生骨露皮穿。',44,'全唐诗/poet.song.195000.json','["一生討頭不見，二生骨露皮穿。", "三生造成地獄，全身活陷黄泉。", "七十二峰俱坐斷，口吞佛祖在機先。"]'),
('ba75ad4c-e4a1-4257-ab69-6793d1b1df81','騎虎豐干贊','釋慧開','宋','宋诗','song-poetry','','[]','忙忙業識老豐干，鼓舌摇唇總自瞞。',32,'全唐诗/poet.song.195000.json','["忙忙業識老豐干，鼓舌摇唇總自瞞。", "縱踞虎頭取虎尾，衲僧門下管窺斑。"]'),
('26dc7813-1460-402f-9a87-2be75291162e','誌公和尚贊','釋慧開','宋','宋诗','song-poetry','','[]','杖頭絡索閑家具，應讖三朝經幾秋。',50,'全唐诗/poet.song.195000.json','["杖頭絡索閑家具，應讖三朝經幾秋。", "生向鷹窠來處異，面皮擘破十三頭。", "㘞，因渠達磨枝條布，惱亂春風卒未休。"]'),
('c06a4a8d-3e57-459b-9ed6-13557e533c61','白雲法師贊','釋慧開','宋','宋诗','song-poetry','','[]','偉哉大法師，逢難轉堅牢。',24,'全唐诗/poet.song.195000.json','["偉哉大法師，逢難轉堅牢。", "不因登絕頂，爭見白雲高。"]'),
('58ee5691-67eb-473b-b668-7a34a8b353a3','天台四睡贊','釋慧開','宋','宋诗','song-poetry','','[]','既是伏爪藏牙，不用三頭六臂。',28,'全唐诗/poet.song.195000.json','["既是伏爪藏牙，不用三頭六臂。", "只圖夢裡惺惺，任疑大蟲瞌睡。"]'),
('f4744a49-ac1c-4b9e-8747-c96e654882a9','政黄牛贊','釋慧開','宋','宋诗','song-poetry','','[]','資福從來不識羞，橘皮熟炙逞風流。',32,'全唐诗/poet.song.195000.json','["資福從來不識羞，橘皮熟炙逞風流。", "倚筇懶赴賢侯命，又却騎牛更覓牛。"]'),
('1578f546-639f-4481-99ae-726b0233bcb2','郁山主贊','釋慧開','宋','宋诗','song-poetry','','[]','百尺竿頭話最親，一交橋斷絕纖塵。',32,'全唐诗/poet.song.195000.json','["百尺竿頭話最親，一交橋斷絕纖塵。", "死中得活珠離蚌，甘作馿前馬後人。"]'),
('d4b0d46d-90de-4327-bb95-0faa7f1939b8','朝陽穿破衲贊','釋慧開','宋','宋诗','song-poetry','','[]','冷時急用之物，趁暖著些針線。',28,'全唐诗/poet.song.195000.json','["冷時急用之物，趁暖著些針線。", "忽然臘月到來，免致脚忙手亂。"]'),
('f037faab-222b-4a31-b610-8a22c9fb0a38','對月了殘經贊','釋慧開','宋','宋诗','song-poetry','','[]','始見些兒光影，要了末後一段。',28,'全唐诗/poet.song.195000.json','["始見些兒光影，要了末後一段。", "若是無門拳頭，不打這般鈍漢。"]'),
('135d92ce-abfc-40a4-bd73-31aef4ede1cb','傅大士贊','釋慧開','宋','宋诗','song-poetry','','[]','對御講經，無本可據。',36,'全唐诗/poet.song.195000.json','["對御講經，無本可據。", "案上一揮，誰知落處。", "知落處，拍板與門槌，總是閑家具。"]'),
('6c7dfb33-dc4a-4665-a082-54edc6d61539','維摩居士贊','釋慧開','宋','宋诗','song-poetry','','[]','毗耶病虎實難親，觸著渠儂便喪身。',32,'全唐诗/poet.song.195000.json','["毗耶病虎實難親，觸著渠儂便喪身。", "非但文殊遭毒口，吞盡靈山一會人。"]'),
('aa855c52-2ae3-42e3-b8e8-d46cc9e61cc8','龐居士贊','釋慧開','宋','宋诗','song-poetry','','[]','平欺馬祖，下視諸方。',34,'全唐诗/poet.song.195000.json','["平欺馬祖，下視諸方。", "生涯蕩却，今古無雙。", "不與萬法爲侶，一口吸盡西江。"]'),
('b0a71d90-c9a2-4f8f-9037-a40e87c88ff6','執劍呂洞賓贊','釋慧開','宋','宋诗','song-poetry','','[]','露刃單提，行殺活令。',40,'全唐诗/poet.song.195000.json','["露刃單提，行殺活令。", "斬貪嗔癡，羣魔乞命。", "夫是之謂，純陽真人。", "激濁揚清，摧邪顯正。"]'),
('f742295c-419b-4c86-b492-8432273d5e87','佛母周氏贊','釋慧開','宋','宋诗','song-poetry','','[]','室女生兒真禍胎，叢林孰不起疑猜。',32,'全唐诗/poet.song.195000.json','["室女生兒真禍胎，叢林孰不起疑猜。", "轉身術子能靈驗，再出頭來滿面埃。"]'),
('2530e228-a3c6-4d51-8009-0531de969857','謝佛眼師號','釋慧開','宋','宋诗','song-poetry','','[]','皇恩頒自九重城，雨露纔霑草木榮。',64,'全唐诗/poet.song.195000.json','["皇恩頒自九重城，雨露纔霑草木榮。", "佛祖門庭增瑞氣，四海歡呼萬歲聲。", "忠心護國成勳業，君父開臣佛眼睛。", "壽山福海恩難報，永日寥寥賀太平。"]'),
('a2f42254-a37d-40d0-9314-d270498a8417','謝宣賜金襴','釋慧開','宋','宋诗','song-poetry','','[]','不是鷄足流傳，亦非黄梅分付。',56,'全唐诗/poet.song.195000.json','["不是鷄足流傳，亦非黄梅分付。", "九重天上降來，千載臣僧一遇。", "中興佛祖宗風，羣魔悉皆驚怖。", "祝延聖壽無疆，志願皇圖永固。"]'),
('9e90252c-5d8c-4fd0-80e3-86abcea9093d','題壁間水波觀音','釋慧開','宋','宋诗','song-poetry','','[]','曹源正派喜流傳，涓滴渾無浪拍天。',32,'全唐诗/poet.song.195000.json','["曹源正派喜流傳，涓滴渾無浪拍天。", "任是大悲千手眼，探渠深淺待馿年。"]'),
('17795b7f-6a99-4f38-947e-083cf7c84756','賀吳丞相生日','釋慧開','宋','宋诗','song-poetry','','[]','大地春回是誕辰，松篁難改四時青。',32,'全唐诗/poet.song.195000.json','["大地春回是誕辰，松篁難改四時青。", "壽星不老福無盡，常在中天伴月明。"]'),
('bd6c306d-35ad-4b7f-ac2b-78ca9a9f793a','趙資政號節齋','釋慧開','宋','宋诗','song-poetry','','[]','著鞭占得地頭寬，高節心空立處端。',32,'全唐诗/poet.song.195000.json','["著鞭占得地頭寬，高節心空立處端。", "多向渭川烟外望，這邊風月少人看。"]'),
('e7e43830-26ff-49f0-87cd-4583bbcc6031','吳尚書尊堂死以偈問用韻以復','釋慧開','宋','宋诗','song-poetry','','[]','身分水月遍三千，月落何曾離得天。',32,'全唐诗/poet.song.195000.json','["身分水月遍三千，月落何曾離得天。", "此是夫人行履處，摩耶相對共談禪。"]'),
('c21f1544-a562-4b9e-8af1-d6d031155221','退步','釋慧開','宋','宋诗','song-poetry','','[]','未曾移定時，前脚讓後脚。',24,'全唐诗/poet.song.195000.json','["未曾移定時，前脚讓後脚。", "只這一步子，誰人蹈得著。"]'),
