('27c36ab2-cca9-4f1b-8fdd-b3197d460487','請行新橋','釋慧開','宋','宋诗','song-poetry','','[]','雲根架就笑談中，凡聖如今一路通。',86,'全唐诗/poet.song.195000.json','["雲根架就笑談中，凡聖如今一路通。", "箇箇脚跟親蹈著，人人足下起清風。", "不似天台滑石，半巇半嶮。", "勝如趙州略彴，度馬度馿。", "雖然欲行千里，要知一步爲初。", "從茲不用頻題柱，來往都乘駟馬車。"]'),
('c91ed2e9-befe-4ccb-95dd-fe37cecf34ce','吳履齋以脚蹈日影索偈','釋慧開','宋','宋诗','song-poetry','','[]','圓陀陀，光爍爍。',28,'全唐诗/poet.song.195000.json','["圓陀陀，光爍爍。", "明眼人，蹈不著。", "蹈得著，更買草鞋去行脚。"]'),
('b21485f7-f236-4eac-83bb-d11c0c07c0af','在南高峰石室中出定作','釋慧開','宋','宋诗','song-poetry','','[]','靜處乾坤窄，閑居日月忙。',24,'全唐诗/poet.song.195000.json','["靜處乾坤窄，閑居日月忙。", "虛空即妙體，獨露法中王。"]'),
('c1fd25e7-b4ca-46f8-af00-9756ebb102fe','六年舉無字一日聞齋鼓有省','釋慧開','宋','宋诗','song-poetry','','[]','青天白日一聲雷，大地羣生眼豁開。',32,'全唐诗/poet.song.195000.json','["青天白日一聲雷，大地羣生眼豁開。", "萬象森羅齊稽首，須彌𨁝跳舞三臺。"]'),
('bebd7186-98f7-46d6-ba7f-b192fd81bbc7','總軸羅漢','釋慧開','宋','宋诗','song-poetry','','[]','洞寇都盧十八頭，千妖百怪逞風流。',32,'全唐诗/poet.song.195000.json','["洞寇都盧十八頭，千妖百怪逞風流。", "人間天上稱尊漢，總被無門一握收。"]'),
('6abc0406-7116-406b-8220-e62cc3ae2cd8','圓覺會','釋慧開','宋','宋诗','song-poetry','','[]','十二獃郎欲決疑，瞿曇嚼飯餵嬰兒。',32,'全唐诗/poet.song.195000.json','["十二獃郎欲決疑，瞿曇嚼飯餵嬰兒。", "若教知有衲僧事，終不人前鼓口皮。"]'),
('adba2fc7-4ce9-404e-a597-afa6100e30dd','石牛','釋慧開','宋','宋诗','song-poetry','','[]','須彌爲骨露纖軀，頭角崢嶸塞太虛。',32,'全唐诗/poet.song.195000.json','["須彌爲骨露纖軀，頭角崢嶸塞太虛。", "大地耕翻無寸土，牧童鞭索豈能拘。"]'),
('7106e552-567a-4393-9fbc-81e07452eb92','懶牛','釋慧開','宋','宋诗','song-poetry','','[]','不經南陌與西阡，犁杷年來怕上肩。',32,'全唐诗/poet.song.195000.json','["不經南陌與西阡，犁杷年來怕上肩。", "棄却欄中肥嫩草，綠楊堤畔飽風烟。"]'),
('f26e8388-98b2-408a-931b-2d99eadb518b','無際','釋慧開','宋','宋诗','song-poetry','','[]','祖翁田地沒憑據，爭許時人取次量。',32,'全唐诗/poet.song.195000.json','["祖翁田地沒憑據，爭許時人取次量。", "但見寥寥成一片，不知何處是封疆。"]'),
('d04f44aa-f667-4579-8c35-e3aad5a9e85e','鐵壁','釋慧開','宋','宋诗','song-poetry','','[]','巍然一座黑金城，縫罅全無及戶扃。',32,'全唐诗/poet.song.195000.json','["巍然一座黑金城，縫罅全無及戶扃。", "堪笑英雄難進步，聖凡到此絕途程。"]'),
('37b4745a-f3f8-4c1a-9def-864b015aa05b','針筒','釋慧開','宋','宋诗','song-poetry','','[]','函蓋乾坤氣量周，銅睛鐵眼一齊取。',32,'全唐诗/poet.song.195000.json','["函蓋乾坤氣量周，銅睛鐵眼一齊取。", "幾多利腦尖鋒者，到此如何敢出頭。"]'),
('5348841a-62f1-4d80-b6d5-aed411c60a91','裁縫','釋慧開','宋','宋诗','song-poetry','','[]','剪斷萬絲頭，工夫已成片。',24,'全唐诗/poet.song.195000.json','["剪斷萬絲頭，工夫已成片。", "針劄不入處，爲渠通一線。"]'),
('0ccac890-6ec2-411c-84d4-ebb879a4bbca','浄髮','釋慧開','宋','宋诗','song-poetry','','[]','鋒鋩未露鬼神號，能剗羣牛頂𩕳毛。',32,'全唐诗/poet.song.195000.json','["鋒鋩未露鬼神號，能剗羣牛頂𩕳毛。", "四海聱頭俱按下，豈容存著一纖毫。"]'),
('0bde00cf-fe6a-4fca-8c3b-eb3aee7cf74f','頭袖','釋慧開','宋','宋诗','song-poetry','','[]','四海英靈俱奪下，銅頭鐵額總兜來。',32,'全唐诗/poet.song.195000.json','["四海英靈俱奪下，銅頭鐵額總兜來。", "莫怪無門施毒手，揭翻腦蓋頂門開。"]'),
('14e31250-d1ba-4874-bb26-b992c5d76bee','帳子','釋慧開','宋','宋诗','song-poetry','','[]','纔得當陽一線通，全彰大用顯家風。',32,'全唐诗/poet.song.195000.json','["纔得當陽一線通，全彰大用顯家風。", "直饒鼻孔遼天漢，未免從頭被罩籠。"]'),
('61bb2414-499f-4225-b085-1404026299d7','薦蓆','釋慧開','宋','宋诗','song-poetry','','[]','亂草窠中，打成一片。',20,'全唐诗/poet.song.195000.json','["亂草窠中，打成一片。", "坐卧寂然，真機頓現。"]'),
('ce3cbcda-0ed1-45f7-8d53-310d68acb942','枕頭','釋慧開','宋','宋诗','song-poetry','','[]','輪回根本，莫著相好。',20,'全唐诗/poet.song.195000.json','["輪回根本，莫著相好。", "鐵脊梁漢，因他放倒。"]'),
('fda9aa4d-69d6-4938-8215-30c8d330b569','捨鞋','釋慧開','宋','宋诗','song-poetry','','[]','驗盡脚跟長與短，箇中寬窄已先知。',32,'全唐诗/poet.song.195000.json','["驗盡脚跟長與短，箇中寬窄已先知。", "自從蹈著這些子，左右逢原顯大機。"]'),
('0410e544-f102-47c4-b053-0fcf2c14623e','牙藥','釋慧開','宋','宋诗','song-poetry','','[]','點著些兒，妙不可述。',20,'全唐诗/poet.song.195000.json','["點著些兒，妙不可述。", "纔開臭口，驗得骨出。"]'),
('a43b623a-0361-47a4-8597-7dd3b1d93b3b','醫眼','釋慧開','宋','宋诗','song-poetry','','[]','開黑暗門，通向上竅。',20,'全唐诗/poet.song.195000.json','["開黑暗門，通向上竅。", "內外障除，神光獨耀。"]'),
('fe945d6d-c966-4119-915d-be805c0604b4','施湯','釋慧開','宋','宋诗','song-poetry','','[]','不是甘草大黄，亦非苦參半夏。',28,'全唐诗/poet.song.195000.json','["不是甘草大黄，亦非苦參半夏。", "莫教一滴沾唇，直得通身汗下。"]'),
('f6a609aa-a573-4e2a-b186-2c039b14dcd3','接待','釋慧開','宋','宋诗','song-poetry','','[]','洋銅汁羹，熱鐵丸飯。',20,'全唐诗/poet.song.195000.json','["洋銅汁羹，熱鐵丸飯。", "滴粒纔沾，通身腐爛。"]'),
('a6a3625d-b2d2-49d8-9a8f-aff5f7c9acd3','餛飩','釋慧開','宋','宋诗','song-poetry','','[]','寬著肚皮急叉手，鑊湯裡面翻筋斗。',32,'全唐诗/poet.song.195000.json','["寬著肚皮急叉手，鑊湯裡面翻筋斗。", "渾身糜爛轉馨香，那箇禪和不開口。"]'),
('6abd58fe-77c9-4b50-9641-e47ccb460058','孟少保戎裝相贊','釋慧開','宋','宋诗','song-poetry','','[]','英雄盖世上將軍，洞寇聞風喪膽魂。',32,'全唐诗/poet.song.195000.json','["英雄盖世上將軍，洞寇聞風喪膽魂。", "寸刃不施機莫測，看渠談笑定乾坤。"]'),
('68a3a1f5-89eb-46d3-a871-bfc507bee89b','又道裝相贊','釋慧開','宋','宋诗','song-poetry','','[]','靈山付囑人，示現威稜身。',40,'全唐诗/poet.song.195000.json','["靈山付囑人，示現威稜身。", "在欲而無欲，居塵不染塵。", "等閑伸出擎天手，撥轉如來正法輪。"]'),
('1c4f84f2-2978-4923-a3ac-9e7ae4631ddf','孟無菴與師同軸請贊','釋慧開','宋','宋诗','song-poetry','','[]','居士身，比丘相。',58,'全唐诗/poet.song.195000.json','["居士身，比丘相。", "蹺蹺踦踦，牢牢攘攘。", "驀然覿面相逢，直是無門可向。", "一拳一喝，雙收雙放。", "無菴居士眼無筋，識得這般村和尚。"]'),
('d63f5fba-5a5e-429a-86c1-75f1a393cfc4','履齋樞相鈞容贊','釋慧開','宋','宋诗','song-poetry','','[]','湘水之清，崑玉之潔。',60,'全唐诗/poet.song.195000.json','["湘水之清，崑玉之潔。", "和氣如春，忠心如鐵。", "儲風月之精，稟松篁之節。", "真廊廟楷模，行佛祖途轍。", "裴李蘇黄總不如，柱石明堂渠迥別。"]'),
('4357c7b9-64d1-4cb0-bf07-d4d9da363ec2','月泉趙寺丞壽像贊','釋慧開','宋','宋诗','song-poetry','','[]','身爲皇族，名著南宮。',83,'全唐诗/poet.song.195000.json','["身爲皇族，名著南宮。", "孔孟屋裏，做模打樣。", "釋老室內，談玄說空。", "似箇般伎倆，半錢不直，又說甚道理三教俱通。", "從前學解掀翻盡，却於無處立宗風。", "天龍更爲重饒舌，熨斗煎茶銚不同。"]'),
('091a2072-b58f-4ebd-85c3-7dd00bde56b9','孟少保繪師握拳缺指相請贊','釋慧開','宋','宋诗','song-poetry','','[]','爲人手段十分粗，拳下搜尋一箇無。',32,'全唐诗/poet.song.195000.json','["爲人手段十分粗，拳下搜尋一箇無。", "咄這村僧難湊泊，釋迦彌勒是他奴。"]'),
('44da2649-1f34-41c2-bfce-720f411e56a2','牧菴簡菴師三人共軸贊','釋慧開','宋','宋诗','song-poetry','','[]','謾說降龍伏虎，徒誇對御談禪。',28,'全唐诗/poet.song.195000.json','["謾說降龍伏虎，徒誇對御談禪。", "莫怪無門擔板，佛來也喫粗拳。"]');
